@dataclass
class Projectile:
    row: int
    x: float
    y: float
    damage: float
    speed: float
    slow: float = 0.0
    direction: int = 1
    lobbed: bool = False
    splash: float = 0.0
    color: Tuple[int, int, int] = (41, 179, 71)
    outline: Tuple[int, int, int] = (20, 110, 38)
    radius: int = 8
    enemy: bool = False
    teleport_cd: float = 0.0
    anti_air: bool = False
    kind: str = ""

    def update(self, dt: float) -> None:
        self.x += self.speed * dt * self.direction
        self.teleport_cd = max(0.0, self.teleport_cd - dt)


