class RollingNut:
    kind: str
    row: int
    x: float
    speed: float
    damage: float
    pierce: int
    radius: int
    splash: float = 0.0
    ttl: float = 7.0
    spin: float = 0.0


@dataclass
class Token:
    x: float
    y: float
    value: int
    life: float
    kind: str

    def update(self, dt: float) -> None:
        self.life -= dt

    def hit(self, p: Tuple[int, int], r: int) -> bool:
        dx = p[0] - self.x
        dy = p[1] - self.y
        return dx * dx + dy * dy <= r * r


