    def build_i_zombie_endless_layout(self, templates: List[Dict[str, object]]) -> Dict[str, object]:
        if not templates:
            return {"start_sun": 150, "cards": ["normal", "conehead", "buckethead"], "plants": []}
        unlocked = int(self.save_data.get("unlocked", 1))
        tier = max(1, unlocked // 6)
        base_idx = int(clamp(float(tier % len(templates)), 0.0, float(len(templates) - 1)))
        base = templates[base_idx]
        cards = [
            "normal",
            "conehead",
            "buckethead",
            "newspaper",
            "pole_vaulting",
            "football",
            "screen_door",
            "ladder",
            "digger",
            "pogo",
        ]
        if tier >= 8:
            cards.extend(["gargantuar", "imp"])
        start_sun = max(120, int(base.get("start_sun", 170)) - max(0, tier - 2) * 3)
        plants = list(base.get("plants", []))
        # Endless should not feel identical each run.
        rng = random.Random(random.randint(1, 10**9))
        extra_pool = ["wallnut", "tall_nut", "pumpkin", "repeater", "snowpea", "melon_pult", "spikeweed", "chomper"]
        for _ in range(min(4 + tier // 5, 8)):
            kind = rng.choice(extra_pool)
            row = rng.randrange(self.rows())
            col = rng.randint(2, 5)
            plants.append((kind, row, col))
        return {"start_sun": start_sun, "cards": cards, "plants": plants}

    def setup_i_zombie_board(self) -> None:
        templates = self.i_zombie_layout_templates()
        mode_name = self.mode_name()
        stage_cfg = self.i_zombie_stage_configs()
        default_id = self.i_zombie_layout_progress_id(max(1, len(stage_cfg)))
        all_stage_ids = [eid for eid, _, _ in CLASSIC_PUZZLE_IZOMBIE_LIST]
        layout_id = int(self.mode_float("i_zombie_layout_id", float(default_id)))
        if mode_name in all_stage_ids:
            layout_id = all_stage_ids.index(mode_name)
        layout_id = int(clamp(float(layout_id), 0.0, float(max(0, len(all_stage_ids) - 1))))
        fallback_stage_id = all_stage_ids[layout_id] if all_stage_ids else ""
        if mode_name == "puzzle_i_zombie_endless":
            layout = self.build_i_zombie_endless_layout(templates)
        elif mode_name in stage_cfg:
            layout = dict(stage_cfg.get(mode_name, {}))
        else:
            layout = dict(stage_cfg.get(fallback_stage_id, {}))
            if not layout:
                layout = templates[layout_id] if templates else {"start_sun": 175, "cards": ["normal"], "plants": []}

        raw_cards = [k for k in self.mode_list("zombie_cards") if k in self.zombie_types]
        if not raw_cards:
            raw_cards = [k for k in layout.get("cards", []) if k in self.zombie_types]
        if not raw_cards:
            raw_cards = ["normal", "conehead", "buckethead", "newspaper", "pole_vaulting"]

        seen = set()
        self.cards = []
        for k in raw_cards:
            if k not in seen:
                self.cards.append(k)
                seen.add(k)
        self.initial_selected_cards = list(self.cards)
        self.selected = self.cards[0] if self.cards else "normal"
        self.card_timer = {k: 0.0 for k in self.cards}
        self.cleaners = [False for _ in range(self.rows())]
        self.brains = {row: 1.0 for row in range(self.rows())}
        self.brain_goal = len(self.brains)
        self.sun = int(self.mode_float("i_zombie_start_sun", float(layout.get("start_sun", 175))))
        for kind, row, col in layout.get("plants", []):
            rr = int(clamp(float(row), 0.0, float(self.rows() - 1)))
            cc = int(clamp(float(col), 0.0, float(COLS - 1)))
            if kind in self.plant_types:
                self.spawn_plant_direct(str(kind), rr, cc, force_place=True)

    def reveal_vase(self, row: int, col: int) -> bool:
        payload = self.vases.pop((row, col), None)
        if not payload:
            return False
        payload_kind = str(payload.get("kind", ""))
        payload_value = payload.get("value")
        self.vase_reveals.append({"row": row, "col": col, "kind": payload_kind, "value": payload_value, "t": 0.56, "ttl": 0.56})
        if payload_kind == "plant" and isinstance(payload_value, str):
            self.cards.append(payload_value)
            if (not self.selected) or (self.selected not in self.cards):
                self.selected = payload_value
            return True
        if payload_kind == "zombie" and isinstance(payload_value, str):
            z = self.spawn_zombie_instance(payload_value, row, self.cell_center(row, col)[0] + 18, wave_idx=max(1, self.current_wave))
            self.zombies.append(z)
            return True
        if payload_kind == "sun":
            cx, cy = self.cell_center(row, col)
            self.tokens.append(Token(cx, cy - 12, int(payload_value or 25), 9.0, "sun"))
            return True
        return False

    def place_i_zombie(self, kind: str, row: int, col: int) -> bool:
        if not self.is_i_zombie_mode() or kind not in self.zombie_types:
            return False
        if self.card_timer.get(kind, 0.0) > 0.0:
            return False
        cost = self.i_zombie_cost(kind)
        if (not self.mode_bool("infinite_sun", False)) and self.sun < cost:
            return False
        # In I, Zombie, placement is row-focused; allow click in any column and spawn from the right edge.
        right_spawn_block_x = self.lawn_right() - 12
        lane_cap = max(1, int(self.mode_float("i_zombie_lane_cap", 3.0)))
        pending_in_row = sum(1 for z in self.zombies if z.hp > 0 and z.row == row and z.x >= right_spawn_block_x)
        if pending_in_row >= lane_cap:
            return False
        if not self.mode_bool("infinite_sun", False):
            self.sun -= cost
        self.card_timer[kind] = self.i_zombie_cooldown(kind)
        x = self.lawn_right() + 26.0
        z = self.spawn_zombie_instance(kind, row, x, wave_idx=max(1, self.current_wave))
        self.zombies.append(z)
        self.selected = kind
        return True

    def i_zombie_cost(self, kind: str) -> int:
        costs = {
            "normal": 40,
            "conehead": 60,
            "buckethead": 90,
            "newspaper": 55,
            "pole_vaulting": 65,
            "football": 120,
            "screen_door": 82,
            "ladder": 92,
            "digger": 78,
            "pogo": 82,
        }
        base = float(costs.get(kind, 100))
        scale = max(0.45, self.mode_float("i_zombie_cost_scale", 1.0))
        return int(round(base * scale))

    def i_zombie_cooldown(self, kind: str) -> float:
        cds = {
            "normal": 0.45,
            "conehead": 1.1,
            "buckethead": 1.7,
            "newspaper": 1.2,
            "pole_vaulting": 1.3,
            "football": 2.1,
            "screen_door": 1.7,
            "ladder": 1.9,
            "digger": 1.5,
            "pogo": 1.5,
        }
        base = float(cds.get(kind, 2.5))
        scale = max(0.35, self.mode_float("i_zombie_cd_scale", 1.0))
        return base * scale

    def can_play_any_i_zombie_card(self) -> bool:
        if not self.is_i_zombie_mode():
            return False
        if self.mode_bool("infinite_sun", False):
            return any(self.mode_bool("no_cooldown", False) or self.card_timer.get(kind, 0.0) <= 0.0 for kind in self.cards)
        for kind in self.cards:
            if self.card_timer.get(kind, 0.0) > 0.0:
                continue
            if self.sun >= self.i_zombie_cost(kind):
                return True
        return False

    def beghouled_board_cols(self) -> List[int]:
        return [c for c in range(1, max(2, COLS - 1))]

    def beghouled_upgrade_chain(self) -> List[str]:
        requested = [k for k in self.mode_list("beghouled_chain") if k in self.plant_types]
        default_chain = ["sunflower", "peashooter", "snowpea", "repeater", "starfruit", "gatling"]
        chain: List[str] = []
        for kind in requested or default_chain:
            cfg = self.plant_types.get(kind)
            if cfg is None or cfg.is_support or cfg.is_overlay or cfg.aquatic_only:
                continue
            if cfg.behavior in {"bomb", "squash", "row_blast", "ice", "doom", "blover", "grave_buster", "coffee", "imitate", "potato"}:
                continue
            if kind not in chain:
                chain.append(kind)
        if len(chain) < 4:
            for kind in default_chain:
                if kind in self.plant_types and kind not in chain:
                    chain.append(kind)
        return chain[: max(4, min(6, len(chain)))]

    def beghouled_pool(self) -> List[str]:
        pool = [k for k in self.mode_list("beghouled_pool") if k in self.plant_types]
        if pool:
            return pool
        chain = self.beghouled_upgrade_chain()
        base_count = 5 if self.is_beghouled_twist_mode() else 4
        return chain[: max(3, min(len(chain), base_count))]

    def beghouled_next_kind(self, kind: str) -> str:
        chain = self.beghouled_upgrade_chain()
        if not chain:
            return kind
        if kind not in chain:
            return chain[0]
        idx = chain.index(kind)
        return chain[min(len(chain) - 1, idx + 1)]

    def clear_beghouled_board_entities(self) -> None:
        cols = set(self.beghouled_board_cols())
        for collection in (self.main, self.support, self.armor):
            for pos in [p for p in collection.keys() if p[1] in cols]:
                del collection[pos]

    def sync_beghouled_board(self) -> None:
        self.clear_beghouled_board_entities()
        for (row, col), kind in self.beghouled_cells.items():
            cfg = self.plant_types.get(kind)
            if cfg is None:
                continue
            plant_hp = float(cfg.hp) * self.plant_hp_scale()
            p = Plant(kind=kind, row=row, col=col, hp=plant_hp, slot="main", cd=random.uniform(0.12, 0.55))
            p.state["hp_max"] = float(p.hp)
            p.state["beghouled_tile"] = 1.0
            self.ensure_plant_anim_state(p)
            if kind == "sunflower":
                p.cd = random.uniform(2.6, 4.2)
            elif kind in ("repeater", "gatling", "starfruit"):
                p.cd = random.uniform(0.15, 0.35)
            self.main[(row, col)] = p

    def collect_beghouled_match_groups(self) -> List[List[Tuple[int, int]]]:
        cols = self.beghouled_board_cols()
        if not cols:
            return []
        groups: List[set[Tuple[int, int]]] = []
        for r in range(self.rows()):
            run: List[Tuple[int, int]] = []
            run_kind = ""
            for c in cols:
                kind = self.beghouled_cells.get((r, c), "")
                if kind and kind == run_kind:
                    run.append((r, c))
                else:
                    if len(run) >= 3:
                        groups.append(set(run))
                    run_kind = kind
                    run = [(r, c)] if kind else []
            if len(run) >= 3:
                groups.append(set(run))
        for c in cols:
            run = []
            run_kind = ""
            for r in range(self.rows()):
                kind = self.beghouled_cells.get((r, c), "")
                if kind and kind == run_kind:
                    run.append((r, c))
                else:
                    if len(run) >= 3:
                        groups.append(set(run))
                    run_kind = kind
                    run = [(r, c)] if kind else []
            if len(run) >= 3:
                groups.append(set(run))
        merged: List[set[Tuple[int, int]]] = []
        while groups:
            current = groups.pop()
            changed = True
            while changed:
                changed = False
                rest: List[set[Tuple[int, int]]] = []
                for group in groups:
                    if current & group:
                        current |= group
                        changed = True
                    else:
                        rest.append(group)
                groups = rest
            merged.append(current)
        return [sorted(group, key=lambda pos: (pos[0], pos[1])) for group in merged]

    def collect_beghouled_matches(self) -> List[Tuple[int, int]]:
        matched: List[Tuple[int, int]] = []
        for group in self.collect_beghouled_match_groups():
            matched.extend(group)
        return matched

    def setup_beghouled_mode(self) -> None:
        rules = self.beghouled_rules()
        self.cards = []
        self.card_timer = {}
        self.selected = ""
        self.main.clear()
        self.support.clear()
        self.armor.clear()
        self.zombies.clear()
        self.tokens.clear()
        self.hit_sparks.clear()
        self.cleaners = [True for _ in range(self.rows())]
        self.beghouled_cells.clear()
        self.beghouled_selected = None
        self.mode_spawn_t = 0.0
        self.mode_event_t = 0.0
        self.mode_score = 0
        self.mode_goal = max(18, int(self.mode_float("beghouled_goal", float(rules.get("goal", 40.0)))))
        self.mode_rules["beghouled_last_gain"] = 0.0
        self.mode_rules["beghouled_last_combo"] = 0.0
        cols = self.beghouled_board_cols()
        pool = self.beghouled_pool()
        for r in range(self.rows()):
            for c in cols:
                tries = 0
                pick = random.choice(pool)
                while tries < 10:
                    left_match = c >= cols[0] + 2 and self.beghouled_cells.get((r, c - 1)) == pick and self.beghouled_cells.get((r, c - 2)) == pick
                    up_match = r >= 2 and self.beghouled_cells.get((r - 1, c)) == pick and self.beghouled_cells.get((r - 2, c)) == pick
                    if not left_match and not up_match:
                        break
                    pick = random.choice(pool)
                    tries += 1
                self.beghouled_cells[(r, c)] = pick
        self.sync_beghouled_board()

    def is_beghouled_cell(self, row: int, col: int) -> bool:
        return (row, col) in self.beghouled_cells

    def setup_beghouled_board(self) -> None:
        self.setup_beghouled_mode()

    def resolve_beghouled_matches(self, allow_cascade: bool = True) -> int:
        rules = self.beghouled_rules()
        match_scores = {int(k): int(v) for k, v in dict(rules.get("match_scores", {})).items()}
        upgrade_scores = list(rules.get("upgrade_scores", (0, 2, 4, 6, 8, 10)))
        cascade_mults = [float(x) for x in list(rules.get("cascade_mult", (1.0, 1.25, 1.5, 1.75)))]
        refill_pool = self.beghouled_pool()
        chain = self.beghouled_upgrade_chain()
        total = 0
        cascades = 0
        while True:
            groups = self.collect_beghouled_match_groups()
            if not groups:
                break
            cascades += 1
            refill_positions: List[Tuple[int, int]] = []
            gained = 0.0
            for group in groups:
                anchor = max(group, key=lambda pos: (pos[0], pos[1]))
                current_kind = self.beghouled_cells.get(anchor, refill_pool[0])
                next_kind = self.beghouled_next_kind(current_kind)
                self.beghouled_cells[anchor] = next_kind
                length = len(group)
                base = float(match_scores.get(length, match_scores.get(5, 17) + max(0, length - 5) * 4))
                if next_kind != current_kind and next_kind in chain:
                    tier = chain.index(next_kind)
                    gained += float(upgrade_scores[min(len(upgrade_scores) - 1, tier)])
                gained += base
                for pos in group:
                    if pos != anchor:
                        refill_positions.append(pos)
            for pos in refill_positions:
                self.beghouled_cells[pos] = random.choice(refill_pool)
            cascade_mult = cascade_mults[min(len(cascade_mults) - 1, cascades - 1)] if cascade_mults else 1.0
            wave_gain = int(round(gained * cascade_mult))
            total += wave_gain
            self.mode_score += wave_gain
            self.mode_rules["beghouled_last_gain"] = float(wave_gain)
            self.mode_rules["beghouled_last_combo"] = float(cascades)
            self.sync_beghouled_board()
            if not allow_cascade or cascades >= 6:
                break
        return total

    def resolve_beghouled_move(self, updates: List[Tuple[Tuple[int, int], str]], allow_cascade: bool = True) -> bool:
        snapshot = dict(self.beghouled_cells)
        for pos, kind in updates:
            self.beghouled_cells[pos] = kind
        gained = self.resolve_beghouled_matches(allow_cascade=allow_cascade)
        if gained <= 0:
            self.beghouled_cells.clear()
            self.beghouled_cells.update(snapshot)
            self.sync_beghouled_board()
            return False
        return True

    def handle_beghouled_input(self, row: int, col: int, twist: bool = False) -> bool:
        if not self.is_beghouled_cell(row, col):
            self.beghouled_selected = None
            return False
        if twist:
            tl_r = int(clamp(float(row), 0.0, float(max(0, self.rows() - 2))))
            tl_c = int(clamp(float(col), float(self.beghouled_board_cols()[0]), float(self.beghouled_board_cols()[-1] - 1)))
            square = [(tl_r, tl_c), (tl_r, tl_c + 1), (tl_r + 1, tl_c + 1), (tl_r + 1, tl_c)]
            if not all(pos in self.beghouled_cells for pos in square):
                return False
            vals = [self.beghouled_cells[pos] for pos in square]
            rotated = [vals[3], vals[0], vals[1], vals[2]]
            if not self.resolve_beghouled_move(list(zip(square, rotated)), allow_cascade=True):
                return False
            return True
        if self.beghouled_selected is None:
            self.beghouled_selected = (row, col)
            return True
        sr, sc = self.beghouled_selected
        if (sr, sc) == (row, col):
            self.beghouled_selected = None
            return True
        if abs(sr - row) + abs(sc - col) != 1:
            self.beghouled_selected = (row, col)
            return True
        a = self.beghouled_cells[(sr, sc)]
        b = self.beghouled_cells[(row, col)]
        self.resolve_beghouled_move([((sr, sc), b), ((row, col), a)], allow_cascade=True)
        self.beghouled_selected = None
        return True

    def handle_beghouled_click(self, row: int, col: int, twist: bool = False) -> bool:
        return self.handle_beghouled_input(row, col, twist=twist)

    def setup_seeing_stars_mode(self) -> None:
        layouts = self.seeing_stars_layouts()
        if not layouts:
            self.seeing_stars_targets = []
            self.mode_goal = 0
            self.mode_score = 0
            self.mode_event_t = 0.0
            return
        layout_key = str(self.mode_rules.get("seeing_stars_layout", ""))
        if layout_key and layout_key in layouts:
            base = layouts[layout_key]
        else:
            names = list(layouts.keys())
            pattern_idx = int(clamp(self.mode_float("seeing_stars_pattern", 0.0), 0.0, float(len(names) - 1)))
            base = layouts[names[pattern_idx]]
        targets: List[Tuple[int, int]] = []
        for r, c in base:
            rr = int(clamp(float(r), 0.0, float(self.rows() - 1)))
            cc = int(clamp(float(c), 0.0, float(COLS - 1)))
            pos = (rr, cc)
            if pos not in targets:
                targets.append(pos)
        self.seeing_stars_targets = targets
        self.mode_goal = len(targets)
        self.mode_score = 0
        self.mode_event_t = 0.0

    def setup_seeing_stars_targets(self) -> None:
        self.setup_seeing_stars_mode()

    def update_seeing_stars_mode(self, dt: float) -> None:
        if not self.seeing_stars_targets:
            return
        done = 0
        for pos in self.seeing_stars_targets:
            p = self.main.get(pos)
            if p and p.kind == "starfruit" and p.hp > 0:
                done += 1
        self.mode_score = done
        if done >= len(self.seeing_stars_targets):
            self.mode_event_t += dt
            if self.mode_event_t >= 0.35:
                self.result = "win"
        else:
            self.mode_event_t = 0.0

    def draw_seeing_stars_overlay(self, screen: pygame.Surface) -> None:
        pulse = 0.5 + 0.5 * math.sin(self.elapsed * 3.2)
        for row, col in self.seeing_stars_targets:
            cx, cy = self.cell_center(row, col)
            points = []
            for i in range(10):
                ang = math.radians(-90 + i * 36)
                rr = 18 if i % 2 == 0 else 8
                points.append((cx + math.cos(ang) * rr, cy + math.sin(ang) * rr))
            filled = False
            p = self.main.get((row, col))
            if p and p.kind == "starfruit" and p.hp > 0:
                filled = True
            fill_col = (250, 224, 122) if filled else (224, 186, 94)
            edge_col = (150, 104, 46) if filled else (136, 96, 48)
            pygame.draw.polygon(screen, fill_col, points)
            pygame.draw.polygon(screen, edge_col, points, 2)
            if not filled:
                glow = pygame.Surface((50, 50), pygame.SRCALPHA)
                pygame.draw.circle(glow, (255, 230, 160, int(28 + 24 * pulse)), (25, 25), 18)
                screen.blit(glow, (cx - 25, cy - 25))
        for idx in range(max(0, len(self.seeing_stars_targets) - 1)):
            x1, y1 = self.cell_center(*self.seeing_stars_targets[idx])
            x2, y2 = self.cell_center(*self.seeing_stars_targets[idx + 1])
            pygame.draw.line(screen, (222, 196, 104), (x1, y1), (x2, y2), 1)

    def draw_beghouled_overlay(self, screen: pygame.Surface, plant_sprite_fn) -> None:
        for (row, col), kind in self.beghouled_cells.items():
            cx, cy = self.cell_center(row, col)
            rect = pygame.Rect(cx - 26, cy - 28, 52, 56)
            fill = (244, 230, 194)
            border = (142, 100, 54)
            if self.beghouled_selected == (row, col):
                border = (236, 144, 38)
                fill = (252, 240, 210)
            top_fill = tuple(int(clamp(c + 10, 0, 255)) for c in fill)
            bot_fill = tuple(int(clamp(c - 8, 0, 255)) for c in fill)
            for y in range(rect.h):
                t = y / max(1, rect.h - 1)
                col_fill = (
                    int(top_fill[0] + (bot_fill[0] - top_fill[0]) * t),
                    int(top_fill[1] + (bot_fill[1] - top_fill[1]) * t),
                    int(top_fill[2] + (bot_fill[2] - top_fill[2]) * t),
                )
                pygame.draw.line(screen, col_fill, (rect.x, rect.y + y), (rect.right - 1, rect.y + y))
            pygame.draw.rect(screen, border, rect, 2, border_radius=8)
            groove = pygame.Rect(rect.x + 4, rect.y + 4, rect.w - 8, 11)
            pygame.draw.rect(screen, (196, 150, 86), groove, border_radius=5)
            pygame.draw.rect(screen, (114, 78, 40), groove, 1, border_radius=5)
            icon = plant_sprite_fn(kind, "main")
            if icon is not None:
                icon = pygame.transform.smoothscale(icon, (32, 32))
                screen.blit(icon, icon.get_rect(center=(cx, cy - 3)))
            else:
                pygame.draw.circle(screen, (98, 184, 104), (cx, cy - 3), 13)
            chain = self.beghouled_upgrade_chain()
            tier = chain.index(kind) + 1 if kind in chain else 1
            dots = min(3, tier)
            for i in range(dots):
                pygame.draw.circle(screen, (94, 72, 44), (cx - 8 + i * 8, cy + 16), 2)

    def update_beghouled_mode(self, dt: float) -> None:
        rules = self.beghouled_rules()
        for pos, kind in self.beghouled_cells.items():
            plant = self.main.get(pos)
            if plant is None or plant.kind != kind or plant.hp <= 0:
                self.sync_beghouled_board()
                break
        if self.mode_score >= self.mode_goal:
            self.mode_event_t += dt
            if self.mode_event_t >= 0.4:
                self.result = "win"
            return
        self.mode_event_t = 0.0
        self.mode_spawn_t += dt
        alive = [z for z in self.zombies if z.hp > 0 and z.state.get("dying_t", 0.0) <= 0.0 and not z.hypnotized]
        active_cap = max(2, int(self.mode_float("beghouled_active_cap", float(rules.get("active_cap", 3.0)))))
        base_interval = self.mode_float("beghouled_spawn_interval", float(rules.get("spawn_interval", 2.35)))
        progress = clamp(self.mode_score / max(1.0, float(self.mode_goal)), 0.0, 1.0)
        spawn_interval = max(base_interval * 0.72, base_interval - progress * 0.34)
        pool = [k for k in self.mode_list("beghouled_zombies") if k in self.zombie_types]
        if not pool:
            pool = [str(k) for k in list(rules.get("zombie_pool", ("normal", "conehead", "newspaper"))) if k in self.zombie_types]
        while self.mode_spawn_t >= spawn_interval and len(alive) < active_cap:
            self.mode_spawn_t -= spawn_interval
            row_loads = {
                row: sum(
                    1
                    for z in alive
                    if z.row == row and z.x > LAWN_X + CELL_W * 2.5
                )
                for row in range(self.rows())
            }
            row = min(row_loads, key=lambda rr: (row_loads[rr], random.random()))
            kind = random.choice(pool)
            spawn_x = self.lawn_right() + random.randint(28, 72)
            hp_scale = 0.76 if self.is_beghouled_twist_mode() else 0.70
            speed_scale = 0.94 if self.is_beghouled_twist_mode() else 0.86
            dps_scale = 0.90 if self.is_beghouled_twist_mode() else 0.84
            self.zombies.append(
                self.spawn_zombie_instance(
                    kind,
                    row,
                    float(spawn_x),
                    wave_idx=1,
                    hp_scale=hp_scale,
                    speed_scale=speed_scale,
                    dps_scale=dps_scale,
                )
            )
            alive = [z for z in self.zombies if z.hp > 0 and z.state.get("dying_t", 0.0) <= 0.0 and not z.hypnotized]

    def spawn_zombiquarium_fish(self, row: Optional[int] = None) -> bool:
        water_rows = list(self.field.water_rows) if self.field.water_rows else [min(self.rows() - 1, 1), min(self.rows() - 1, 3)]
        if not water_rows:
            return False
        if row is None or row not in water_rows:
            used_rows = [int(f.get("row", 0.0)) for f in self.zombiquarium_fish]
            free_rows = [rr for rr in water_rows if rr not in used_rows]
            row = random.choice(free_rows or water_rows)
        self.zombiquarium_fish.append(
            {
                "row": float(row),
                "x": float(random.randint(LAWN_X + 90, self.lawn_right() - 90)),
                "dir": float(random.choice([-1, 1])),
                "sun_t": random.uniform(3.2, 4.4),
                "hunger_t": random.uniform(16.0, 20.0),
                "hungry": 0.0,
                "starve_t": 7.5,
            }
        )
        return True

    def zombiquarium_fish_cap(self) -> int:
        return max(1, int(self.mode_float("zombiquarium_fish_cap", 4.0)))

    def setup_zombiquarium(self) -> None:
        self.cards = []
        self.card_timer = {}
        self.selected = ""
        self.main.clear()
        self.support.clear()
        self.armor.clear()
        self.zombies.clear()
        self.tokens.clear()
        self.cleaners = [False for _ in range(self.rows())]
        self.zombiquarium_fish.clear()
        self.mode_spawn_t = 0.0
        self.mode_event_t = 0.0
        self.mode_score = 0
        self.mode_goal = max(300, int(self.mode_float("zombiquarium_goal", 1000.0)))
        start_fish = max(1, min(self.zombiquarium_fish_cap(), int(self.mode_float("zombiquarium_start_fish", 1.0))))
        for _ in range(start_fish):
            self.spawn_zombiquarium_fish()

    def buy_zombiquarium_fish(self) -> bool:
        if not self.is_zombiquarium_mode():
            return False
        fish_cost = max(25, int(self.mode_float("zombiquarium_fish_cost", 100.0)))
        if len(self.zombiquarium_fish) >= self.zombiquarium_fish_cap():
            return False
        if (not self.mode_bool("infinite_sun", False)) and self.sun < fish_cost:
            return False
        if not self.mode_bool("infinite_sun", False):
            self.sun -= fish_cost
        return self.spawn_zombiquarium_fish()

    def buy_zombiquarium_trophy(self) -> bool:
        if not self.is_zombiquarium_mode():
            return False
        trophy_cost = max(300, int(self.mode_float("zombiquarium_goal", 1000.0)))
        if (not self.mode_bool("infinite_sun", False)) and self.sun < trophy_cost:
            return False
        if not self.mode_bool("infinite_sun", False):
            self.sun -= trophy_cost
        self.result = "win"
        return True

    def feed_zombiquarium_fish(self, px: int, py: int) -> bool:
        if not self.is_zombiquarium_mode():
            return False
        feed_cost = max(1, int(self.mode_float("zombiquarium_feed_cost", 25.0)))
        for fish in self.zombiquarium_fish:
            fx = float(fish.get("x", 0.0))
            fy = float(self.row_y(int(fish.get("row", 0.0))))
            if math.hypot(px - fx, py - fy) > 28:
                continue
            if fish.get("hungry", 0.0) <= 0.0:
                return True
            if (not self.mode_bool("infinite_sun", False)) and self.sun < feed_cost:
                return True
            if not self.mode_bool("infinite_sun", False):
                self.sun -= feed_cost
            fish["hungry"] = 0.0
            fish["hunger_t"] = random.uniform(16.0, 22.0)
            fish["starve_t"] = 7.0
            fish["sun_t"] = min(float(fish.get("sun_t", 0.0)), 2.0)
            return True
        return False

    def update_zombiquarium_mode(self, dt: float) -> None:
        if not self.zombiquarium_fish:
            self.result = "lose"
            return
        for fish in list(self.zombiquarium_fish):
            x = float(fish.get("x", 0.0))
            direction = float(fish.get("dir", 1.0))
            x += direction * 36.0 * dt
            if x < LAWN_X + 44:
                x = LAWN_X + 44
                direction = 1.0
            elif x > self.lawn_right() - 44:
                x = self.lawn_right() - 44
                direction = -1.0
            fish["x"] = x
            fish["dir"] = direction
            fish["sun_t"] = float(fish.get("sun_t", 0.0)) - dt
            fish["hunger_t"] = float(fish.get("hunger_t", 0.0)) - dt
            if fish.get("hungry", 0.0) <= 0.0 and fish["hunger_t"] <= 0.0:
                fish["hungry"] = 1.0
                fish["starve_t"] = 7.0
            if fish.get("hungry", 0.0) > 0.0:
                fish["starve_t"] = float(fish.get("starve_t", 0.0)) - dt
                if fish["starve_t"] <= 0.0:
                    self.zombiquarium_fish.remove(fish)
                    continue
            if fish["sun_t"] <= 0.0 and fish.get("hungry", 0.0) <= 0.0:
                row = int(fish.get("row", 0.0))
                self.tokens.append(Token(x, self.row_y(row) - 14, 25, 9.0, "sun"))
                fish["sun_t"] = random.uniform(4.6, 6.2)
        if not self.zombiquarium_fish:
            self.result = "lose"

    def begin_last_stand_assault(self) -> None:
        if not self.last_stand_in_prep():
            return
        self.mode_rules["last_stand_prepare"] = False
        self.current_wave = 0
        self.next_wave = 1.0
        self.wave_pause_t = 1.1
        self.spawn_t = 0.0

    def update_bungee_blitz_mode(self, dt: float) -> None:
        if self.target_duration > 0 and self.elapsed >= self.target_duration:
            return
        active_alive = [z for z in self.zombies if z.hp > 0 and z.state.get("dying_t", 0.0) <= 0.0]
        plant_positions = list(self.main.keys()) + list(self.support.keys()) + list(self.armor.keys())
        self.mode_event_t += dt
        self.mode_spawn_t += dt
        bungee_interval = max(4.4, self.mode_float("bungee_blitz_raid_interval", 7.4) - self.elapsed * 0.014)
        if plant_positions:
            while self.mode_event_t >= bungee_interval:
                self.mode_event_t -= bungee_interval
                raid_count = 1 + (1 if self.elapsed >= self.target_duration * 0.45 else 0)
                raid_count = min(2, max(1, raid_count))
                for _ in range(raid_count):
                    target_rows = sorted({r for r, _ in plant_positions}) or list(range(self.rows()))
                    row = random.choice(target_rows)
                    x = self.lawn_right() + random.randint(24, 72)
                    z = self.spawn_zombie_instance("bungee", row, float(x), wave_idx=1, hp_scale=0.92, speed_scale=1.0, dps_scale=1.0)
                    z.state["steal_t"] = random.uniform(1.35, 1.7)
                    self.zombies.append(z)
        ground_interval = max(5.8, self.mode_float("bungee_blitz_ground_interval", 8.8) - self.elapsed * 0.018)
        ground_cap = max(2, int(self.mode_float("bungee_blitz_ground_cap", 5.0)))
        while self.mode_spawn_t >= ground_interval and len(active_alive) < ground_cap:
            self.mode_spawn_t -= ground_interval
            ground_pool = [kind for kind in self.mode_list("bungee_blitz_ground_pool") if kind in self.zombie_types]
            if not ground_pool:
                ground_pool = ["normal", "conehead", "buckethead"]
            kind = random.choice(ground_pool)
            row = self.choose_spawn_row(kind)
            spawn_x = self.lawn_right() + random.randint(38, 96)
            self.zombies.append(self.spawn_zombie_instance(kind, row, float(spawn_x), wave_idx=1, hp_scale=0.90, speed_scale=0.96, dps_scale=0.92))
            active_alive = [z for z in self.zombies if z.hp > 0 and z.state.get("dying_t", 0.0) <= 0.0]

    def setup_whack_mode(self) -> None:
        self.cards = []
        self.card_timer = {}
        self.selected = ""
        self.main.clear()
        self.support.clear()
        self.armor.clear()
        self.zombies.clear()
        self.tokens.clear()
        self.cleaners = [False for _ in range(self.rows())]
        self.mode_spawn_t = 0.0
        self.mode_score = 0
        self.mode_goal = max(10, int(self.mode_float("whack_goal", 24.0)))
        self.mode_misses = 0

    def spawn_whack_target(self) -> None:
        kinds = [k for k in self.mode_list("whack_zombies") if k in self.zombie_types]
        if not kinds:
            kinds = ["normal", "conehead", "buckethead", "newspaper"]
        row = random.randrange(self.rows())
        col = random.randint(2, COLS - 1)
        target_x = float(self.cell_center(row, col)[0])
        crowded = any(z.state.get("whack_popup", 0.0) > 0.0 and z.row == row and abs(z.x - target_x) < 36 for z in self.zombies)
        if crowded:
            return
        kind = random.choice(kinds)
        z = self.spawn_zombie_instance(kind, row, target_x, wave_idx=1, hp_scale=0.42, speed_scale=0.0, dps_scale=0.0)
        z.speed = 0.0
        z.dps = 0.0
        z.state["whack_popup"] = 1.0
        z.state["whack_t"] = random.uniform(0.95, 1.45)
        z.state["whack_col"] = float(col)
        self.zombies.append(z)

    def hit_whack_target(self, px: int, py: int) -> bool:
        if not self.is_whack_mode():
            return False
        for z in self.zombies:
            if z.hp <= 0 or z.state.get("dying_t", 0.0) > 0.0:
                continue
            if z.state.get("whack_popup", 0.0) <= 0.0:
                continue
            zy = self.row_y(z.row) - 8
            if abs(px - z.x) <= 36 and abs(py - zy) <= 42:
                self.slay_zombie(z, source="whack")
                self.mode_score += 1
                self.hit_sparks.append({"x": z.x, "y": zy, "t": 0.22, "ttl": 0.22})
                return True
        return False

    def update_whack_mode(self, dt: float) -> None:
        self.mode_spawn_t += dt
        spawn_interval = max(0.46, self.mode_float("whack_spawn_interval", 0.9) - self.elapsed * 0.0018)
        active = [z for z in self.zombies if z.hp > 0 and z.state.get("dying_t", 0.0) <= 0.0 and z.state.get("whack_popup", 0.0) > 0.0]
        active_cap = max(3, int(self.mode_float("whack_active_cap", 6.0)))
        while self.mode_spawn_t >= spawn_interval and len(active) < active_cap:
            self.mode_spawn_t -= spawn_interval
            self.spawn_whack_target()
            active = [z for z in self.zombies if z.hp > 0 and z.state.get("dying_t", 0.0) <= 0.0 and z.state.get("whack_popup", 0.0) > 0.0]
        for z in list(self.zombies):
            if z.hp <= 0 or z.state.get("dying_t", 0.0) > 0.0:
                continue
            if z.state.get("whack_popup", 0.0) <= 0.0:
                continue
            z.state["whack_t"] = float(z.state.get("whack_t", 0.0)) - dt
            if z.state["whack_t"] <= 0.0:
                self.mode_misses += 1
                self.zombies.remove(z)
        miss_limit = max(1, int(self.mode_float("whack_miss_limit", 8.0)))
        if self.mode_score >= self.mode_goal:
            self.result = "win"
        elif self.mode_misses >= miss_limit:
            self.result = "lose"

    def plant_interval_scale(self) -> float:
        return max(0.35, self.mode_float("plant_interval_scale", 1.0))

    def scaled_plant_interval(self, base: float) -> float:
        return max(0.12, float(base) * self.plant_interval_scale())

    def special_hint_key(self) -> str:
        key = str(self.mode_rules.get("special_hint_key", ""))
        if key:
            return key
        if self.is_beghouled_twist_mode():
            return "beghouled_twist_hint"
        if self.is_beghouled_mode():
            return "beghouled_hint"
        if self.is_seeing_stars_mode():
            return "seeing_stars_hint"
        if self.is_vasebreaker_mode():
            return "vasebreaker_hint"
        if self.is_i_zombie_mode():
            return "i_zombie_objective"
        if self.is_zombiquarium_mode():
            return "zombiquarium_hint"
        if self.is_last_stand_mode():
            return "last_stand_hint"
        return ""

    def setup_portal_combat_mode(self) -> None:
        self.portal_pairs.clear()
        raw_pairs = self.mode_rules.get("portal_pairs", [])
        if not isinstance(raw_pairs, (list, tuple)) or not raw_pairs:
            raw_pairs = [
                [[0, 2], [max(0, self.rows() - 2), 6]],
                [[min(1, self.rows() - 1), 6], [max(0, self.rows() - 1), 2]],
                [[min(2, self.rows() - 1), 3], [0, 5]],
            ]
        palettes = [
            ((108, 182, 236), (178, 228, 252)),
            ((214, 138, 228), (244, 196, 252)),
            ((236, 186, 102), (252, 224, 154)),
        ]
        for idx, pair in enumerate(raw_pairs):
            if not isinstance(pair, (list, tuple)) or len(pair) != 2:
                continue
            endpoints: List[Tuple[int, int]] = []
            for endpoint in pair:
                if not isinstance(endpoint, (list, tuple)) or len(endpoint) != 2:
                    continue
                rr = int(clamp(float(endpoint[0]), 0.0, float(self.rows() - 1)))
                cc = int(clamp(float(endpoint[1]), 1.0, float(COLS - 2)))
                endpoints.append((rr, cc))
            if len(endpoints) != 2:
                continue
            col_outer, col_inner = palettes[idx % len(palettes)]
            self.portal_pairs.append({
                "a": endpoints[0],
                "b": endpoints[1],
                "outer": col_outer,
                "inner": col_inner,
            })

    def setup_bobsled_bonanza_mode(self) -> None:
        self.ice_rows = {row: 9999.0 for row in range(self.rows()) if not self.is_water(row)}

    def setup_special_minigame_mode(self) -> None:
        if self.mode_bool("hide_fog_overlay", False) and self.field.has_fog:
            self.fog_clear_t = 9999.0
        self.portal_layout_index = 0
        self.portal_shuffle_t = 0.0
        self.portal_shift_notice_t = 0.0
        self.bobsled_burst_t = 0.0
        self.bobsled_burst_cycle_index = 0
        if self.is_zomboss_boss_mode():
            self.setup_zomboss_boss_mode()
        if self.is_seeing_stars_mode():
            self.setup_seeing_stars_mode()
        if self.is_portal_combat_mode():
            raw_layouts = self.mode_rules.get("portal_layouts", [])
            if isinstance(raw_layouts, (list, tuple)) and raw_layouts:
                self.mode_rules["portal_pairs"] = raw_layouts[0]
            self.setup_portal_combat_mode()
        if self.is_zombiquarium_mode():
            self.setup_zombiquarium()
            self.initial_selected_cards = []
        if self.is_last_stand_mode():
            self.mode_rules["last_stand_prepare"] = bool(self.mode_rules.get("last_stand_prepare", True))
            self.wave_pause_t = 0.0
            self.current_wave = 0
            self.next_wave = 1.0
        if self.is_bobsled_bonanza_mode():
            self.setup_bobsled_bonanza_mode()
        if self.is_bungee_blitz_mode():
            self.total_waves = 0
            self.large_wave_indices = ()
            self.final_wave_index = 0
            self.wave_budgets = []
            self.wave_spawn_queue = []
            self.wave_spawn_total = 0
            self.wave_spawn_remaining = 0
            self.cleaners = [False for _ in range(self.rows())]

    def update_special_minigame_mode(self, dt: float) -> None:
        if self.is_zomboss_boss_mode():
            self.update_zomboss_boss_mode(dt)
        if self.is_portal_combat_mode():
            raw_layouts = self.mode_rules.get("portal_layouts", [])
            interval = self.mode_float("portal_shuffle_interval", 0.0)
            if isinstance(raw_layouts, (list, tuple)) and len(raw_layouts) > 1 and interval > 0.0:
                self.portal_shuffle_t += dt
                if self.portal_shuffle_t >= interval:
                    self.portal_shuffle_t -= interval
                    self.portal_layout_index = (self.portal_layout_index + 1) % len(raw_layouts)
                    self.mode_rules["portal_pairs"] = raw_layouts[self.portal_layout_index]
                    self.setup_portal_combat_mode()
                    self.portal_shift_notice_t = 1.6
            self.portal_shift_notice_t = max(0.0, self.portal_shift_notice_t - dt)
        if self.is_bobsled_bonanza_mode():
            for row in list(self.ice_rows.keys()):
                self.ice_rows[row] = max(0.0, float(self.ice_rows.get(row, 0.0)) - dt * 0.02)
            interval = self.mode_float("bobsled_burst_interval", 0.0)
            cap = max(0, int(self.mode_float("bobsled_burst_cap", 0.0)))
            cycle = [k for k in self.mode_list("bobsled_burst_cycle") if k in self.zombie_types]
            if interval > 0.0 and cap > 0 and cycle:
                self.bobsled_burst_t += dt
                active_specials = sum(
                    1
                    for z in self.zombies
                    if z.kind in {"bobsled_team", "zomboni"} and z.hp > 0 and float(z.state.get("dying_t", 0.0)) <= 0.0
                )
                while self.bobsled_burst_t >= interval:
                    self.bobsled_burst_t -= interval
                    if active_specials >= cap:
                        continue
                    kind = cycle[self.bobsled_burst_cycle_index % len(cycle)]
                    self.bobsled_burst_cycle_index += 1
                    self.spawn_zombie(self.current_wave or 1, forced_kind=kind)
                    active_specials += 1

    def draw_special_minigame_overlay(self, screen: pygame.Surface, plant_sprite_fn, zombie_sprite_fn=None, tr_fn=None, entity_anim_frame_fn=None) -> None:
        if self.is_zomboss_boss_mode():
            self.draw_zomboss_boss_overlay(screen, zombie_sprite_fn, tr_fn, entity_anim_frame_fn)
        if self.is_portal_combat_mode():
            self.draw_portal_combat_overlay(screen)
            if self.portal_shift_notice_t > 0.0:
                alpha = int(clamp(self.portal_shift_notice_t / 1.6, 0.0, 1.0) * 220)
                note_rect = pygame.Rect(LAWN_X + 180, LAWN_Y + 8, 180, 14)
                plate = pygame.Surface(note_rect.size, pygame.SRCALPHA)
                plate.fill((88, 42, 96, min(180, alpha)))
                screen.blit(plate, note_rect.topleft)
                pygame.draw.rect(screen, (216, 190, 250, min(210, alpha)), note_rect, 2, border_radius=9)
                notice_font = pygame.font.Font(None, 16)
                notice = notice_font.render(self.tr("portal_shifted"), True, (248, 238, 252))
                notice.set_alpha(min(255, alpha + 28))
                screen.blit(notice, notice.get_rect(center=(note_rect.centerx, note_rect.centery + 1)))
        if self.is_seeing_stars_mode():
            self.draw_seeing_stars_overlay(screen)
        if self.is_beghouled_mode() or self.is_beghouled_twist_mode():
            self.draw_beghouled_overlay(screen, plant_sprite_fn)
        if self.is_invisi_ghoul_mode():
            pulse = 0.5 + 0.5 * math.sin(self.elapsed * 3.2)
            for collection in (self.main, self.support):
                for plant in collection.values():
                    if plant.hp <= 0 or plant.kind != "plantern":
                        continue
                    cx, cy = self.cell_center(plant.row, plant.col)
                    aura = pygame.Surface((CELL_W * 5, CELL_H * 3), pygame.SRCALPHA)
                    center = (aura.get_width() // 2, aura.get_height() // 2)
                    for radius, alpha in ((48, 22), (72, 16), (92, 10)):
                        pygame.draw.circle(aura, (248, 228, 142, int(alpha * (0.7 + pulse * 0.3))), center, radius, 2)
                    screen.blit(aura, (cx - aura.get_width() // 2, cy - aura.get_height() // 2))

    def apply_portal_transfer(self, row: int, x: float, direction: int, cooldown: float) -> Tuple[int, float, float]:
        if cooldown > 0.0 or not self.portal_pairs:
            return row, x, cooldown
        for pair in self.portal_pairs:
            for src_key, dst_key in (("a", "b"), ("b", "a")):
                src_row, src_col = pair[src_key]
                if row != src_row:
                    continue
                src_x, _ = self.cell_center(src_row, src_col)
                if abs(x - src_x) > 14.0:
                    continue
                dst_row, dst_col = pair[dst_key]
                dst_x, _ = self.cell_center(dst_row, dst_col)
                offset = 18.0 if direction > 0 else -18.0
                return dst_row, dst_x + offset, 0.34
        return row, x, cooldown

    def draw_portal_combat_overlay(self, screen: pygame.Surface) -> None:
        pulse = 0.5 + 0.5 * math.sin(self.elapsed * 3.8)
        for pair in self.portal_pairs:
            for key in ("a", "b"):
                row, col = pair[key]
                cx, cy = self.cell_center(row, col)
                outer = pygame.Rect(cx - 22, cy - 22, 44, 44)
                inner = outer.inflate(-12, -12)
                pygame.draw.ellipse(screen, pair["outer"], outer, 4)
                pygame.draw.ellipse(screen, pair["inner"], inner, 3)
                glow = pygame.Surface((56, 56), pygame.SRCALPHA)
                pygame.draw.circle(glow, (*pair["inner"], int(46 + 24 * pulse)), (28, 28), 16, 2)
                screen.blit(glow, (cx - 28, cy - 28))

    def zombotany_variant_roster(self) -> List[str]:
        requested = [kind for kind in self.mode_list("zombotany_variants") if kind in self.plant_types]
        if requested:
            intro_count = max(0, int(self.mode_float("zombotany_intro_count", 0.0)))
            if intro_count > 0 and self.special_pressure_progress() < 0.45:
                return requested[: min(len(requested), intro_count)]
            return requested
        mode_name = self.mode_name()
        return list(ZOMBOTANY_VARIANT_ROSTERS.get(mode_name, ZOMBOTANY_VARIANT_ROSTERS["mini_zombotany"]))

    def assign_zombotany_variant(self, zombie: Zombie) -> None:
        if not self.is_zombotany_mode() or zombie.hypnotized or zombie.kind in ("balloon", "zomboni", "catapult", "bobsled_team", "bungee"):
            return
        if zombie.state.get("zombotany_variant"):
            return
        roster = self.zombotany_variant_roster()
        if not roster:
            return
        variant = random.choice(roster)
        zombie.state["zombotany_variant"] = variant
        zombie.state["zombotany_action_t"] = random.uniform(1.2, 2.0)
        if variant == "wallnut":
            zombie.hp *= 1.45
            zombie.hp_max *= 1.45
            zombie.speed *= 0.92
        elif variant == "tall_nut":
            zombie.hp *= 1.8
            zombie.hp_max *= 1.8
            zombie.speed *= 0.86
        elif variant == "sunflower":
            zombie.state["zombotany_action_t"] = random.uniform(4.8, 6.6)
        elif variant == "gatling":
            zombie.state["zombotany_action_t"] = random.uniform(1.5, 2.0)
        elif variant in ("squash", "jalapeno"):
            zombie.state["zombotany_action_t"] = random.uniform(2.2, 3.0)

    def update_zombotany_zombie(self, zombie: Zombie, dt: float) -> None:
        variant = str(zombie.state.get("zombotany_variant", ""))
        if not variant:
            return
        timer = float(zombie.state.get("zombotany_action_t", 0.0)) - dt
        zombie.state["zombotany_action_t"] = timer
        if timer > 0.0:
            return
        if variant == "sunflower":
            self.tokens.append(Token(zombie.x - 8, self.row_y(zombie.row) - 18, 25, 8.0, "sun"))
            zombie.state["zombotany_action_t"] = random.uniform(5.4, 7.0)
            return
        front_plants = [
            plant
            for collection in (self.armor, self.main, self.support)
            for plant in collection.values()
            if plant.row == zombie.row and plant.hp > 0 and self.is_plant_edible(plant) and self.cell_center(plant.row, plant.col)[0] < zombie.x
        ]
        front_plants.sort(key=lambda plant: zombie.x - self.cell_center(plant.row, plant.col)[0])
        front_target = front_plants[0] if front_plants else None
        if variant == "jalapeno":
            if not zombie.state.get("zombotany_used_special", 0.0):
                if front_target and (zombie.x - self.cell_center(front_target.row, front_target.col)[0]) <= CELL_W * 2.1:
                    for plant in list(self.main.values()) + list(self.support.values()) + list(self.armor.values()):
                        if plant.row != zombie.row or plant.hp <= 0:
                            continue
                        plant.hp -= 9999
                        plant.state["hit_flash"] = 0.24
                    zombie.state["zombotany_used_special"] = 1.0
                    zombie.state["bite_t"] = max(float(zombie.state.get("bite_t", 0.0)), 0.18)
                zombie.state["zombotany_action_t"] = random.uniform(5.0, 6.4)
                return
            zombie.state["zombotany_action_t"] = random.uniform(3.0, 4.2)
            return
        if variant == "squash":
            if front_target and (zombie.x - self.cell_center(front_target.row, front_target.col)[0]) <= CELL_W * 1.8:
                front_target.hp -= 220.0
                front_target.state["hit_flash"] = 0.24
                zombie.state["bite_t"] = max(float(zombie.state.get("bite_t", 0.0)), 0.18)
            zombie.state["zombotany_action_t"] = random.uniform(2.4, 3.2)
            return
        if front_target is None:
            zombie.state["zombotany_action_t"] = random.uniform(0.8, 1.4)
            return
        damage = 16.0
        slow = 0.0
        shots = 1
        color = (84, 194, 96)
        outline = (32, 102, 44)
        if variant == "snowpea":
            slow = 1.8
            color = (110, 210, 245)
            outline = (30, 110, 140)
        elif variant == "repeater":
            shots = 2
            damage = 18.0
        elif variant == "gatling":
            shots = 4
            damage = 17.0
        elif variant == "tall_nut":
            zombie.state["zombotany_action_t"] = random.uniform(1.5, 2.2)
            return
        elif variant == "peashooter":
            damage = 16.0
        else:
            zombie.state["zombotany_action_t"] = random.uniform(1.4, 2.0)
            return
        base_y = self.row_y(zombie.row) - 8
        for shot_idx in range(shots):
            self.add_projectile(
                zombie.row,
                zombie.x - 16 - shot_idx * 10,
                base_y + (shot_idx - (shots - 1) / 2.0) * 6.0,
                damage,
                slow=slow,
                direction=-1,
                color=color,
                outline=outline,
                enemy=True,
            )
        zombie.state["bite_t"] = max(float(zombie.state.get("bite_t", 0.0)), 0.08)
        zombie.state["zombotany_action_t"] = random.uniform(1.45, 2.15) if shots == 1 else random.uniform(1.8, 2.4)

    def update_special_mode_logic(self, dt: float) -> None:
        if self.is_beghouled_mode() or self.is_beghouled_twist_mode():
            self.update_beghouled_mode(dt)
        if self.is_seeing_stars_mode():
            self.update_seeing_stars_mode(dt)
        if self.is_zombiquarium_mode():
            self.update_zombiquarium_mode(dt)
        if self.is_bungee_blitz_mode():
            self.update_bungee_blitz_mode(dt)
        if self.is_whack_mode():
            self.update_whack_mode(dt)
        self.update_special_minigame_mode(dt)

    def slot_machine_spin(self) -> Tuple[str, int, Optional[str]]:
        if not self.is_slot_machine_mode():
            return ("invalid", 0, None)
        cost = max(1, int(self.mode_float("slot_spin_cost", 25.0)))
        if self.sun < cost:
            return ("no_sun", cost, None)
        self.sun -= cost
        roll = random.random()
        if roll < 0.46:
            gain = random.choice([50, 75])
            self.sun += gain
            return ("sun", gain, None)
        if roll < 0.62:
            gain = random.choice([25, 40])
            self.sun += gain
            return ("sun", gain, None)
        if roll < 0.78:
            gain = random.choice([15, 20, 25])
            self.save_data["coins"] = int(self.save_data.get("coins", 0)) + gain
            return ("coin", gain, None)
        if roll < 0.93 and self.cards:
            ready = random.choice(self.cards)
            self.card_timer[ready] = 0.0
            return ("ready", 0, ready)
        jackpot = max(120, int(self.mode_float("slot_jackpot_sun", 225.0)))
        self.sun += jackpot
        return ("jackpot", jackpot, None)

    def card_runtime_cost(self, card_kind: str) -> int:
        target_kind = self.resolve_card_kind(card_kind)
        cfg = self.plant_types.get(target_kind) or self.plant_types.get(card_kind)
        return int(cfg.cost if cfg else 0)

    def card_runtime_cooldown(self, card_kind: str) -> float:
        target_kind = self.resolve_card_kind(card_kind)
        cfg = self.plant_types.get(target_kind) or self.plant_types.get(card_kind)
        if not cfg:
            return 0.0
        return float(cfg.cooldown)

    def ensure_plant_anim_state(self, plant: Plant) -> None:
        if "anim_phase" not in plant.state:
            plant.state["anim_phase"] = random.uniform(0.0, math.tau)
        if "last_hp" not in plant.state:
            plant.state["last_hp"] = plant.hp
        if not isinstance(plant.state.get("_anim"), AnimationState):
            plant.state["_anim"] = AnimationState()
        if not isinstance(plant.state.get("_anim_seen"), dict):
            plant.state["_anim_seen"] = {}
        self.update_plant_visual_state(plant)

    def ensure_zombie_anim_state(self, zombie: Zombie) -> None:
        if "anim_phase" not in zombie.state:
            zombie.state["anim_phase"] = random.uniform(0.0, math.tau)
        if "last_hp" not in zombie.state:
            zombie.state["last_hp"] = zombie.hp
        if not isinstance(zombie.state.get("_anim"), AnimationState):
            zombie.state["_anim"] = AnimationState()
        if not isinstance(zombie.state.get("_anim_seen"), dict):
            zombie.state["_anim_seen"] = {}
        if zombie.kind == "balloon":
            zombie.state.setdefault("balloon_state", "airborne")
            zombie.state.setdefault("balloon_drop_t", 0.0)
            zombie.state.setdefault("balloon_drop_total", 0.92)
            zombie.state.setdefault("balloon_grounded_t", 0.0)
            zombie.state.setdefault("balloon_land_wobble_t", 0.0)
            zombie.state.setdefault("balloon_land_wobble_total", 0.58)
        elif zombie.kind == "bungee":
            zombie.state.setdefault("bungee_state", "descending")
            zombie.state.setdefault("bungee_phase_t", 0.92)
            zombie.state.setdefault("bungee_phase_total", 0.92)
            zombie.state.setdefault("target_row", -1.0)
            zombie.state.setdefault("target_col", -1.0)
            zombie.state.setdefault("has_loot", 0.0)
        elif zombie.kind == "digger":
            zombie.state.setdefault("digger_state", "burrow_enter")
            zombie.state.setdefault("digger_phase_t", 0.72)
            zombie.state.setdefault("digger_phase_total", 0.72)
            zombie.state.setdefault("digger_target_x", LAWN_X + CELL_W * 2.2)
        elif zombie.kind == "ladder":
            zombie.state.setdefault("ladder_state", "carrying")
            zombie.state.setdefault("ladder_phase_t", 0.0)
            zombie.state.setdefault("ladder_phase_total", 0.0)
        elif zombie.kind == "pole_vaulting":
            zombie.state.setdefault("pole_vault_state", "run")
            zombie.state.setdefault("pole_vault_t", 0.0)
            zombie.state.setdefault("pole_vault_total", 0.0)
            zombie.state.setdefault("pole_vault_end_x", zombie.x)
        elif zombie.kind == "zomboni":
            zombie.state.setdefault("zomboni_state", "cruise")
            zombie.state.setdefault("zomboni_crush_t", 0.0)
            zombie.state.setdefault("zomboni_crush_total", 0.42)
        elif zombie.kind == "catapult":
            zombie.state.setdefault("catapult_state", "walk")
            zombie.state.setdefault("catapult_phase_t", random.uniform(1.7, 2.8))
            zombie.state.setdefault("catapult_phase_total", float(zombie.state.get("catapult_phase_t", 2.0)))
            zombie.state.setdefault("catapult_target_col", -1.0)
        elif zombie.kind == "pogo":
            zombie.state.setdefault("pogo_state", "hop_loop")
            zombie.state.setdefault("pogo_phase_t", 0.0)
            zombie.state.setdefault("pogo_recover_total", 0.32)
            zombie.state.setdefault("pogo_start_x", zombie.x)
            zombie.state.setdefault("pogo_end_x", zombie.x)

    def ensure_entity_animation_runtime(self, entity: object) -> AnimationState:
        st = getattr(entity, "state", {})
        if not isinstance(st.get("_anim"), AnimationState):
            st["_anim"] = AnimationState()
        if not isinstance(st.get("_anim_seen"), dict):
            st["_anim_seen"] = {}
        return st["_anim"]

    def animation_seen(self, entity: object) -> Dict[str, int]:
        st = getattr(entity, "state", {})
        if not isinstance(st.get("_anim_seen"), dict):
            st["_anim_seen"] = {}
        return st["_anim_seen"]

    def bump_anim_event(self, entity: object, key: str) -> None:
        st = getattr(entity, "state", {})
        seq_key = f"{key}_seq"
        st[seq_key] = int(st.get(seq_key, 0)) + 1

    def consume_anim_event(self, entity: object, key: str) -> bool:
        st = getattr(entity, "state", {})
        seen = self.animation_seen(entity)
        seq_key = f"{key}_seq"
        current = int(st.get(seq_key, 0))
        if current > int(seen.get(seq_key, 0)):
            seen[seq_key] = current
            return True
        return False

    def animation_clip_for(self, entity_kind: str, variant: str, clip_name: str) -> Optional[AnimationClip]:
        provider = self.animation_clip_provider
        if callable(provider):
            try:
                return provider(entity_kind, clip_name, variant=variant)
            except TypeError:
                return provider(entity_kind, clip_name, variant)
        return None

    def switch_entity_animation(self, entity: object, entity_kind: str, variant: str, clip_name: str) -> AnimationState:
        anim = self.ensure_entity_animation_runtime(entity)
        clip = self.animation_clip_for(entity_kind, variant, clip_name)
        if clip is None:
            anim.current_clip = clip_name
            anim.frame_index = 0
            anim.frame_timer_ms = 0.0
            anim.locked = False
            anim.pending_clip = ""
            anim.hold_timer_ms = 0.0
            return anim
        anim.current_clip = clip_name
        anim.frame_index = 0
        anim.frame_timer_ms = 0.0
        anim.locked = bool(clip.lock_until_end)
        anim.pending_clip = ""
        anim.hold_timer_ms = 0.0
        return anim

    def plant_animation_variant(self, plant: Plant) -> Optional[str]:
        if plant.kind in {"sunflower", "peashooter", "wallnut", "potato_mine", "imitater"}:
            return plant.kind
        return None

    def zombie_animation_variant(self, zombie: Zombie) -> Optional[str]:
        if zombie.kind in {
            "normal",
            "conehead",
            "buckethead",
            "pole_vaulting",
            "newspaper",
            "bungee",
            "balloon",
            "digger",
            "ladder",
            "zomboni",
            "catapult",
            "pogo",
            "zomboss",
        }:
            return zombie.kind
        return None

    def resolve_entity_animation(self, entity: object, entity_kind: str) -> Tuple[Optional[str], Optional[str]]:
        if isinstance(entity, Plant):
            variant = self.plant_animation_variant(entity)
            if variant is None:
                return None, None
            if entity.hp <= 0:
                return variant, "death"
            if self.consume_anim_event(entity, "hit"):
                return variant, "hit"
            if entity.kind == "sunflower":
                if self.consume_anim_event(entity, "sun"):
                    return variant, "sun_produce"
                return variant, "idle"
            if entity.kind == "peashooter":
                if self.consume_anim_event(entity, "shoot"):
                    return variant, "shoot"
                return variant, "idle"
            if entity.kind == "wallnut":
                if self.consume_anim_event(entity, "hit"):
                    stage = str(entity.state.get("damage_stage", "healthy"))
                    return variant, "hit"
                stage = str(entity.state.get("damage_stage", "healthy"))
                if stage == "heavy_cracked":
                    return variant, "idle_heavy_cracked"
                if stage == "cracked":
                    return variant, "idle_cracked"
                return variant, "idle_healthy"
            if entity.kind == "potato_mine":
                if self.consume_anim_event(entity, "detonate"):
                    return variant, "detonate"
                potato_state = str(entity.state.get("potato_state", "arming"))
                if potato_state == "armed":
                    return variant, "armed_idle"
                if potato_state == "priming":
                    return variant, "priming"
                return variant, "arming"
            if entity.kind == "imitater":
                if float(entity.state.get("imitater_morph_t", 0.0)) > 0.0 or str(entity.state.get("imitater_state", "copied")) == "morphing":
                    return variant, "morphing"
                return variant, "copied_idle"
            return variant, "idle"
        if isinstance(entity, Zombie):
            variant = self.zombie_animation_variant(entity)
            if variant is None:
                return None, None
            if entity.hp <= 0 or float(entity.state.get("dying_t", 0.0)) > 0.0:
                if entity.kind == "zomboss":
                    return variant, "defeat"
                return variant, "death"
            if entity.kind in {"conehead", "buckethead"} and self.consume_anim_event(entity, "helmet_break"):
                return variant, "helmet_break"
            if entity.kind == "newspaper":
                state = str(entity.state.get("paper_state", "paper_intact"))
                if state == "paper_lost_transition":
                    return variant, "paper_loss"
                if self.consume_anim_event(entity, "hit"):
                    return variant, "hit_enraged" if state == "enraged" else "hit_paper"
                if state == "enraged":
                    return variant, "eat_enraged" if float(entity.state.get("bite_t", 0.0)) > 0.0 else "enraged_walk"
                if float(entity.state.get("bite_t", 0.0)) > 0.0:
                    return variant, "eat_paper"
                return variant, "walk_paper"
            if entity.kind == "bungee":
                state = self.bungee_state(entity)
                if state == "descending":
                    return variant, "descending"
                if state == "lock_target":
                    return variant, "lock_target"
                if state == "steal_lift":
                    return variant, "steal_lift"
                if state == "blocked_exit":
                    return variant, "blocked_exit"
                return variant, "exit"
            if entity.kind == "balloon":
                state = self.balloon_state(entity)
                if state == "airborne":
                    return variant, "airborne"
                if state == "popped_fall":
                    return variant, "popped_fall"
                return variant, "eat" if float(entity.state.get("bite_t", 0.0)) > 0.0 else "grounded_walk"
            if entity.kind == "digger":
                state = self.digger_state(entity)
                if state in {"burrow_enter", "underground_travel", "emerge", "surface_attack"}:
                    return variant, state
            if entity.kind == "ladder":
                state = self.ladder_state(entity)
                if state == "placing":
                    return variant, "placing"
                if state == "placed_attack":
                    return variant, "eat" if float(entity.state.get("bite_t", 0.0)) > 0.0 else "placed_walk"
                return variant, "carrying_walk"
            if entity.kind == "zomboni":
                state = self.zomboni_state(entity)
                return variant, "crush" if state == "crush" else "cruise"
            if entity.kind == "catapult":
                if self.consume_anim_event(entity, "lob"):
                    return variant, "lob"
                state = self.catapult_state(entity)
                if state == "windup":
                    return variant, "windup"
                if state == "recover":
                    return variant, "recover"
                return variant, "walk"
            if entity.kind == "pogo":
                state = self.pogo_state(entity)
                if state == "vault_over":
                    return variant, "vault_over"
                if state == "recover":
                    return variant, "recover"
                return variant, "eat" if float(entity.state.get("bite_t", 0.0)) > 0.0 else "hop_loop"
            if entity.kind == "pole_vaulting":
                pole_state = str(entity.state.get("pole_vault_state", "run"))
                if pole_state == "vault":
                    return variant, "vault"
                if pole_state == "post_vault_walk":
                    if self.consume_anim_event(entity, "hit"):
                        return variant, "hit_post_vault"
                    return variant, "eat" if float(entity.state.get("bite_t", 0.0)) > 0.0 else "post_vault_walk"
                if self.consume_anim_event(entity, "hit"):
                    return variant, "hit_run"
                return variant, "eat" if float(entity.state.get("bite_t", 0.0)) > 0.0 else "run"
            if entity.kind == "zomboss":
                if self.consume_anim_event(entity, "hurt"):
                    return variant, "hurt"
                phase = str(self.zomboss_attack_phase or self.zomboss_pending_attack.get("phase", ""))
                if phase == "head_dip_row_select":
                    return variant, "head_dip_row_select"
                if phase == "windup_fire":
                    return variant, "windup_fire"
                if phase == "release_fire":
                    return variant, "release_fire"
                if phase == "windup_ice":
                    return variant, "windup_ice"
                if phase == "release_ice":
                    return variant, "release_ice"
                if phase == "bungee_call":
                    return variant, "bungee_call"
                if phase == "stomp_smash":
                    return variant, "stomp_smash"
                if phase == "rv_call":
                    return variant, "rv_call"
                if phase == "recover_exposed" or self.zomboss_exposed_t > 0.0:
                    return variant, "recover_exposed"
                return variant, "idle"
            if self.consume_anim_event(entity, "hit"):
                return variant, "hit"
            if float(entity.state.get("bite_t", 0.0)) > 0.0:
                return variant, "eat"
            return variant, "walk"
        return None, None

    def advance_entity_animation(self, entity: object, dt: float, entity_kind: str) -> None:
        variant, requested_clip = self.resolve_entity_animation(entity, entity_kind)
        if not variant or not requested_clip:
            return
        anim = self.ensure_entity_animation_runtime(entity)
        if not anim.current_clip:
            self.switch_entity_animation(entity, entity_kind, variant, requested_clip)
            return
        if requested_clip != anim.current_clip:
            current_clip = self.animation_clip_for(entity_kind, variant, anim.current_clip)
            if current_clip is not None and not current_clip.loop and anim.locked:
                anim.pending_clip = requested_clip
            else:
                self.switch_entity_animation(entity, entity_kind, variant, requested_clip)
                return
        clip = self.animation_clip_for(entity_kind, variant, anim.current_clip)
        if clip is None or not clip.frames:
            return
        def finish_non_loop(current_clip: AnimationClip, current_variant: str) -> bool:
            fallback_clip = current_clip.next_clip or anim.pending_clip
            if not fallback_clip:
                next_variant, next_requested = self.resolve_entity_animation(entity, entity_kind)
                fallback_clip = next_requested or anim.current_clip
                current_variant = next_variant or current_variant
            self.switch_entity_animation(entity, entity_kind, current_variant, fallback_clip)
            anim.pending_clip = ""
            return True

        dt_ms = dt * 1000.0
        if not clip.loop and anim.frame_index >= len(clip.frames) - 1 and anim.hold_timer_ms > 0.0:
            anim.hold_timer_ms = max(0.0, anim.hold_timer_ms - dt_ms)
            if anim.hold_timer_ms > 0.0:
                return
            finish_non_loop(clip, variant)
            clip = self.animation_clip_for(entity_kind, variant, anim.current_clip)
            if clip is None or not clip.frames:
                return
        anim.frame_timer_ms += dt_ms
        while clip.frames and anim.frame_timer_ms >= clip.frames[min(anim.frame_index, len(clip.frames) - 1)].duration_ms:
            anim.frame_timer_ms -= clip.frames[min(anim.frame_index, len(clip.frames) - 1)].duration_ms
            anim.frame_index += 1
            if anim.frame_index < len(clip.frames):
                continue
            if clip.loop:
                anim.frame_index = 0
                break
            if clip.hold_last_frame_ms > 0 and anim.hold_timer_ms <= 0.0:
                anim.frame_index = len(clip.frames) - 1
                anim.frame_timer_ms = 0.0
                anim.hold_timer_ms = float(clip.hold_last_frame_ms)
                break
            finish_non_loop(clip, variant)
            clip = self.animation_clip_for(entity_kind, variant, anim.current_clip)
            if clip is None or not clip.frames:
                break

    def get_entity_animation_state(self, entity: object) -> Optional[AnimationState]:
        st = getattr(entity, "state", {})
        anim = st.get("_anim")
        return anim if isinstance(anim, AnimationState) else None

    def ensure_zomboss_anim_actor(self) -> Optional[Zombie]:
        if not self.is_zomboss_boss_mode():
            return None
        if self.zomboss_actor is None:
            self.zomboss_actor = Zombie(
                kind="zomboss",
                row=max(0, self.rows() // 2),
                x=float(self.lawn_right() + 34),
                hp=max(1.0, self.zomboss_hp or 1.0),
                hp_max=max(1.0, self.zomboss_hp_max or 1.0),
                speed=0.0,
                dps=0.0,
                state={},
            )
        actor = self.zomboss_actor
        actor.row = max(0, self.rows() // 2)
        actor.x = float(self.lawn_right() + 34)
        actor.hp_max = max(1.0, self.zomboss_hp_max or actor.hp_max or 1.0)
        if self.zomboss_hp_max > 0.0:
            actor.hp = max(0.0, self.zomboss_hp)
        self.ensure_zombie_anim_state(actor)
        return actor

    def update_zomboss_animation(self, dt: float) -> None:
        actor = self.ensure_zomboss_anim_actor()
        if actor is None:
            return
        actor.hp = max(0.0, self.zomboss_hp)
        actor.hp_max = max(1.0, self.zomboss_hp_max or actor.hp_max)
        actor.state["hit_flash"] = max(0.0, float(actor.state.get("hit_flash", 0.0)) - dt)
        actor.state["boss_phase"] = self.zomboss_attack_phase
        actor.state["eye_mode"] = self.zomboss_eye_mode
        actor.state["exposed_t"] = self.zomboss_exposed_t
        actor.state["head_lane_row"] = self.zomboss_head_lane_row
        self.advance_entity_animation(actor, dt, "zombie")

    def rows(self) -> int:
        return self.field.rows

    def lawn_h(self) -> int:
        return self.rows() * CELL_H

    def lawn_right(self) -> int:
        return LAWN_X + COLS * CELL_W

    def lawn_bottom(self) -> int:
        return LAWN_Y + self.lawn_h()

    def row_y(self, row: int) -> int:
        return LAWN_Y + row * CELL_H + CELL_H // 2

    def cell_center(self, row: int, col: int) -> Tuple[int, int]:
        return (LAWN_X + col * CELL_W + CELL_W // 2, self.row_y(row))

    def is_water(self, row: int) -> bool:
        return row in self.field.water_rows

    def export_survival_state(self) -> Dict[str, object]:
        def pack_plant(plant: Plant) -> Dict[str, object]:
            return {
                "kind": plant.kind,
                "row": int(plant.row),
                "col": int(plant.col),
                "hp": float(plant.hp),
                "cd": float(plant.cd),
                "slot": plant.slot,
                "awake_override": bool(plant.awake_override),
                "state": dict(plant.state),
            }

        return {
            "main": [pack_plant(p) for p in self.main.values()],
            "support": [pack_plant(p) for p in self.support.values()],
            "armor": [pack_plant(p) for p in self.armor.values()],
            "graves": [(int(r), int(c), float(hp)) for (r, c), hp in self.graves.items()],
            "cleaners": [bool(x) for x in self.cleaners],
            "sun": int(self.sun),
        }

    def apply_survival_state(self, payload: Dict[str, object]) -> None:
        if not isinstance(payload, dict):
            return
        self.main.clear()
        self.support.clear()
        self.armor.clear()
        self.graves.clear()

        def unpack(items: object, target: Dict[Tuple[int, int], Plant], fallback_slot: str) -> None:
            if not isinstance(items, list):
                return
            for item in items:
                if not isinstance(item, dict):
                    continue
                kind = str(item.get("kind", ""))
                if kind not in self.plant_types:
                    continue
                row = int(clamp(float(item.get("row", 0.0)), 0.0, float(self.rows() - 1)))
                col = int(clamp(float(item.get("col", 0.0)), 0.0, float(COLS - 1)))
                hp = max(1.0, float(item.get("hp", 1.0)))
                cd = max(0.0, float(item.get("cd", 0.0)))
                slot = str(item.get("slot", fallback_slot)) or fallback_slot
                awake_override = bool(item.get("awake_override", False))
                raw_state = item.get("state", {})
                state = dict(raw_state) if isinstance(raw_state, dict) else {}
                plant = Plant(kind=kind, row=row, col=col, hp=hp, cd=cd, slot=slot, awake_override=awake_override, state=state)
                plant.state["hp_max"] = max(float(self.plant_types[kind].hp) * self.plant_hp_scale(), float(plant.state.get("hp_max", hp)))
                self.ensure_plant_anim_state(plant)
                target[(row, col)] = plant

        unpack(payload.get("main", []), self.main, "main")
        unpack(payload.get("support", []), self.support, "support")
        unpack(payload.get("armor", []), self.armor, "armor")

        graves = payload.get("graves", [])
        if isinstance(graves, list):
            for row, col, hp in graves:
                rr = int(clamp(float(row), 0.0, float(self.rows() - 1)))
                cc = int(clamp(float(col), 0.0, float(COLS - 1)))
                self.graves[(rr, cc)] = max(1.0, float(hp))

        cleaners = payload.get("cleaners", [])
        if isinstance(cleaners, list) and cleaners:
            clean = [bool(x) for x in cleaners[: self.rows()]]
            if len(clean) < self.rows():
                clean.extend([True] * (self.rows() - len(clean)))
            self.cleaners = clean
        sun = payload.get("sun", None)
        if isinstance(sun, (int, float)):
            self.sun = max(0, int(sun))

    def level_available_cards(self, level: LevelConfig) -> List[str]:
        upgrade_locked = set(UPGRADE_PLANT_KEYS)
        owned = set(k for k, v in self.save_data.get("upgrades", {}).items() if v)
        cards: List[str] = []
        for c in level.cards:
            if c not in self.plant_types:
                continue
            if c in upgrade_locked and c not in owned:
                continue
            cards.append(c)
        if not cards:
            cards = ["sunflower", "peashooter", "wallnut"]
        return cards

    def reset(
        self,
        level: LevelConfig,
        selected_cards: Optional[List[str]] = None,
        mode_rules: Optional[Dict[str, object]] = None,
    ) -> None:
        self.level = level
        self.mode_rules = dict(mode_rules or {})
        self.field = self.fields[level.battlefield]
        available = self.level_available_cards(level)
        forced_pool = [k for k in self.mode_list("force_pool") if k in self.plant_types]
        if forced_pool:
            available = forced_pool
        chosen = [c for c in (selected_cards or []) if c in available]
        self.cards = chosen if chosen else list(available)
        if "imitater" in self.cards:
            desired = str(self.mode_rules.get("imitater_target", ""))
            non_imit = [c for c in self.cards if c != "imitater" and c not in UPGRADE_PLANT_KEYS]
            if desired and desired in self.plant_types and desired != "imitater" and desired not in UPGRADE_PLANT_KEYS:
                self.imitater_target = desired
            elif non_imit:
                self.imitater_target = non_imit[0]
            else:
                self.imitater_target = None
        else:
            self.imitater_target = None
        self.initial_selected_cards = list(self.cards)
        self.selected = self.cards[0] if self.cards else "sunflower"
        self.card_timer = {c: 0.0 for c in self.cards}
        self.sun = int(self.mode_float("start_sun_override", float(level.start_sun)))
        self.target_duration = self.mode_float("duration_override", level.duration)
        if self.target_duration <= 0:
            self.target_duration = level.duration * self.mode_float("duration_mult", 1.0)
        self.wave_interval = max(10.0, self.mode_float("wave_interval", 25.0))
        self.total_waves, self.large_wave_indices, self.final_wave_index, self.wave_budgets = self.mode_wave_budgets(level)
        self.elapsed = 0.0
        self.spawn_t = 0.0
        self.sky_t = 0.0
        self.conveyor_t = 0.0
        self.grave_t = 0.0
        self.fog_clear_t = 0.0
        self.kills = 0
        self.paused = False
        self.shovel_mode = False
        self.wave_warning_t = 0.0
        self.next_wave = 1.0
        self.current_wave = 0
        self.wave_spawn_queue = []
        self.wave_spawn_total = 0
        self.wave_spawn_remaining = 0
        self.wave_pause_t = 1.2
        self.result = None
        self.almanac_open = False
        self.main.clear()
        self.support.clear()
        self.armor.clear()
        self.graves.clear()
        self.zombies.clear()
        self.projs.clear()
        self.rolling_nuts.clear()
        self.tokens.clear()
        self.hit_sparks.clear()
        self.cleaners = [True for _ in range(self.rows())]
        self.vases.clear()
        self.vase_reveals.clear()
        self.brains.clear()
        self.brain_goal = 0
        self.mode_spawn_t = 0.0
        self.mode_event_t = 0.0
        self.mode_score = 0
        self.mode_goal = 0
        self.mode_misses = 0
        self.beghouled_cells.clear()
        self.beghouled_selected = None
        self.seeing_stars_targets.clear()
        self.zombiquarium_fish.clear()
        self.portal_pairs.clear()
        self.ice_rows.clear()
        self.portal_layout_index = 0
        self.portal_shuffle_t = 0.0
        self.portal_shift_notice_t = 0.0
        self.bobsled_burst_t = 0.0
        self.bobsled_burst_cycle_index = 0
        self.conveyor_opening_queue = []
        self.conveyor_weights = {}
        self.notice_request_text = ""
        self.notice_request_duration_ms = 0
        self.zomboss_hp = 0.0
        self.zomboss_hp_max = 0.0
        self.zomboss_intro_elapsed = 0.0
        self.zomboss_intro_index = 0
        self.zomboss_attack_t = 0.0
        self.zomboss_attack_index = 0
        self.zomboss_spawn_t = 0.0
        self.zomboss_spawn_index = 0
        self.zomboss_bungee_t = 0.0
        self.zomboss_stomp_t = 0.0
        self.zomboss_rv_t = 0.0
        self.zomboss_pattern_id = 0
        self.zomboss_pattern_step = 0
        self.zomboss_attack_phase = ""
        self.zomboss_exposed_t = 0.0
        self.zomboss_head_lane_row = -1
        self.zomboss_eye_mode = "idle"
        self.zomboss_pending_attack = {}
        self.zomboss_night_tint = 0.0
        self.zomboss_actor = None
        if self.mode_bool("conveyor", False):
            self.conveyor_pool = [k for k in self.mode_list("conveyor_pool") if k in self.plant_types] or list(available)
            self.conveyor_cap = max(4, int(self.mode_float("conveyor_cap", 8.0)))
            raw_weights = self.mode_rules.get("conveyor_weights", {})
            if isinstance(raw_weights, dict):
                self.conveyor_weights = {
                    str(kind): float(weight)
                    for kind, weight in raw_weights.items()
                    if str(kind) in self.plant_types and float(weight) > 0.0
                }
            self.conveyor_opening_queue = [kind for kind in self.mode_list("opening_cards") if kind in self.plant_types]
            self.cards = []
            self.initial_selected_cards = []
            self.card_timer = {}
            self.selected = self.conveyor_pool[0] if self.conveyor_pool else "sunflower"
        else:
            self.conveyor_pool = []
            self.conveyor_cap = 8
        if self.is_vasebreaker_mode():
            self.cleaners = [False for _ in range(self.rows())]
            self.total_waves = 0
            self.large_wave_indices = ()
            self.final_wave_index = 0
            self.wave_budgets = []
            self.wave_spawn_queue = []
            self.wave_spawn_total = 0
            if self.field.has_fog:
                self.fog_clear_t = 9999.0
            self.setup_vasebreaker_board()
        elif self.is_i_zombie_mode():
            self.total_waves = 0
            self.large_wave_indices = ()
            self.final_wave_index = 0
            self.wave_budgets = []
            self.wave_spawn_queue = []
            self.wave_spawn_total = 0
            self.setup_i_zombie_board()
        elif self.is_beghouled_mode() or self.is_beghouled_twist_mode():
            self.total_waves = 0
            self.large_wave_indices = ()
            self.final_wave_index = 0
            self.wave_budgets = []
            self.wave_spawn_queue = []
            self.wave_spawn_total = 0
            self.setup_beghouled_mode()
        elif self.is_whack_mode():
            self.total_waves = 0
            self.large_wave_indices = ()
            self.final_wave_index = 0
            self.wave_budgets = []
            self.wave_spawn_queue = []
            self.wave_spawn_total = 0
            self.setup_whack_mode()
        else:
            self.setup_special_minigame_mode()
        if self.mode_bool("survival_resume", False):
            state_payload = self.mode_rules.get("survival_resume_state")
            if isinstance(state_payload, dict):
                self.apply_survival_state(state_payload)
            bonus_sun = self.mode_rules.get("survival_resume_sun", None)
            if isinstance(bonus_sun, (int, float)):
                self.sun = max(self.sun, int(bonus_sun))

    def spawn_zombie(self, wave_idx: Optional[int] = None, forced_kind: Optional[str] = None) -> None:
        if not self.level:
            return
        roster_caps = self.special_roster_caps()
        active_counts = self.active_zombie_counts()
        if forced_kind and forced_kind in self.zombie_types and active_counts.get(forced_kind, 0) < roster_caps.get(forced_kind, 999):
            kind = forced_kind
        else:
            override_weights = self.mode_rules.get("zombie_weights_override")
            if isinstance(override_weights, dict):
                pairs = [
                    (str(k), float(v))
                    for k, v in override_weights.items()
                    if str(k) in self.zombie_types
                    and float(v) > 0.0
                    and active_counts.get(str(k), 0) < roster_caps.get(str(k), 999)
                ]
                if pairs:
                    kinds = [k for k, _ in pairs]
                    weights = [v for _, v in pairs]
                    kind = random.choices(kinds, weights=weights, k=1)[0]
                else:
                    fallback_pairs = [
                        (kind_name, weight)
                        for kind_name, weight in self.level.z_weights.items()
                        if active_counts.get(kind_name, 0) < roster_caps.get(kind_name, 999)
                    ]
                    if not fallback_pairs:
                        fallback_pairs = list(self.level.z_weights.items())
                    kinds = [k for k, _ in fallback_pairs]
                    kind = random.choices(kinds, weights=[v for _, v in fallback_pairs], k=1)[0]
            else:
                forced_pool = [
                    k
                    for k in self.mode_list("forced_zombie_pool")
                    if k in self.zombie_types and active_counts.get(k, 0) < roster_caps.get(k, 999)
                ]
                if forced_pool:
                    kind = random.choice(forced_pool)
                else:
                    fallback_pairs = [
                        (kind_name, weight)
                        for kind_name, weight in self.level.z_weights.items()
                        if active_counts.get(kind_name, 0) < roster_caps.get(kind_name, 999)
                    ]
                    if not fallback_pairs:
                        fallback_pairs = list(self.level.z_weights.items())
                    kinds = [k for k, _ in fallback_pairs]
                    kind = random.choices(kinds, weights=[v for _, v in fallback_pairs], k=1)[0]
        row = self.choose_spawn_row(kind)
        row_load = sum(1 for z in self.zombies if z.row == row and z.hp > 0 and float(z.state.get("dying_t", 0.0)) <= 0.0)
        spawn_x = self.lawn_right() + random.randint(26, 108) + row_load * 12
        z = self.spawn_zombie_instance(kind, row, spawn_x, wave_idx=wave_idx or max(1, self.current_wave))
        self.zombies.append(z)

    def mushroom_sleeping(self, plant: Plant) -> bool:
        cfg = self.plant_types[plant.kind]
        if self.is_zomboss_boss_mode() or self.mode_bool("night_roof_palette", False):
            return False
        return cfg.is_mushroom and not plant.awake_override and not self.field.is_night

    def z_ahead(self, row: int, x: float) -> bool:
        return any(
            z.row == row
            and z.x > x
            and not z.hypnotized
            and self.zombie_targetable(z)
            for z in self.zombies
        )

    def z_near(self, row: int, x: float, r: float) -> Optional[Zombie]:
        near = None
        best = 1e9
        for z in self.zombies:
            if z.row != row or not self.zombie_targetable(z):
                continue
            d = abs(z.x - x)
            if d <= r and d < best:
                best = d
                near = z
        return near

    def add_projectile(
        self,
        row: int,
        x: float,
        y: float,
        dmg: float,
        slow: float = 0.0,
        lobbed: bool = False,
        direction: int = 1,
        splash: float = 0.0,
        color: Tuple[int, int, int] = (41, 179, 71),
        outline: Tuple[int, int, int] = (20, 110, 38),
        enemy: bool = False,
        anti_air: bool = False,
        speed: float = 360.0,
        radius: int = 8,
        kind: str = "",
    ) -> None:
        self.projs.append(
            Projectile(
                row=row,
                x=x,
                y=y,
                damage=dmg,
                speed=speed,
                slow=slow,
                direction=direction,
                lobbed=lobbed,
                splash=splash,
                color=color,
                outline=outline,
                radius=radius,
                enemy=enemy,
                anti_air=anti_air,
                kind=kind,
            )
        )

    def boom(self, x: float, y: float, radius: float, damage: float, slow_t: float = 0.0) -> None:
        for z in self.zombies:
            if not self.zombie_targetable(z):
                continue
            if math.hypot(z.x - x, self.row_y(z.row) - y) <= radius:
                self.damage_zombie(z, damage, source="boom")
                z.state["hit_flash"] = 0.14
                if slow_t > 0:
                    z.slow_t = max(z.slow_t, slow_t)

    def can_place(self, kind: str, row: int, col: int) -> bool:
        if not (0 <= row < self.rows() and 0 <= col < COLS):
            return False
        pos = (row, col)
        cfg = self.plant_types[kind]
        water = self.is_water(row)
        if pos in self.graves and kind != "grave_buster":
            return False
        if kind == "grave_buster":
            return pos in self.graves
        if kind == "coffee_bean":
            base = self.main.get(pos)
            return base is not None and self.mushroom_sleeping(base)
        if cfg.is_overlay:
            return (pos in self.main or pos in self.support) and pos not in self.armor
        if cfg.is_support:
            if pos in self.support:
                return False
            if kind == "lily_pad" and not water:
                return False
            if kind == "flower_pot" and not self.field.is_roof:
                return False
            return True
        if pos in self.main:
            return False
        if cfg.aquatic_only and not water:
            return False
        if water and not cfg.aquatic_only and self.support.get(pos) is None:
            return False
        if self.field.is_roof and kind != "flower_pot" and self.support.get(pos) is None:
            return False
        return True

    def place(self, kind: str, row: int, col: int) -> bool:
        if kind == "imitater" and not self.imitater_target:
            return False
        place_kind = self.resolve_card_kind(kind)
        if place_kind not in self.plant_types:
            return False
        vasebreaker_mode = self.is_vasebreaker_mode()
        if vasebreaker_mode and kind not in self.cards:
            return False
        cfg = self.plant_types[place_kind]
        if not self.can_place(place_kind, row, col):
            return False
        conveyor_mode = self.mode_bool("conveyor", False)
        free_planting = self.mode_bool("no_sun_cost", False) or self.mode_bool("infinite_sun", False) or conveyor_mode or vasebreaker_mode
        if conveyor_mode and kind not in self.cards:
            return False
        runtime_cost = self.card_runtime_cost(kind)
        if not free_planting and self.sun < runtime_cost:
            return False
        if (not conveyor_mode) and (not vasebreaker_mode) and self.card_timer.get(kind, 0.0) > 0:
            return False
        if not free_planting:
            self.sun -= runtime_cost
        if (kind in self.card_timer) and (not vasebreaker_mode):
            cd_mul = self.mode_float("cooldown_scale", 1.0)
            if self.last_stand_in_prep():
                self.card_timer[kind] = 0.0
            else:
                self.card_timer[kind] = 0.0 if self.mode_bool("no_cooldown", False) else max(0.1, self.card_runtime_cooldown(kind) * cd_mul)
        pos = (row, col)
        if place_kind == "coffee_bean":
            self.main[pos].awake_override = True
            if conveyor_mode and kind in self.cards:
                self.cards.remove(kind)
                if self.selected == kind:
                    self.selected = self.cards[0] if self.cards else (self.conveyor_pool[0] if self.conveyor_pool else kind)
            return True
        if place_kind == "grave_buster":
            gb = Plant(kind=place_kind, row=row, col=col, hp=float(cfg.hp), cd=2.0, slot="main")
            gb.state["hp_max"] = float(gb.hp)
            self.main[pos] = gb
            self.ensure_plant_anim_state(self.main[pos])
            if conveyor_mode and kind in self.cards:
                self.cards.remove(kind)
                if self.selected == kind:
                    self.selected = self.cards[0] if self.cards else (self.conveyor_pool[0] if self.conveyor_pool else kind)
            return True
        if self.is_wallnut_bowling_mode() and place_kind in ("wallnut", "cherrybomb") and self.spawn_rolling_nut(place_kind, row, col):
            if conveyor_mode and kind in self.cards:
                self.cards.remove(kind)
                if self.selected == kind:
                    self.selected = self.cards[0] if self.cards else (self.conveyor_pool[0] if self.conveyor_pool else kind)
            return True
        slot = "armor" if cfg.is_overlay else ("support" if cfg.is_support else "main")
        plant_hp = float(cfg.hp) * self.plant_hp_scale()
        p = Plant(kind=place_kind, row=row, col=col, hp=plant_hp, slot=slot, cd=random.uniform(0.2, 0.8))
        p.state["hp_max"] = float(p.hp)
        self.ensure_plant_anim_state(p)
        if place_kind == "potato_mine":
            p.cd = 0.0
            p.state["arm_t"] = 10.0
            p.state["armed"] = 0.0
            p.state["potato_state"] = "arming"
        if place_kind in ("cherrybomb", "jalapeno", "doom_shroom", "ice_shroom", "blover"):
            p.cd = 0.8
        if place_kind == "sunflower":
            p.cd = random.uniform(4.5, 7.0)
        if place_kind == "sun_shroom":
            p.cd = random.uniform(4.0, 6.0)
        if place_kind == "marigold":
            p.cd = random.uniform(9.0, 12.0)
        if kind == "imitater":
            p.state["from_imitater"] = 1.0
            p.state["imitater_target"] = place_kind
            p.state["imitater_morph_t"] = 3.2
            p.state["imitater_morph_total"] = 3.2
            p.state["imitater_state"] = "morphing"
            p.hp = min(p.hp, 75.0)
        if slot == "main":
            self.main[pos] = p
        elif slot == "support":
            self.support[pos] = p
        else:
            self.armor[pos] = p
        if self.is_column_like_mode():
            clone_forbidden = {
                "cherrybomb",
                "jalapeno",
                "doom_shroom",
                "ice_shroom",
                "grave_buster",
                "coffee_bean",
                "cob_cannon",
                "imitater",
            }
            if (slot == "main") and (place_kind not in clone_forbidden):
                for rr in range(self.rows()):
                    if rr == row:
                        continue
                    if self.can_place(place_kind, rr, col):
                        self.spawn_plant_direct(place_kind, rr, col, force_place=False)
        consume_card = conveyor_mode or vasebreaker_mode
        if consume_card and kind in self.cards:
            self.cards.remove(kind)
            if self.selected == kind:
                self.selected = self.cards[0] if self.cards else (self.conveyor_pool[0] if self.conveyor_pool else kind)
        return True

    def shovel(self, row: int, col: int) -> None:
        pos = (row, col)
        if pos in self.armor:
            del self.armor[pos]
            return
        if pos in self.main:
            del self.main[pos]
            return
        if pos in self.support:
            del self.support[pos]

    def update(self, dt: float) -> None:
        if not self.level or self.result or self.paused or self.almanac_open:
            return
        if self.last_stand_in_prep():
            for k in list(self.card_timer.keys()):
                self.card_timer[k] = 0.0
            self.spawn_t = 0.0
            self.wave_pause_t = 0.0
            self.next_wave = 1.0
            return
        self.elapsed += dt
        self.spawn_t += dt
        self.sky_t += dt
        self.conveyor_t += dt
        self.grave_t += dt
        self.wave_warning_t = max(0.0, self.wave_warning_t - dt)
        self.fog_clear_t = max(0.0, self.fog_clear_t - dt)
        for k in list(self.card_timer.keys()):
            self.card_timer[k] = max(0.0, self.card_timer[k] - dt)
        if self.mode_bool("no_cooldown", False):
            for k in self.card_timer.keys():
                self.card_timer[k] = 0.0
        if self.mode_bool("infinite_sun", False):
            self.sun = max(self.sun, 9990)
        self.wave_pause_t = max(0.0, self.wave_pause_t - dt)
        if self.uses_wave_system():
            active_zombies = [z for z in self.zombies if z.hp > 0 and z.state.get("dying_t", 0.0) <= 0.0]
            if self.current_wave == 0 and self.wave_pause_t <= 0.0 and int(self.next_wave) == 1:
                self.start_next_wave()
            if self.is_adventure_mainline():
                wave_prog = 0.0 if self.total_waves <= 1 else max(0.0, (self.current_wave - 1) / max(1, self.total_waves - 1))
                spawn_cd = max(self.level.spawn_min, self.level.spawn_base - wave_prog * (self.level.spawn_acc * 42.0))
            else:
                spawn_cd = max(self.level.spawn_min, self.level.spawn_base - self.elapsed * self.level.spawn_acc)
            spawn_cd /= max(0.25, self.mode_float("spawn_rate_mult", 1.0))
            if self.is_special_hud_mode():
                spawn_cd *= self.special_spawn_gap_scale()
            rhythm_cycle = self.mode_float("rhythm_cycle", 24.0)
            if rhythm_cycle > 0:
                phase = (self.elapsed % rhythm_cycle) / rhythm_cycle
                if phase < 0.22:
                    spawn_cd *= 1.06 if self.is_adventure_mainline() else 1.10
                elif phase > 0.82:
                    spawn_cd *= 0.94 if self.is_adventure_mainline() else 0.84
            if self.is_adventure_mainline():
                while self.wave_spawn_queue and self.spawn_t >= spawn_cd:
                    self.spawn_t -= spawn_cd
                    next_kind = self.wave_spawn_queue.pop(0)
                    self.spawn_zombie(self.current_wave, forced_kind=next_kind)
                    self.wave_spawn_remaining = len(self.wave_spawn_queue)
            else:
                special_cap = self.special_active_cap() if self.is_special_hud_mode() else 0
                while self.wave_spawn_remaining > 0 and self.spawn_t >= spawn_cd:
                    if special_cap > 0:
                        active_special = sum(
                            1
                            for z in self.zombies
                            if z.hp > 0 and float(z.state.get("dying_t", 0.0)) <= 0.0 and not z.hypnotized
                        )
                        if active_special >= special_cap:
                            break
                    self.spawn_t -= spawn_cd
                    self.spawn_zombie(self.current_wave)
                    self.wave_spawn_remaining -= 1
            lane_pressure_limit = self.adventure_lane_pressure_limit() if self.is_adventure_mainline() else max(2, self.level.danger)
            if self.wave_spawn_remaining <= 0 and self.current_wave > 0:
                if self.current_wave < self.total_waves:
                    if len(active_zombies) <= lane_pressure_limit:
                        if int(self.next_wave) != self.current_wave + 1:
                            self.next_wave = float(self.current_wave + 1)
                            if self.is_adventure_mainline():
                                self.wave_pause_t = 4.2 if (self.current_wave + 1) in self.large_wave_indices else 2.6
                            else:
                                self.wave_pause_t = 3.2 if (self.current_wave + 1) in self.large_wave_indices else 1.9
                        elif self.wave_pause_t <= 0.0:
                            self.start_next_wave()
                    else:
                        self.next_wave = 0.0
                        self.wave_pause_t = 0.0
                elif not active_zombies and not self.rolling_nuts:
                    self.result = "win"
        if self.mode_bool("conveyor", False):
            self.update_conveyor()
        sun_interval = 7.2 * self.mode_float("sky_sun_interval_scale", 1.0)
        if self.field.sky_sun and not self.mode_bool("no_sky_sun", False) and self.sky_t >= sun_interval:
            self.sky_t = 0.0
            self.tokens.append(Token(random.randint(LAWN_X + 36, self.lawn_right() - 36), random.randint(LAWN_Y + 36, self.lawn_bottom() - 36), 25, 9.0, "sun"))
        if self.field.is_night and self.uses_wave_system() and self.grave_t >= 18.0:
            self.grave_t = 0.0
            for _ in range(8):
                row = random.randrange(self.rows())
                col = random.randint(2, COLS - 2)
                pos = (row, col)
                if pos not in self.main and pos not in self.support and pos not in self.graves:
                    self.graves[pos] = 300.0
                    break
        self.update_plants(dt)
        self.update_projectiles(dt)
        self.update_rolling_nuts(dt)
        self.update_zombies(dt)
        for fx in list(self.vase_reveals):
            fx["t"] = float(fx.get("t", 0.0)) - dt
            if float(fx.get("t", 0.0)) <= 0.0:
                self.vase_reveals.remove(fx)
        for spark in list(self.hit_sparks):
            spark["t"] = float(spark.get("t", 0.0)) - dt
            if float(spark.get("t", 0.0)) <= 0.0:
                self.hit_sparks.remove(spark)
        for t in list(self.tokens):
            t.update(dt)
            if t.kind == "sun" and self.mode_bool("auto_collect_sun", False):
                self.sun += t.value
                self.tokens.remove(t)
                continue
            if t.kind == "coin" and self.mode_bool("auto_collect_coins", False):
                self.save_data["coins"] = int(self.save_data.get("coins", 0)) + t.value
                self.tokens.remove(t)
                continue
            if t.life <= 0:
                self.tokens.remove(t)
        self.update_special_mode_logic(dt)
        if self.is_vasebreaker_mode() and not self.vases and (not any(z.hp > 0 or z.state.get("dying_t", 0.0) > 0.0 for z in self.zombies)):
            endless_mode = bool(self.mode_bool("vasebreaker_endless", False)) or self.mode_name() == "puzzle_vasebreaker_endless"
            if endless_mode:
                # Endless: roll into next board instead of ending immediately.
                round_now = int(self.mode_float("vasebreaker_round", 1.0))
                tier_now = int(self.mode_float("vasebreaker_tier", 0.0))
                next_round = max(1, round_now + 1)
                self.mode_rules["vasebreaker_round"] = float(next_round)
                self.mode_rules["vasebreaker_tier"] = float(max(tier_now + 1, next_round - 1))
                self.setup_vasebreaker_board()
            else:
                self.result = "win"
        if self.is_i_zombie_mode():
            if not self.brains:
                self.result = "win"
            elif (not any(z.hp > 0 and z.state.get("dying_t", 0.0) <= 0.0 for z in self.zombies)) and (not self.can_play_any_i_zombie_card()):
                self.result = "lose"
        target_duration = self.target_duration if self.target_duration > 0 else self.level.duration
        if (
            (not self.uses_wave_system())
            and (not self.is_vasebreaker_mode())
            and (not self.is_i_zombie_mode())
            and (not self.is_beghouled_mode())
            and (not self.is_beghouled_twist_mode())
            and (not self.is_zombiquarium_mode())
            and (not self.is_whack_mode())
            and self.elapsed >= target_duration
            and not self.zombies
        ):
            self.result = "win"

    def update_conveyor(self) -> None:
        if not self.conveyor_pool:
            return
        interval = max(0.7, self.mode_float("conveyor_interval", 1.9))
        while self.conveyor_t >= interval:
            self.conveyor_t -= interval
            if len(self.cards) >= self.conveyor_cap:
                continue
            if self.conveyor_opening_queue:
                choice = self.conveyor_opening_queue.pop(0)
            elif self.conveyor_weights:
                weighted_pool = [(kind, weight) for kind, weight in self.conveyor_weights.items() if kind in self.conveyor_pool and weight > 0.0]
                if weighted_pool:
                    choice = random.choices([kind for kind, _ in weighted_pool], weights=[weight for _, weight in weighted_pool], k=1)[0]
                else:
                    choice = random.choice(self.conveyor_pool)
            else:
                choice = random.choice(self.conveyor_pool)
            self.cards.append(choice)
            if self.selected not in self.cards:
                self.selected = self.cards[0]

    def update_plants(self, dt: float) -> None:
        plant_dmg_scale = self.plant_damage_scale()
        for plant in list(self.main.values()) + list(self.support.values()) + list(self.armor.values()):
            cfg = self.plant_types[plant.kind]
            self.ensure_plant_anim_state(plant)
            self.update_plant_visual_state(plant)
            prev_hp = plant.state.get("last_hp", plant.hp)
            if plant.hp < prev_hp - 0.01:
                plant.state["hit_flash"] = 0.14
                self.bump_anim_event(plant, "hit")
            plant.state["last_hp"] = plant.hp
            self.advance_entity_animation(plant, dt, "plant")
            plant.state["recoil_t"] = max(0.0, plant.state.get("recoil_t", 0.0) - dt)
            plant.state["hit_flash"] = max(0.0, plant.state.get("hit_flash", 0.0) - dt)
            plant.state["ladder_flash_t"] = max(0.0, float(plant.state.get("ladder_flash_t", 0.0)) - dt)
            if plant.slot == "armor":
                continue
            if plant.hp <= 0:
                self.main.pop((plant.row, plant.col), None)
                self.support.pop((plant.row, plant.col), None)
                continue
            morph_t = float(plant.state.get("imitater_morph_t", 0.0))
            if morph_t > 0.0:
                morph_t = max(0.0, morph_t - dt)
                plant.state["imitater_morph_t"] = morph_t
                plant.state["imitater_state"] = "morphing"
                plant.state["recoil_t"] = max(plant.state.get("recoil_t", 0.0), 0.09)
                if morph_t <= 0.0:
                    plant.state["imitater_state"] = "copied"
                    plant.state["imitater_flash_t"] = 0.28
                    plant.hp = max(plant.hp, float(cfg.hp) * self.plant_hp_scale())
                continue
            plant.state["imitater_flash_t"] = max(0.0, float(plant.state.get("imitater_flash_t", 0.0)) - dt)
            if self.mushroom_sleeping(plant):
                continue
            plant.cd -= dt
            if self.mode_bool("no_cooldown", False):
                plant.cd = 0.0
            cx, cy = self.cell_center(plant.row, plant.col)
            b = cfg.behavior
            dmg = cfg.damage * plant_dmg_scale
            if self.is_i_zombie_mode() and b in ("sun", "sun_shroom"):
                # I, Zombie uses bite-based sunlight economy, no passive plant production.
                continue
            if b in ("block", "garlic", "support", "armor", "noop", "imitate"):
                continue
            if b == "sun" and plant.cd <= 0:
                self.tokens.append(Token(cx + random.randint(-12, 12), cy - 16, cfg.sun_amount, 9.0, "sun"))
                plant.cd = random.uniform(max(1.0, cfg.interval - 1.0), cfg.interval + 1.0)
                self.bump_anim_event(plant, "sun")
            elif b == "sun_shroom" and plant.cd <= 0:
                amt = 25 if self.elapsed > 90 else 15
                self.tokens.append(Token(cx + random.randint(-12, 12), cy - 16, amt, 9.0, "sun"))
                plant.cd = random.uniform(8.0, 11.0)
            elif b in ("shoot", "shoot_slow", "shoot_balloon") and plant.cd <= 0 and self.z_ahead(plant.row, cx):
                for i in range(cfg.proj_count):
                    oy = (i - (cfg.proj_count - 1) / 2.0) * 8
                    slow = 2.5 if b == "shoot_slow" else 0.0
                    col = (120, 216, 246) if b == "shoot_slow" else ((110, 210, 245) if b == "shoot_balloon" else (41, 179, 71))
                    out = (56, 122, 150) if b == "shoot_slow" else ((30, 110, 140) if b == "shoot_balloon" else (20, 110, 38))
                    self.add_projectile(plant.row, cx + 22, cy + oy, dmg, slow=slow, color=col, outline=out, anti_air=(b == "shoot_balloon"))
                plant.cd = self.scaled_plant_interval(cfg.interval)
                plant.state["recoil_t"] = 0.15
                if plant.kind == "peashooter":
                    self.bump_anim_event(plant, "shoot")
            elif b == "shoot_short" and plant.cd <= 0:
                z = self.z_near(plant.row, cx + CELL_W * 1.5, CELL_W * 3.2)
                if z:
                    self.add_projectile(plant.row, cx + 16, cy, dmg, color=(180, 118, 215), outline=(86, 43, 120))
                    plant.cd = self.scaled_plant_interval(cfg.interval)
                    plant.state["recoil_t"] = 0.14
            elif b == "split" and plant.cd <= 0:
                front = self.z_ahead(plant.row, cx)
                back = any(z.row == plant.row and z.x < cx for z in self.zombies)
                if front:
                    self.add_projectile(plant.row, cx + 20, cy - 3, dmg)
                if back:
                    self.add_projectile(plant.row, cx - 20, cy + 3, dmg, direction=-1)
                if front or back:
                    plant.cd = self.scaled_plant_interval(cfg.interval)
                    plant.state["recoil_t"] = 0.14
            elif b == "star" and plant.cd <= 0 and self.zombies:
                self.add_projectile(plant.row, cx + 16, cy, dmg, color=(245, 213, 81), outline=(160, 120, 20))
                if plant.row > 0:
                    self.add_projectile(plant.row - 1, cx + 14, self.row_y(plant.row - 1), dmg, color=(245, 213, 81), outline=(160, 120, 20))
                if plant.row < self.rows() - 1:
                    self.add_projectile(plant.row + 1, cx + 14, self.row_y(plant.row + 1), dmg, color=(245, 213, 81), outline=(160, 120, 20))
                plant.cd = self.scaled_plant_interval(cfg.interval)
                plant.state["recoil_t"] = 0.12
            elif b == "threepeat" and plant.cd <= 0:
                fired = False
                for rr in (plant.row - 1, plant.row, plant.row + 1):
                    if 0 <= rr < self.rows() and self.z_ahead(rr, cx):
                        self.add_projectile(rr, cx + 18, self.row_y(rr), dmg)
                        fired = True
                if fired:
                    plant.cd = self.scaled_plant_interval(cfg.interval)
                    plant.state["recoil_t"] = 0.17
            elif b == "bomb" and plant.cd <= 0:
                self.boom(cx, cy, 150, 9999)
                plant.hp = 0
            elif b == "potato":
                if "arm_t" not in plant.state:
                    plant.state["arm_t"] = max(0.0, plant.cd if plant.cd > 0 else 10.0)
                if plant.state.get("armed", 0.0) <= 0:
                    plant.state["arm_t"] = max(0.0, plant.state.get("arm_t", 0.0) - dt)
                    if plant.state["arm_t"] <= 0:
                        plant.state["armed"] = 1.0
                        plant.state["potato_state"] = "armed"
                        plant.state["recoil_t"] = max(plant.state.get("recoil_t", 0.0), 0.10)
                    elif plant.state["arm_t"] <= 4.0:
                        plant.state["potato_state"] = "priming"
                elif self.z_near(plant.row, cx, 44):
                    self.boom(cx, cy + 8, 95, 9999)
                    self.bump_anim_event(plant, "detonate")
                    plant.hp = 0
            elif b == "chomp" and plant.cd <= 0:
                z = self.z_near(plant.row, cx, 52)
                if z:
                    self.slay_zombie(z, source="chomp")
                    plant.cd = 9.5
                    plant.state["recoil_t"] = 0.28
            elif b == "fume" and plant.cd <= 0:
                used = False
                for z in self.zombies:
                    if z.row == plant.row and 0 <= z.x - cx <= CELL_W * 4.3:
                        self.damage_zombie(z, dmg, source="fume")
                        used = True
                if used:
                    plant.cd = self.scaled_plant_interval(cfg.interval)
                    plant.state["recoil_t"] = 0.16
            elif b == "scaredy" and plant.cd <= 0:
                if not self.z_near(plant.row, cx, CELL_W * 2.0):
                    z = self.z_near(plant.row, cx + CELL_W * 1.6, CELL_W * 4.0)
                    if z:
                        self.add_projectile(plant.row, cx + 16, cy, dmg, color=(180, 118, 215), outline=(86, 43, 120))
                        plant.cd = self.scaled_plant_interval(cfg.interval)
                        plant.state["recoil_t"] = 0.12
            elif b == "ice" and plant.cd <= 0:
                if self.is_zomboss_boss_mode():
                    self.cancel_zomboss_pending_attack("ice_shroom")
                for z in self.zombies:
                    z.stunned_t = max(z.stunned_t, 2.5)
                    z.slow_t = max(z.slow_t, 4.5)
                plant.hp = 0
            elif b == "doom" and plant.cd <= 0:
                self.boom(cx, cy, 250, 9999)
                plant.hp = 0
            elif b == "squash" and plant.cd <= 0:
                z = self.z_near(plant.row, cx, CELL_W * 1.5)
                if z:
                    self.slay_zombie(z, source="squash")
                    plant.hp = 0
            elif b == "kelp" and self.z_near(plant.row, cx, 54):
                z = self.z_near(plant.row, cx, 54)
                if z:
                    self.slay_zombie(z, source="kelp")
                    plant.hp = 0
            elif b == "row_blast" and plant.cd <= 0:
                if self.is_zomboss_boss_mode() and plant.kind == "jalapeno":
                    self.cancel_zomboss_pending_attack("jalapeno")
                    self.ice_rows.clear()
                for z in self.zombies:
                    if z.row == plant.row:
                        self.slay_zombie(z, source="row_blast")
                plant.hp = 0
            elif b == "spike":
                for z in self.zombies:
                    if z.row == plant.row and abs(z.x - cx) <= 28 and not z.hypnotized:
                        self.damage_zombie(z, dmg * dt * 2.2, source="spike")
            elif b == "blover" and plant.cd <= 0:
                self.fog_clear_t = 8.0
                for z in self.zombies:
                    if z.kind == "balloon":
                        self.slay_zombie(z, source="blover")
                plant.hp = 0
            elif b == "magnet" and plant.cd <= 0:
                for z in self.zombies:
                    if z.kind in ("conehead", "buckethead", "screen_door", "football", "ladder", "catapult") and abs(z.x - cx) <= CELL_W * 4:
                        self.damage_zombie(z, 140, source="magnet")
                        plant.cd = 8.0
                        break
            elif b == "pult" and plant.cd <= 0 and self.z_ahead(plant.row, cx):
                slow = 0.0
                splash = 0.0
                if plant.kind in ("winter_melon",):
                    slow = 2.6
                if plant.kind in ("melon_pult", "winter_melon"):
                    splash = 85.0
                self.add_projectile(plant.row, cx + 16, cy - 8, dmg, slow=slow, lobbed=True, splash=splash, color=(119, 196, 92), outline=(36, 90, 40))
                plant.cd = self.scaled_plant_interval(cfg.interval)
                plant.state["recoil_t"] = 0.22
            elif b == "grave_buster" and plant.cd <= 0:
                self.graves.pop((plant.row, plant.col), None)
                plant.hp = 0
            elif b == "marigold" and plant.cd <= 0:
                self.tokens.append(Token(cx + random.randint(-10, 10), cy, random.choice([20, 25]), 10.0, "coin"))
                plant.cd = random.uniform(9.0, 13.0)
            elif b == "gloom" and plant.cd <= 0:
                self.boom(cx, cy, 105, dmg)
                plant.cd = 1.7
            elif b == "cattail" and plant.cd <= 0 and self.zombies:
                target = min(self.zombies, key=lambda z: abs(z.x - cx))
                self.add_projectile(target.row, cx + 18, cy - 4, dmg, slow=0.4, color=(250, 210, 116), outline=(120, 80, 20), anti_air=True)
                plant.cd = self.scaled_plant_interval(cfg.interval)
                plant.state["recoil_t"] = 0.13
            elif b == "gold_magnet" and plant.cd <= 0:
                pulled = []
                for t in self.tokens:
                    if t.kind == "coin" and math.hypot(t.x - cx, t.y - cy) <= CELL_W * 2.5:
                        pulled.append(t)
                for t in pulled:
                    self.tokens.remove(t)
                    self.save_data["coins"] = int(self.save_data.get("coins", 0)) + t.value
                if pulled:
                    plant.cd = 2.5
            elif b == "cob" and plant.cd <= 0 and self.zombies:
                target = max(self.zombies, key=lambda z: z.x)
                self.boom(target.x, self.row_y(target.row), 130, 1200 * plant_dmg_scale)
                plant.cd = 35.0
                plant.state["recoil_t"] = 0.34

    def update_projectiles(self, dt: float) -> None:
        for p in list(self.projs):
            p.update(dt)
            if self.is_portal_combat_mode():
                p.row, p.x, p.teleport_cd = self.apply_portal_transfer(p.row, p.x, p.direction, p.teleport_cd)
            if self.is_zomboss_boss_mode() and p.direction > 0 and p.lobbed and p.x >= self.lawn_right() + 18:
                self.damage_zomboss(p.damage * 4.0)
                self.projs.remove(p)
                continue
            if p.kind == "zomboss_iceball" and p.x < LAWN_X - 26:
                self.ice_rows[p.row] = max(float(self.ice_rows.get(p.row, 0.0)), 9999.0)
                self.projs.remove(p)
                continue
            if p.x < LAWN_X - 60 or p.x > SCREEN_WIDTH + 40:
                self.projs.remove(p)
                continue
            if self.field.is_roof and not p.lobbed and p.direction > 0 and p.x > LAWN_X + CELL_W * 5:
                self.projs.remove(p)
                continue
            if p.enemy:
                col = int(clamp((p.x - LAWN_X) // CELL_W, 0, COLS - 1))
                hit_plant: Optional[Plant] = None
                hit_pos: Optional[Tuple[int, int]] = None
                for cc in (col, col - 1, col + 1):
                    if not (0 <= cc < COLS):
                        continue
                    pos = (p.row, cc)
                    target = self.armor.get(pos)
                    if target is None:
                        main_target = self.main.get(pos)
                        if self.is_plant_edible(main_target):
                            target = main_target
                    if target is None:
                        support_target = self.support.get(pos)
                        if self.is_plant_edible(support_target):
                            target = support_target
                    if target is None:
                        continue
                    cx, _ = self.cell_center(p.row, cc)
                    if abs(cx - p.x) <= max(28, p.radius + 12):
                        hit_plant = target
                        hit_pos = pos
                        break
                if hit_plant is not None and hit_pos is not None:
                    hit_plant.hp -= p.damage
                    hit_plant.state["hit_flash"] = 0.16
                    self.hit_sparks.append({"x": float(p.x), "y": float(self.row_y(p.row) - 10), "t": 0.16, "ttl": 0.16})
                    if p.kind == "zomboss_iceball":
                        self.ice_rows[p.row] = max(float(self.ice_rows.get(p.row, 0.0)), 9999.0)
                    destroyed = hit_plant.hp <= 0
                    if destroyed:
                        self.armor.pop(hit_pos, None)
                        self.main.pop(hit_pos, None)
                        self.support.pop(hit_pos, None)
                    if p.kind in {"zomboss_fireball", "zomboss_iceball"} and destroyed:
                        continue
                    self.projs.remove(p)
                continue
            hit = None
            for z in self.zombies:
                if z.row == p.row and self.zombie_targetable(z) and abs(z.x - p.x) < 24:
                    if z.kind == "balloon" and not p.anti_air:
                        continue
                    hit = z
                    break
            if hit:
                hit_source = "anti_air_projectile" if p.anti_air else "projectile"
                self.damage_zombie(hit, p.damage, source=hit_source)
                hit.state["hit_flash"] = 0.18
                self.hit_sparks.append({"x": float(hit.x), "y": float(self.row_y(hit.row) - 8), "t": 0.18, "ttl": 0.18})
                if p.slow > 0:
                    hit.slow_t = max(hit.slow_t, p.slow)
                if p.splash > 0:
                    for z in self.zombies:
                        if z is not hit and z.row == hit.row and abs(z.x - hit.x) <= p.splash:
                            self.damage_zombie(z, p.damage * 0.45, source="splash")
                            z.state["hit_flash"] = 0.14
                self.projs.remove(p)

    def update_rolling_nuts(self, dt: float) -> None:
        if not self.rolling_nuts:
            return
        for nut in list(self.rolling_nuts):
            nut.ttl -= dt
            nut.spin = (nut.spin + dt * (nut.speed / 26.0)) % math.tau
            nut.x += nut.speed * dt
            if nut.ttl <= 0 or nut.x > self.lawn_right() + 70:
                self.rolling_nuts.remove(nut)
                continue

            hit_target: Optional[Zombie] = None
            best_x = 10**9
            for z in self.zombies:
                if z.row != nut.row or z.hp <= 0 or not self.zombie_targetable(z):
                    continue
                if abs(z.x - nut.x) <= nut.radius + 18 and z.x < best_x:
                    best_x = z.x
                    hit_target = z
            if hit_target is None:
                continue

            self.damage_zombie(hit_target, nut.damage, source="rolling_nut")
            hit_target.state["hit_flash"] = 0.16
            hit_target.state["bite_t"] = max(hit_target.state.get("bite_t", 0.0), 0.08)
            hit_target.stunned_t = max(hit_target.stunned_t, 0.14)
            if not hit_target.hypnotized:
                hit_target.x += 18
            else:
                hit_target.x -= 18

            if nut.splash > 0:
                self.boom(nut.x, self.row_y(nut.row), nut.splash, nut.damage * 1.15)
                nut.pierce = 0
            else:
                nut.pierce -= 1

            if nut.kind == "wallnut" and random.random() < 0.32:
                lane_shift = random.choice([-1, 1])
                next_row = int(clamp(float(nut.row + lane_shift), 0.0, float(self.rows() - 1)))
                if next_row != nut.row:
                    nut.row = next_row

            nut.x = max(nut.x, hit_target.x + nut.radius + 10)
            if nut.pierce <= 0:
                self.rolling_nuts.remove(nut)

    def update_zombies(self, dt: float) -> None:
        for z in list(self.zombies):
            self.ensure_zombie_anim_state(z)
            z.state["walk_t"] = z.state.get("walk_t", 0.0) + dt * max(0.6, z.speed / 30.0)
            z.state["bite_t"] = max(0.0, z.state.get("bite_t", 0.0) - dt)
            z.state["hit_flash"] = max(0.0, z.state.get("hit_flash", 0.0) - dt)
            z.state["invisi_reveal_t"] = max(0.0, float(z.state.get("invisi_reveal_t", 0.0)) - dt)
            prev_hp = z.state.get("last_hp", z.hp)
            if z.hp < prev_hp - 0.01:
                z.state["hit_flash"] = 0.13
                self.bump_anim_event(z, "hit")
                if self.is_invisi_ghoul_mode():
                    z.state["invisi_reveal_t"] = max(float(z.state.get("invisi_reveal_t", 0.0)), 0.52)
            z.state["last_hp"] = z.hp
            self.advance_entity_animation(z, dt, "zombie")
            if z.kind in {"conehead", "buckethead"}:
                break_ratio = 0.58 if z.kind == "conehead" else 0.62
                if z.hp_max > 0 and (z.hp / z.hp_max) <= break_ratio and float(z.state.get("helmet_broken", 0.0)) <= 0.0:
                    z.state["helmet_broken"] = 1.0
                    self.bump_anim_event(z, "helmet_break")
            if z.kind == "newspaper":
                self.ensure_newspaper_state(z)
                self.update_newspaper_state(z, dt)

            dying_t = z.state.get("dying_t", 0.0)
            if dying_t > 0:
                dying_t -= dt
                if dying_t <= 0:
                    self.zombies.remove(z)
                else:
                    z.state["dying_t"] = dying_t
                continue
            if z.state.get("whack_popup", 0.0) > 0.0 and z.hp > 0:
                continue
            if z.hp <= 0:
                z.state["dying_t"] = 0.34
                self.kills += 1
                if random.random() < 0.45:
                    self.tokens.append(Token(z.x, self.row_y(z.row), random.choice([10, 15, 20]), 10.0, "coin"))
                continue
            if z.slow_t > 0:
                z.slow_t -= dt
            if z.stunned_t > 0:
                z.stunned_t -= dt
                continue
            if z.kind == "newspaper" and z.state.get("paper_state", "paper_intact") == "paper_lost_transition":
                if z.state.get("rage_stun_t", 0.0) > 0.0:
                    z.state["bite_t"] = 0.0
                    continue
            if self.is_zombotany_mode():
                self.update_zombotany_zombie(z, dt)
            if z.kind == "dancing" and z.state.get("spawn_t", 0.0) <= 0:
                z.state["spawn_t"] = 9.0
                for rr in (z.row - 1, z.row, z.row + 1):
                    if 0 <= rr < self.rows():
                        b = self.zombie_types["backup_dancer"]
                        nz = Zombie("backup_dancer", rr, z.x + random.randint(10, 24), float(b.hp), float(b.hp), random.uniform(*b.speed), random.uniform(*b.dps))
                        self.ensure_zombie_anim_state(nz)
                        self.zombies.append(nz)
            else:
                z.state["spawn_t"] = z.state.get("spawn_t", 0.0) - dt
            if z.kind == "jack_in_the_box" and random.random() < 0.0012:
                self.boom(z.x, self.row_y(z.row), 135, 9999)
                self.slay_zombie(z, source="jack_in_the_box")
                continue
            if self.update_special_zombie_state(z, dt):
                continue
            col = int(clamp((z.x - LAWN_X) // CELL_W, 0, COLS - 1))
            pos = (z.row, col)
            target = self.armor.get(pos)
            main_target = self.main.get(pos)
            if target is None:
                if self.is_plant_edible(main_target):
                    target = main_target
            if target is None and main_target is None:
                support_target = self.support.get(pos)
                if self.is_plant_edible(support_target):
                    target = support_target
            if target and self.zombie_should_ignore_target(z, target):
                target = None
            if main_target and self.zombie_should_ignore_target(z, main_target):
                main_target = None
            if z.kind == "zomboni" and target is not None:
                if target.kind in ("spikeweed", "spikerock"):
                    self.damage_zombie(z, 220 if target.kind == "spikeweed" else 420, source="spike_crush")
                target.hp -= 9999
                target.state["hit_flash"] = 0.18
                z.state["zomboni_state"] = "crush"
                z.state["zomboni_crush_t"] = 0.42
                z.state["zomboni_crush_total"] = 0.42
                if target.hp <= 0:
                    self.armor.pop(pos, None)
                    self.main.pop(pos, None)
                    self.support.pop(pos, None)
                target = None
            if z.kind == "ladder" and self.ladder_state(z) == "carrying":
                ladder_target = self.ladderable_plant_at(pos)
                if ladder_target and float(ladder_target.state.get("laddered", 0.0)) <= 0.0:
                    z.state["ladder_state"] = "placing"
                    z.state["ladder_phase_t"] = 0.66
                    z.state["ladder_phase_total"] = 0.66
                    z.state["bite_t"] = 0.0
                    continue
            if z.kind == "pole_vaulting":
                pole_state = str(z.state.get("pole_vault_state", "run"))
                if pole_state == "vault":
                    vault_t = max(0.0, float(z.state.get("pole_vault_t", 0.0)) - dt)
                    z.state["pole_vault_t"] = vault_t
                    total = max(0.01, float(z.state.get("pole_vault_total", 0.38)))
                    progress = 1.0 - clamp(vault_t / total, 0.0, 1.0)
                    end_x = float(z.state.get("pole_vault_end_x", z.x - CELL_W * 0.92))
                    start_x = float(z.state.get("pole_vault_start_x", z.x))
                    z.x = start_x + (end_x - start_x) * progress
                    if vault_t <= 0.0:
                        z.state["pole_vault_state"] = "post_vault_walk"
                    continue
                if pole_state == "run" and target is not None:
                    z.state["pole_vault_state"] = "vault"
                    z.state["pole_vault_t"] = 0.38
                    z.state["pole_vault_total"] = 0.38
                    z.state["pole_vault_start_x"] = z.x
                    z.state["pole_vault_end_x"] = max(LAWN_X - 8.0, z.x - CELL_W * 0.92)
                    self.bump_anim_event(z, "vault")
                    continue
            if z.kind == "pogo" and self.pogo_state(z) == "hop_loop" and target is not None:
                blocked_by_tallnut = bool(main_target and main_target.kind == "tall_nut")
                pogo_target_kind = target.kind if target else ""
                if (not blocked_by_tallnut) and pogo_target_kind in {"wallnut", "pumpkin", "spikeweed", "spikerock", "garlic"}:
                    z.state["pogo_state"] = "vault_over"
                    z.state["pogo_phase_t"] = 0.46
                    z.state["pogo_total_t"] = 0.46
                    z.state["pogo_start_x"] = z.x
                    z.state["pogo_end_x"] = max(LAWN_X - 8.0, z.x - CELL_W * 0.96)
                    continue
            if target and self.zombie_can_attack_plants(z):
                target.hp -= z.dps * dt
                target.state["hit_flash"] = 0.14
                z.state["bite_t"] = 0.12
                if self.is_i_zombie_mode() and target.kind in ("sunflower", "twin_sunflower"):
                    # I, Zombie rule: sunflower bite grants sunlight.
                    sun_bite_t = max(0.0, z.state.get("sun_bite_t", 0.0) - dt)
                    if sun_bite_t <= 0.0:
                        self.sun += 25
                        sun_bite_t = 0.28
                    z.state["sun_bite_t"] = sun_bite_t
                if target.kind == "hypno_shroom" and target.hp <= 0:
                    z.hypnotized = True
                if target.kind == "garlic" and target.hp > 0:
                    z.row = int(clamp(z.row + random.choice([-1, 1]), 0, self.rows() - 1))
                if target.hp <= 0:
                    self.armor.pop(pos, None)
                    self.main.pop(pos, None)
                    self.support.pop(pos, None)
            else:
                z.state["sun_bite_t"] = 0.0
                direction = 1 if z.hypnotized else -1
                mul = 0.55 if z.slow_t > 0 else 1.0
                z.x += direction * z.speed * mul * dt
                if self.is_portal_combat_mode():
                    portal_cd = float(z.state.get("portal_cd", 0.0))
                    z.row, z.x, portal_cd = self.apply_portal_transfer(z.row, z.x, direction, portal_cd)
                    z.state["portal_cd"] = portal_cd
                if self.is_bobsled_bonanza_mode() and z.kind in ("bobsled_team", "zomboni") and not z.hypnotized:
                    self.ice_rows[z.row] = max(float(self.ice_rows.get(z.row, 0.0)), 9999.0)
            # Hypnotized zombies that walk off the right edge should leave battle.
            if z.hypnotized and z.x > self.lawn_right() + 72:
                if z in self.zombies:
                    self.zombies.remove(z)
                continue
            if not z.hypnotized and z.x < LAWN_X - 18:
                if self.is_i_zombie_mode():
                    if z.row in self.brains:
                        self.brains.pop(z.row, None)
                    if z in self.zombies:
                        self.zombies.remove(z)
                    continue
                if self.cleaners[z.row]:
                    self.cleaners[z.row] = False
                    for lane_z in self.zombies:
                        if lane_z.row == z.row and not lane_z.hypnotized:
                            self.slay_zombie(lane_z, source="cleaner")
                else:
                    self.result = "lose"
                    return

    def surface_content_size(self, surface: Optional[pygame.Surface]) -> Tuple[int, int]:
        if surface is None:
            return (0, 0)
        rect = surface.get_bounding_rect(min_alpha=1)
        if rect.w <= 0 or rect.h <= 0:
            return surface.get_size()
        return (int(rect.w), int(rect.h))

    def normalize_animation_surface(
        self,
        surface: Optional[pygame.Surface],
        frame: AnimationFrame,
        *,
        target_size: Optional[Tuple[int, int]] = None,
    ) -> Tuple[Optional[pygame.Surface], float, float, float]:
        if surface is None:
            return None, 0.0, 0.0, 1.0
        full_rect = surface.get_rect()
        rect = full_rect.copy()
        if frame.content_bbox is not None:
            rect = pygame.Rect(frame.content_bbox)
            rect.clamp_ip(full_rect)
            if rect.w <= 0 or rect.h <= 0:
                rect = full_rect.copy()
        anchor = frame.anchor
        if not (0 <= int(anchor[0]) <= full_rect.w and 0 <= int(anchor[1]) <= full_rect.h):
            anchor = full_rect.center
        crop_anchor_x = float(anchor[0] - rect.x)
        crop_anchor_y = float(anchor[1] - rect.y)
        crop_center_x = rect.w / 2.0
        crop_center_y = rect.h / 2.0
        shift_x = float(crop_center_x - crop_anchor_x)
        shift_y = float(crop_center_y - crop_anchor_y)
        scale_ratio = 1.0
        if target_size is not None:
            target_w = max(1, int(target_size[0]))
            target_h = max(1, int(target_size[1]))
            scale_ratio = min(target_w / max(1, rect.w), target_h / max(1, rect.h))
        if rect.size == surface.get_size() and rect.topleft == (0, 0):
            return surface, shift_x, shift_y, scale_ratio
        return surface.subsurface(rect).copy(), shift_x, shift_y, scale_ratio

    def draw(
        self,
        screen: pygame.Surface,
        fonts: Dict[str, pygame.font.Font],
        lang: str,
        tr,
        plant_name_fn,
        zombie_name_fn,
        plant_sprite_fn,
        zombie_sprite_fn,
        entity_anim_frame_fn=None,
        ui_flags: Optional[Dict[str, bool]] = None,
    ) -> None:
        show_plant_hp_bars = True if ui_flags is None else bool(ui_flags.get("show_plant_hp_bars", True))
        show_zombie_hp_bars = True if ui_flags is None else bool(ui_flags.get("show_zombie_hp_bars", True))
        bg = (42, 52, 84) if self.field.is_night else (198, 224, 190)
        screen.fill(bg)
        sky_rect = pygame.Rect(0, 0, SCREEN_WIDTH, LAWN_Y + 20)
        sky_top = (62, 78, 116) if self.field.is_night else (192, 220, 200)
        sky_bottom = (36, 44, 68) if self.field.is_night else (170, 206, 176)
        for y in range(sky_rect.h):
            t = y / max(1, sky_rect.h - 1)
            col = (
                int(sky_top[0] + (sky_bottom[0] - sky_top[0]) * t),
                int(sky_top[1] + (sky_bottom[1] - sky_top[1]) * t),
                int(sky_top[2] + (sky_bottom[2] - sky_top[2]) * t),
            )
            pygame.draw.line(screen, col, (0, y), (SCREEN_WIDTH, y))
        side = pygame.Rect(0, 0, SIDE_W, SCREEN_HEIGHT)
        side_top = (162, 126, 84)
        side_bot = (130, 96, 62)
        for y in range(side.h):
            t = y / max(1, side.h - 1)
            col = (
                int(side_top[0] + (side_bot[0] - side_top[0]) * t),
                int(side_top[1] + (side_bot[1] - side_top[1]) * t),
                int(side_top[2] + (side_bot[2] - side_top[2]) * t),
            )
            pygame.draw.line(screen, col, (side.x, y), (side.right, y))
        pygame.draw.rect(screen, (108, 74, 40), side, 3)
        # Keep decorative bushes readable but less dominant than the lawn.
        pygame.draw.ellipse(screen, (82, 142, 76), (-118, 430, 264, 182))
        pygame.draw.ellipse(screen, (64, 116, 62), (-112, 572, 220, 128))
        lawn_rect = pygame.Rect(LAWN_X, LAWN_Y, COLS * CELL_W, self.lawn_h())
        pygame.draw.rect(screen, (124, 196, 96), lawn_rect, border_radius=22)
        pygame.draw.rect(screen, (44, 90, 34), lawn_rect, 4, border_radius=22)
        for r in range(self.rows()):
            for c in range(COLS):
                tile = pygame.Rect(LAWN_X + c * CELL_W + 1, LAWN_Y + r * CELL_H + 1, CELL_W - 2, CELL_H - 2)
                if self.is_water(r):
                    base = (76, 152, 224)
                elif self.field.is_roof:
                    base = (188, 122, 84)
                else:
                    base = (124, 202, 98)
                shade = -9 if (r + c) % 2 else 2
                col = (int(clamp(base[0] + shade, 0, 255)), int(clamp(base[1] + shade, 0, 255)), int(clamp(base[2] + shade, 0, 255)))
                pygame.draw.rect(screen, col, tile)
                top_line = (int(clamp(col[0] + 20, 0, 255)), int(clamp(col[1] + 22, 0, 255)), int(clamp(col[2] + 18, 0, 255)))
                bottom_line = (int(clamp(col[0] - 20, 0, 255)), int(clamp(col[1] - 24, 0, 255)), int(clamp(col[2] - 22, 0, 255)))
                pygame.draw.line(screen, top_line, (tile.x + 4, tile.y + 3), (tile.right - 4, tile.y + 3), 1)
                pygame.draw.line(screen, bottom_line, (tile.x + 4, tile.bottom - 3), (tile.right - 4, tile.bottom - 3), 1)
                if not self.is_water(r):
                    for n in range(4):
                        sx = tile.x + 8 + ((c * 37 + r * 19 + n * 23) % max(12, tile.w - 16))
                        sy = tile.y + 10 + ((c * 29 + r * 31 + n * 17) % max(12, tile.h - 20))
                        pygame.draw.circle(screen, (96, 168, 80), (sx, sy), 2)
                        if n % 2 == 0:
                            pygame.draw.circle(screen, (78, 150, 66), (sx + 3, sy + 3), 1)
        for c in range(1, COLS):
            x = LAWN_X + c * CELL_W
            pygame.draw.line(screen, (44, 94, 34, 160), (x, LAWN_Y + 6), (x, LAWN_Y + self.lawn_h() - 6), 1)
        for r in range(1, self.rows()):
            y = LAWN_Y + r * CELL_H
            pygame.draw.line(screen, (44, 94, 34, 140), (LAWN_X + 6, y), (LAWN_X + COLS * CELL_W - 6, y), 1)
        vignette = pygame.Surface((lawn_rect.w, lawn_rect.h), pygame.SRCALPHA)
        for y in range(vignette.get_height()):
            edge_t = abs((y / max(1, vignette.get_height() - 1)) - 0.5) * 2.0
            alpha = int(clamp(edge_t * 44.0, 0.0, 44.0))
            pygame.draw.line(vignette, (20, 24, 18, alpha), (0, y), (vignette.get_width(), y))
        screen.blit(vignette, lawn_rect.topleft)
        if self.field.has_fog and self.fog_clear_t <= 0:
            fog = pygame.Surface((COLS * CELL_W, self.lawn_h()), pygame.SRCALPHA)
            for x in range(fog.get_width()):
                alpha = int(clamp((x / max(1, fog.get_width()) - 0.26) / 0.74, 0.0, 1.0) * 190)
                pygame.draw.line(fog, (170, 178, 190, alpha), (x, 0), (x, fog.get_height()))
            screen.blit(fog, (LAWN_X, LAWN_Y))
        if self.is_bobsled_bonanza_mode() or self.is_zomboss_boss_mode():
            for row, ttl in self.ice_rows.items():
                if ttl <= 0.0:
                    continue
                row_rect = pygame.Rect(LAWN_X + 2, LAWN_Y + row * CELL_H + 6, COLS * CELL_W - 4, CELL_H - 12)
                ice = pygame.Surface((row_rect.w, row_rect.h), pygame.SRCALPHA)
                for yy in range(ice.get_height()):
                    t = yy / max(1, ice.get_height() - 1)
                    col = (
                        int(182 + (118 - 182) * t),
                        int(222 + (172 - 222) * t),
                        int(246 + (222 - 246) * t),
                        72,
                    )
                    pygame.draw.line(ice, col, (0, yy), (ice.get_width(), yy))
                screen.blit(ice, row_rect.topleft)
                for yy in range(row_rect.y + 6, row_rect.bottom - 6, 8):
                    pygame.draw.line(screen, (214, 238, 252), (row_rect.x + 10, yy), (row_rect.right - 10, yy), 1)
        self.draw_special_minigame_overlay(screen, plant_sprite_fn, zombie_sprite_fn, tr, entity_anim_frame_fn)
        if self.is_whack_mode():
            for row in range(self.rows()):
                for col in range(2, COLS):
                    cx, cy = self.cell_center(row, col)
                    hole = pygame.Rect(cx - 23, cy + 14, 46, 16)
                    pygame.draw.ellipse(screen, (42, 30, 24), hole)
                    pygame.draw.ellipse(screen, (86, 62, 42), hole, 2)
        if self.is_zombiquarium_mode():
            for fish in self.zombiquarium_fish:
                row = int(fish.get("row", 0.0))
                cx = int(fish.get("x", LAWN_X + 40))
                cy = self.row_y(row)
                facing_right = fish.get("dir", 1.0) > 0
                body = pygame.Rect(cx - 16, cy - 10, 32, 20)
                pygame.draw.ellipse(screen, (132, 170, 188), body)
                pygame.draw.ellipse(screen, (64, 102, 120), body, 2)
                tail = [(cx + 14, cy), (cx + 24, cy - 8), (cx + 24, cy + 8)] if facing_right else [(cx - 14, cy), (cx - 24, cy - 8), (cx - 24, cy + 8)]
                pygame.draw.polygon(screen, (112, 154, 176), tail)
                eye_x = cx + 8 if facing_right else cx - 8
                pygame.draw.circle(screen, (16, 20, 24), (eye_x, cy - 2), 2)
                if fish.get("hungry", 0.0) > 0.0:
                    pygame.draw.circle(screen, (230, 74, 66), (cx, cy - 20), 5)
                    pygame.draw.circle(screen, (120, 34, 30), (cx, cy - 20), 5, 2)
        for row, active in enumerate(self.cleaners):
            y = self.row_y(row)
            rect = pygame.Rect(LAWN_X - 34, y - 16, 28, 32)
            if self.is_i_zombie_mode():
                if row in self.brains:
                    brain = pygame.Rect(rect.x - 2, rect.y + 2, 34, 24)
                    pygame.draw.ellipse(screen, (212, 132, 148), brain)
                    pygame.draw.ellipse(screen, (136, 76, 92), brain, 2)
                continue
            pygame.draw.rect(screen, (220, 60, 60) if active else (120, 120, 120), rect, border_radius=5)
        for (r, c) in self.graves:
            cx, cy = self.cell_center(r, c)
            pygame.draw.rect(screen, (142, 132, 142), (cx - 20, cy - 26, 40, 52), border_radius=8)
        for (r, c), payload in self.vases.items():
            cx, cy = self.cell_center(r, c)
            vase = pygame.Rect(cx - 18, cy - 28, 36, 56)
            pygame.draw.ellipse(screen, (202, 172, 138), vase)
            pygame.draw.ellipse(screen, (126, 92, 62), vase, 3)
            neck = pygame.Rect(cx - 10, cy - 34, 20, 18)
            pygame.draw.ellipse(screen, (214, 186, 150), neck)
            pygame.draw.ellipse(screen, (126, 92, 62), neck, 2)
            marker = str(payload.get("kind", ""))
            marker_col = (86, 168, 96) if marker == "plant" else ((146, 164, 136) if marker == "zombie" else (248, 212, 92))
            pygame.draw.circle(screen, marker_col, (cx, cy - 4), 6)
        for fx in self.vase_reveals:
            ttl = max(0.01, float(fx.get("ttl", 0.56)))
            t = max(0.0, float(fx.get("t", 0.0)))
            p = clamp(1.0 - t / ttl, 0.0, 1.0)
            r = int(clamp(8 + p * 30, 8.0, 38.0))
            alpha = int(clamp((1.0 - p) * 180, 0.0, 180.0))
            cx, cy = self.cell_center(int(fx.get("row", 0)), int(fx.get("col", 0)))
            ring = pygame.Surface((r * 2 + 4, r * 2 + 4), pygame.SRCALPHA)
            pygame.draw.circle(ring, (255, 246, 222, alpha), (r + 2, r + 2), r, 3)
            screen.blit(ring, (cx - r - 2, cy - r - 2))
            rise_y = int(cy - 8 - p * 20)
            kind = str(fx.get("kind", ""))
            value = fx.get("value")
            if kind == "plant" and isinstance(value, str):
                sp = plant_sprite_fn(value, "main")
                if sp is not None:
                    icon = pygame.transform.smoothscale(sp, (40, 40))
                    icon.set_alpha(int(clamp((1.0 - p * 0.35) * 255, 80.0, 255.0)))
                    screen.blit(icon, icon.get_rect(center=(cx, rise_y)))
                else:
                    pygame.draw.circle(screen, (88, 172, 98), (cx, rise_y), 14)
            elif kind == "zombie" and isinstance(value, str):
                zsp = zombie_sprite_fn(value)
                if zsp is not None:
                    icon = pygame.transform.smoothscale(zsp, (34, 46))
                    icon.set_alpha(int(clamp((1.0 - p * 0.35) * 255, 80.0, 255.0)))
                    screen.blit(icon, icon.get_rect(center=(cx, rise_y)))
                else:
                    pygame.draw.rect(screen, (132, 146, 124), (cx - 12, rise_y - 18, 24, 30), border_radius=6)
            elif kind == "sun":
                pygame.draw.circle(screen, (255, 218, 96), (cx, rise_y), 12)
                pygame.draw.circle(screen, (186, 126, 28), (cx, rise_y), 12, 2)
        def sprite_fx(
            sprite: pygame.Surface,
            scale: float = 1.0,
            angle: float = 0.0,
            flash: float = 0.0,
            alpha: float = 1.0,
            flip_x: bool = False,
            mono: bool = False,
        ) -> pygame.Surface:
            out = sprite
            if flip_x:
                out = pygame.transform.flip(out, True, False)
            if abs(scale - 1.0) > 0.01 or abs(angle) > 0.01:
                out = pygame.transform.rotozoom(out, angle, max(0.45, scale))
            if mono:
                mono_surf = out.copy()
                tint_dark = pygame.Surface(mono_surf.get_size(), pygame.SRCALPHA)
                tint_dark.fill((110, 110, 110, 170))
                mono_surf.blit(tint_dark, (0, 0), special_flags=pygame.BLEND_RGBA_MULT)
                tint_light = pygame.Surface(mono_surf.get_size(), pygame.SRCALPHA)
                tint_light.fill((48, 48, 48, 36))
                mono_surf.blit(tint_light, (0, 0), special_flags=pygame.BLEND_RGBA_ADD)
                out = mono_surf
            if flash > 0.0:
                fx = out.copy()
                tint = pygame.Surface(fx.get_size(), pygame.SRCALPHA)
                tint.fill((255, 255, 255, int(clamp(flash, 0.0, 1.0) * 180)))
                fx.blit(tint, (0, 0), special_flags=pygame.BLEND_RGBA_ADD)
                out = fx
            if alpha < 1.0:
                out = out.copy()
                out.set_alpha(int(clamp(alpha, 0.0, 1.0) * 255))
            return out

        for nut in self.rolling_nuts:
            cy = self.row_y(nut.row) + 6
            angle = math.degrees(nut.spin) % 360.0
            scale = 0.46 if nut.kind == "wallnut" else 0.42
            sprite = plant_sprite_fn(nut.kind, "main")
            if sprite is not None:
                rs = sprite_fx(sprite, scale=scale, angle=angle)
                screen.blit(rs, rs.get_rect(center=(int(nut.x), int(cy))))
            else:
                col = (166, 114, 66)
                if nut.kind == "cherrybomb":
                    col = (214, 62, 62)
                r = max(10, nut.radius - 4)
                pygame.draw.circle(screen, col, (int(nut.x), int(cy)), r)
                pygame.draw.circle(screen, (82, 58, 34), (int(nut.x), int(cy)), r, 3)
            shadow_rect = pygame.Rect(int(nut.x) - 24, int(cy) + 16, 48, 10)
            pygame.draw.ellipse(screen, (58, 50, 42), shadow_rect)

        plant_global_scale = 1.12
        for plant in list(self.support.values()) + list(self.main.values()) + list(self.armor.values()):
            self.ensure_plant_anim_state(plant)
            cx, cy = self.cell_center(plant.row, plant.col)
            cfg = self.plant_types[plant.kind]
            phase = plant.state.get("anim_phase", 0.0)
            t = self.elapsed + phase
            recoil = plant.state.get("recoil_t", 0.0)
            hit_flash = plant.state.get("hit_flash", 0.0)

            dx = 0.0
            dy = 0.0
            scale = 1.0
            angle = 0.0

            if plant.slot == "support":
                dy += math.sin(t * 2.4) * 1.1
                angle += math.sin(t * 1.7) * 1.2
                if plant.kind == "lily_pad":
                    scale += 0.022 * math.sin(t * 1.8)
                    dx += math.sin(t * 1.2) * 1.2
            elif plant.slot == "armor":
                dy += math.sin(t * 1.4) * 0.7
                scale += 0.010 * math.sin(t * 1.1)
            elif cfg.is_mushroom:
                dy += math.sin(t * 2.9) * 2.2
                scale += 0.036 * math.sin(t * 2.3)
                angle += 2.8 * math.sin(t * 1.8)
            elif plant.kind in ("sunflower", "twin_sunflower"):
                dx += math.sin(t * 1.8) * 3.8
                dy += math.sin(t * 2.6) * 2.2
                angle += 3.0 * math.sin(t * 1.45)
                scale += 0.024 * math.sin(t * 2.0)
            elif cfg.behavior in ("shoot", "shoot_slow", "shoot_balloon", "shoot_short", "split", "threepeat", "star", "scaredy", "cattail"):
                dy += math.sin(t * 3.8) * 1.8
                dx += math.sin(t * 2.2) * 0.8
                angle += 1.8 * math.sin(t * 3.1)
                scale += 0.018 * math.sin(t * 5.4)
            elif cfg.behavior in ("pult", "cob"):
                windup = (math.sin(t * 1.8) + 1.0) * 0.5
                dy += math.sin(t * 2.2) * 1.2
                dx -= windup * 1.6
                angle += 4.0 * math.sin(t * 1.8)
                scale += 0.010 * math.sin(t * 2.2)
            elif cfg.behavior in ("potato",):
                armed = plant.state.get("armed", 0.0) > 0.0
                if armed:
                    dy += math.sin(t * 2.8) * 1.6
                    angle += math.sin(t * 3.0) * 1.2
                else:
                    dy += 8.0 + math.sin(t * 1.8) * 0.9
                    scale *= 0.82
            elif cfg.behavior in ("block",):
                dy += math.sin(t * 1.25) * 0.7
                scale += 0.008 * math.sin(t * 1.15)
            elif cfg.behavior in ("chomp",):
                dy += math.sin(t * 2.1) * 1.4
                angle += 4.2 * math.sin(t * 2.4)
                dx += math.sin(t * 3.4) * 1.0
            elif cfg.behavior in ("bomb", "row_blast"):
                dy += math.sin(t * 2.0) * 1.0
                scale += 0.016 * math.sin(t * 4.4)
            else:
                dy += math.sin(t * 2.3) * 1.1

            if self.mushroom_sleeping(plant):
                dy += 4.0
                angle -= 8.0
                scale *= 0.94

            if recoil > 0.0:
                k = clamp(recoil / 0.34, 0.0, 1.0)
                dx -= 8.0 * k
                dy += 2.0 * k
                scale -= 0.06 * k
                angle += 5.0 * k

            sprite = plant_sprite_fn(plant.kind, plant.slot)
            anim_alpha = 1.0
            used_anim_frame = False
            if entity_anim_frame_fn is not None:
                anim_surface, anim_frame = entity_anim_frame_fn(
                    "plant",
                    plant.kind,
                    self.get_entity_animation_state(plant),
                    slot=plant.slot,
                )
                if anim_surface is not None and anim_frame is not None and self.plant_animation_variant(plant):
                    target_size = self.surface_content_size(sprite)
                    anim_surface, surf_dx, surf_dy, anim_scale_fit = self.normalize_animation_surface(
                        anim_surface,
                        anim_frame,
                        target_size=target_size,
                    )
                    sprite = anim_surface
                    dx = float(anim_frame.offset[0]) + surf_dx
                    dy = float(anim_frame.offset[1]) + surf_dy
                    scale = float(anim_frame.scale) * anim_scale_fit
                    angle = float(anim_frame.angle)
                    anim_alpha = clamp(float(anim_frame.alpha) / 255.0, 0.0, 1.0)
                    used_anim_frame = True
            draw_cx = int(cx + dx)
            draw_cy = int((cy if plant.slot != "support" else cy + 6) + dy)
            shadow_w = 46 if plant.slot != "support" else 52
            shadow_h = 12 if plant.slot != "support" else 10
            shadow_rect = pygame.Rect(draw_cx - shadow_w // 2, draw_cy + 24, shadow_w, shadow_h)
            pygame.draw.ellipse(screen, (26, 34, 24), shadow_rect)
            plant_render_w = 56
            plant_render_h = 72
            if sprite is not None:
                if not used_anim_frame and plant.state.get("imitater_morph_t", 0.0) > 0.0:
                    sprite = plant_sprite_fn("imitater", plant.slot) or sprite
                    angle += 220.0 * (1.0 - clamp(float(plant.state.get("imitater_morph_t", 0.0)) / max(0.1, float(plant.state.get("imitater_morph_total", 3.2))), 0.0, 1.0))
                flash_strength = (hit_flash / 0.24) if used_anim_frame else (hit_flash / 0.14)
                sp = sprite_fx(
                    sprite,
                    scale=scale if used_anim_frame else scale * plant_global_scale,
                    angle=angle,
                    flash=flash_strength,
                    alpha=anim_alpha,
                    mono=bool(plant.state.get("from_imitater", 0.0)) and plant.state.get("imitater_morph_t", 0.0) <= 0.0,
                )
                self_rect = sp.get_rect(center=(draw_cx, draw_cy))
                plant_render_w = max(24, self_rect.w)
                plant_render_h = max(24, self_rect.h)
                screen.blit(sp, self_rect)
            else:
                if plant.slot == "support":
                    color = (89, 165, 101) if plant.kind == "lily_pad" else ((190, 104, 72) if plant.kind == "flower_pot" else (109, 174, 110))
                    ew = int(60 * max(0.8, scale))
                    eh = int(20 * max(0.8, scale))
                    pygame.draw.ellipse(screen, color, (draw_cx - ew // 2, draw_cy + 16 - eh // 2, ew, eh))
                    plant_render_w = ew
                    plant_render_h = max(eh, 20)
                elif plant.slot == "armor":
                    pygame.draw.ellipse(screen, (228, 120, 64), (draw_cx - 34, draw_cy - 24, 68, 52))
                    plant_render_w = 68
                    plant_render_h = 52
                else:
                    color = (160, 112, 190) if cfg.is_mushroom else (86, 180, 95)
                    if plant.kind in ("wallnut", "tall_nut", "garlic"):
                        color = (156, 102, 64)
                    if self.mushroom_sleeping(plant):
                        color = (95, 88, 110)
                    rad = int(24 * max(0.82, scale))
                    pygame.draw.circle(screen, color, (draw_cx, draw_cy), rad)
                    plant_render_w = rad * 2
                    plant_render_h = rad * 2
            if plant.kind == "potato_mine" and not used_anim_frame:
                armed = plant.state.get("armed", 0.0) > 0.0
                potato_state = str(plant.state.get("potato_state", "arming"))
                if armed:
                    pygame.draw.circle(screen, (252, 228, 116), (draw_cx + 14, draw_cy - 12), 5)
                    for sx in (-16, -8, 0, 8, 16):
                        pygame.draw.line(screen, (72, 62, 50), (draw_cx + sx, draw_cy + 18), (draw_cx + sx, draw_cy + 8), 2)
                    if int(self.elapsed * 7.0) % 2 == 0:
                        pygame.draw.circle(screen, (255, 246, 194), (draw_cx + 14, draw_cy - 12), 2)
                else:
                    arm_t = max(0.0, plant.state.get("arm_t", 0.0))
                    ratio = clamp(1.0 - arm_t / 10.0, 0.0, 1.0)
                    bulb_col = (214, 154, 84) if potato_state == "priming" else (190, 110, 58)
                    stem_col = (98, 176, 90) if potato_state == "priming" else (74, 156, 78)
                    bar_col = (238, 198, 104) if potato_state == "priming" else (86, 196, 112)
                    bulb_r = 15 if potato_state == "priming" else 13
                    pygame.draw.circle(screen, bulb_col, (draw_cx, draw_cy + 20), bulb_r)
                    pygame.draw.rect(screen, (52, 44, 32), (draw_cx - 18, draw_cy - 26, 36, 5), border_radius=3)
                    pygame.draw.rect(screen, bar_col, (draw_cx - 18, draw_cy - 26, int(36 * ratio), 5), border_radius=3)
                    sprout_h = int((10 if potato_state == "priming" else 6) + ratio * 12)
                    pygame.draw.line(screen, stem_col, (draw_cx, draw_cy + 10), (draw_cx, draw_cy + 10 - sprout_h), 3)
                    if potato_state == "priming" and int(self.elapsed * 6.0) % 2 == 0:
                        pygame.draw.circle(screen, (255, 234, 164), (draw_cx + 8, draw_cy + 8), 3)
            if plant.kind == "imitater" and float(plant.state.get("imitater_morph_t", 0.0)) > 0.0:
                swirl_t = clamp(float(plant.state.get("imitater_morph_t", 0.0)) / max(0.1, float(plant.state.get("imitater_morph_total", 3.2))), 0.0, 1.0)
                for idx in range(3):
                    radius = int(14 + idx * 6 + (1.0 - swirl_t) * 8)
                    alpha = int(110 * swirl_t)
                    swirl = pygame.Surface((radius * 2 + 6, radius * 2 + 6), pygame.SRCALPHA)
                    pygame.draw.circle(swirl, (214, 214, 224, alpha), (radius + 3, radius + 3), radius, 2)
                    screen.blit(swirl, (draw_cx - radius - 3, draw_cy - radius - 10))
                if swirl_t < 0.24:
                    glow = pygame.Surface((58, 58), pygame.SRCALPHA)
                    pygame.draw.circle(glow, (246, 242, 232, int(150 * (1.0 - swirl_t / 0.24))), (29, 29), 22, 2)
                    screen.blit(glow, (draw_cx - 29, draw_cy - 30))
            imitater_flash_t = float(plant.state.get("imitater_flash_t", 0.0))
            if plant.kind == "imitater" and imitater_flash_t > 0.0:
                flash_alpha = int(180 * clamp(imitater_flash_t / 0.28, 0.0, 1.0))
                flash = pygame.Surface((72, 72), pygame.SRCALPHA)
                pygame.draw.circle(flash, (248, 246, 236, flash_alpha), (36, 36), 26, 3)
                pygame.draw.circle(flash, (255, 234, 172, int(flash_alpha * 0.75)), (36, 36), 18, 2)
                screen.blit(flash, (draw_cx - 36, draw_cy - 38))
            if plant.kind in {"wallnut", "tall_nut", "pumpkin"}:
                damage_stage = str(plant.state.get("damage_stage", "healthy"))
                if damage_stage != "healthy":
                    crack_col = (98, 58, 34) if damage_stage == "cracked" else (82, 44, 26)
                    pygame.draw.line(screen, crack_col, (draw_cx - 8, draw_cy - 10), (draw_cx + 2, draw_cy + 6), 3)
                    pygame.draw.line(screen, crack_col, (draw_cx + 2, draw_cy + 6), (draw_cx - 6, draw_cy + 18), 3)
                    if damage_stage == "heavy_cracked":
                        pygame.draw.line(screen, crack_col, (draw_cx + 10, draw_cy - 8), (draw_cx - 2, draw_cy + 10), 3)
                        pygame.draw.line(screen, crack_col, (draw_cx + 4, draw_cy - 18), (draw_cx + 14, draw_cy + 4), 2)
                        pygame.draw.circle(screen, (120, 78, 42), (draw_cx + 15, draw_cy + 14), 3)
            if float(plant.state.get("laddered", 0.0)) > 0.0:
                ladder_x = draw_cx + int(min(18, plant_render_w * 0.18))
                ladder_y = draw_cy - 26
                ladder_col = (152, 108, 58)
                glow = int(80 * clamp(float(plant.state.get("ladder_flash_t", 0.0)) / 0.4, 0.0, 1.0))
                if glow > 0:
                    glow_surf = pygame.Surface((30, 56), pygame.SRCALPHA)
                    pygame.draw.rect(glow_surf, (255, 230, 164, glow), (4, 4, 22, 48), border_radius=8)
                    screen.blit(glow_surf, (ladder_x - 15, ladder_y - 4))
                pygame.draw.line(screen, ladder_col, (ladder_x - 8, ladder_y), (ladder_x - 8, ladder_y + 46), 3)
                pygame.draw.line(screen, ladder_col, (ladder_x + 8, ladder_y), (ladder_x + 8, ladder_y + 46), 3)
                for step in range(4):
                    yy = ladder_y + 8 + step * 10
                    pygame.draw.line(screen, (186, 140, 84), (ladder_x - 7, yy), (ladder_x + 7, yy), 2)
            if show_plant_hp_bars:
                hp_max = max(1.0, float(plant.state.get("hp_max", cfg.hp)))
                hp_ratio = clamp(plant.hp / hp_max, 0.0, 1.0)
                bar_w = int(clamp(plant_render_w * 0.66, 30.0, 72.0))
                bar_h = 9
                bar_y = draw_cy - max(44, int(plant_render_h * 0.56))
                bar_y = max(LAWN_Y + 20, bar_y)
                bar_rect = pygame.Rect(draw_cx - bar_w // 2, bar_y, bar_w, bar_h)
                pygame.draw.rect(screen, (12, 12, 12), bar_rect.inflate(4, 4), border_radius=5)
                pygame.draw.rect(screen, (34, 38, 46), bar_rect, border_radius=4)
                fill_rect = pygame.Rect(bar_rect.x + 1, bar_rect.y + 1, int((bar_rect.w - 2) * hp_ratio), bar_rect.h - 2)
                pygame.draw.rect(screen, (70, 218, 104), fill_rect, border_radius=3)
                pygame.draw.rect(screen, (8, 12, 8), bar_rect, 1, border_radius=4)
        for b in self.projs:
            px, py = int(b.x), int(b.y)
            pr = int(max(5, b.radius + 1.4))
            pygame.draw.ellipse(screen, (22, 24, 20), (px - pr, py + pr - 1, pr * 2, max(3, pr - 1)))
            pygame.draw.circle(screen, b.color, (px, py), pr)
            pygame.draw.circle(screen, b.outline, (px, py), pr, 2)
            pygame.draw.circle(screen, (248, 252, 236), (px - max(1, pr // 3), py - max(1, pr // 3)), max(1, pr // 3))
        for spark in self.hit_sparks:
            ttl = max(0.01, float(spark.get("ttl", 0.18)))
            tleft = max(0.0, float(spark.get("t", 0.0)))
            ratio = clamp(tleft / ttl, 0.0, 1.0)
            sx = int(spark.get("x", 0.0))
            sy = int(spark.get("y", 0.0))
            radius = int(4 + (1.0 - ratio) * 8)
            alpha = int(180 * ratio)
            burst = pygame.Surface((radius * 2 + 6, radius * 2 + 6), pygame.SRCALPHA)
            pygame.draw.circle(burst, (255, 226, 124, alpha), (radius + 3, radius + 3), radius, 2)
            pygame.draw.circle(burst, (255, 156, 84, int(alpha * 0.8)), (radius + 3, radius + 3), max(2, radius - 3))
            screen.blit(burst, (sx - radius - 3, sy - radius - 3))
        zombie_bar_tracks: Dict[int, List[Tuple[int, int, int]]] = {}
        for z in sorted(self.zombies, key=lambda zz: (zz.row, -zz.x)):
            if self.field.has_fog and self.fog_clear_t <= 0 and z.x > LAWN_X + CELL_W * 3.6:
                show = any(p.kind == "plantern" and abs(p.row - z.row) <= 1 and abs(self.cell_center(p.row, p.col)[0] - z.x) <= CELL_W * 2.8 for p in self.main.values())
                if not show:
                    continue
            self.ensure_zombie_anim_state(z)
            y = self.row_y(z.row)
            walk_t = z.state.get("walk_t", 0.0) + z.state.get("anim_phase", 0.0)
            step = math.sin(walk_t * 6.0)
            dx = 0.0
            dy = 0.0
            scale = 1.0
            angle = 0.0
            kind = z.kind
            zombie_global_scale = 1.14
            if kind in ("zomboni", "catapult", "bobsled_team"):
                roll = math.sin(walk_t * 4.6)
                dy += roll * 1.3
                dx += math.sin(walk_t * 2.2) * 1.2
                angle += math.sin(walk_t * 7.4) * 2.2
                scale = 1.12 if kind != "bobsled_team" else 1.17
                if kind == "zomboni" and self.zomboni_state(z) == "crush":
                    dy -= 4.0
                    angle += math.sin(walk_t * 14.0) * 5.0
                if kind == "catapult":
                    c_state = self.catapult_state(z)
                    if c_state == "windup":
                        dy -= 5.0
                        angle -= 8.0
                    elif c_state == "recover":
                        dy += 3.0
                        angle += 6.0
            elif kind == "pogo":
                p_state = self.pogo_state(z)
                if p_state == "vault_over":
                    vault_t = float(z.state.get("pogo_phase_t", 0.0))
                    total = max(0.01, float(z.state.get("pogo_total_t", 0.46)))
                    progress = clamp(1.0 - vault_t / total, 0.0, 1.0)
                    dy -= 26.0 * math.sin(progress * math.pi)
                    angle += 14.0 * math.sin(progress * math.pi)
                elif p_state == "recover":
                    dy -= 6.0
                    angle -= 4.0
                else:
                    hop = abs(math.sin(walk_t * 5.0))
                    dy -= 12.0 * hop
                    dx += math.sin(walk_t * 5.0) * 2.2
                    angle += 7.5 * math.sin(walk_t * 5.0)
            elif kind == "balloon":
                b_state = self.balloon_state(z)
                if b_state == "airborne":
                    dy -= 16.0 + math.sin(walk_t * 2.0) * 6.0
                    angle += math.sin(walk_t * 2.2) * 3.0
                    scale = 0.95 + 0.03 * math.sin(walk_t * 2.0)
                elif b_state == "popped_fall":
                    fall_total = max(0.01, float(z.state.get("balloon_drop_total", 0.92)))
                    fall_t = clamp(float(z.state.get("balloon_drop_t", 0.0)) / fall_total, 0.0, 1.0)
                    dy -= 12.0 * fall_t
                    angle += 18.0 * (1.0 - fall_t)
                    scale = 0.98
                else:
                    wobble_total = max(0.01, float(z.state.get("balloon_land_wobble_total", 0.58)))
                    wobble_t = clamp(float(z.state.get("balloon_land_wobble_t", 0.0)) / wobble_total, 0.0, 1.0)
                    dy += abs(step) * 2.4 + wobble_t * 4.0
                    angle += math.sin(walk_t * 4.6) * (1.4 + wobble_t * 4.0)
                    scale = 1.02
            elif kind == "gargantuar":
                dy += abs(step) * 4.2
                scale = 1.24
                dx += math.sin(walk_t * 1.6) * 0.8
                angle += math.sin(walk_t * 1.8) * 1.6
            elif kind == "imp":
                dy += abs(step) * 2.0
                dx += math.sin(walk_t * 7.0) * 1.8
                scale = 0.76
                angle += math.sin(walk_t * 7.4) * 3.4
            elif kind == "football":
                dy += abs(math.sin(walk_t * 8.0)) * 4.8
                dx += math.sin(walk_t * 8.0) * 0.9
                scale = 1.11
                angle += math.sin(walk_t * 8.0) * 2.2
            elif kind in ("dancing", "backup_dancer"):
                sway = math.sin(walk_t * 6.4)
                dx += sway * 2.6
                dy += abs(math.sin(walk_t * 6.4)) * 1.8
                angle += sway * 2.4
            elif kind in ("conehead", "buckethead", "screen_door", "ladder"):
                dy += abs(step) * 2.9
                dx += math.sin(walk_t * 3.3) * 0.6
                angle += math.sin(walk_t * 6.6) * 1.8
                scale = 1.05
                if kind == "ladder":
                    l_state = self.ladder_state(z)
                    if l_state == "placing":
                        dy += 4.0
                        angle -= 9.0
                    elif l_state == "placed_attack":
                        dy += 2.0
                        angle += 3.5
            elif kind == "newspaper":
                self.ensure_newspaper_state(z)
                paper_state = str(z.state.get("paper_state", "paper_intact"))
                if paper_state == "paper_intact":
                    dy += abs(step) * 2.2
                    dx -= 1.0 + abs(math.sin(walk_t * 2.0))
                    angle -= 5.4
                elif paper_state == "paper_lost_transition":
                    jitter = math.sin(walk_t * 20.0) * 1.8
                    dy += abs(step) * 1.8 + jitter
                    dx += math.sin(walk_t * 10.0) * 1.3
                    angle -= 11.0 + math.sin(walk_t * 12.0) * 4.0
                else:
                    dy += abs(math.sin(walk_t * 8.2)) * 3.6
                    dx += math.sin(walk_t * 6.2) * 1.5
                    angle += math.sin(walk_t * 8.4) * 2.0
            elif kind in ("pole_vaulting", "digger"):
                dy += abs(step) * 2.6
                dx += math.sin(walk_t * 6.0) * 1.4
                angle += math.sin(walk_t * 5.2) * 2.2
                if kind == "digger":
                    d_state = self.digger_state(z)
                    if d_state == "burrow_enter":
                        dy += 12.0
                        angle -= 12.0
                    elif d_state == "underground_travel":
                        dy += 18.0
                        scale = 0.88
                    elif d_state == "emerge":
                        rise_total = max(0.01, float(z.state.get("digger_phase_total", 0.35)))
                        rise = clamp(float(z.state.get("digger_phase_t", 0.0)) / rise_total, 0.0, 1.0)
                        dy += 18.0 * rise
                        angle += 10.0 * (1.0 - rise)
                        scale = 0.94
            elif kind in ("snorkel", "ducky_tube", "dolphin_rider"):
                dy += math.sin(walk_t * 4.8) * 2.2
                angle += math.sin(walk_t * 4.2) * 1.6
                dx += math.sin(walk_t * 3.1) * 1.0
            elif kind == "bungee":
                b_state = self.bungee_state(z)
                if b_state == "descending":
                    total = max(0.01, float(z.state.get("bungee_phase_total", 0.92)))
                    phase = clamp(float(z.state.get("bungee_phase_t", 0.0)) / total, 0.0, 1.0)
                    dy -= 80.0 * phase
                elif b_state == "lock_target":
                    dy -= 12.0
                    angle += math.sin(walk_t * 6.0) * 1.2
                elif b_state == "steal_lift":
                    total = max(0.01, float(z.state.get("bungee_phase_total", 0.54)))
                    phase = 1.0 - clamp(float(z.state.get("bungee_phase_t", 0.0)) / total, 0.0, 1.0)
                    dy -= 24.0 + phase * 44.0
                elif b_state == "exit":
                    total = max(0.01, float(z.state.get("bungee_phase_total", 0.44)))
                    phase = 1.0 - clamp(float(z.state.get("bungee_phase_t", 0.0)) / total, 0.0, 1.0)
                    dy -= 54.0 + phase * 56.0
            else:
                dy += abs(step) * 2.4
                dx += math.sin(walk_t * 3.0) * 0.6
                angle += math.sin(walk_t * 6.0) * 1.2

            bite_t = z.state.get("bite_t", 0.0)
            if bite_t > 0.0:
                bite_k = clamp(bite_t / 0.12, 0.0, 1.0)
                dx -= 6.0 * bite_k
                angle += 8.0 * math.sin((1.0 - bite_k) * math.pi)

            hit_flash = z.state.get("hit_flash", 0.0)
            dying_t = z.state.get("dying_t", 0.0)
            alpha = 1.0 if dying_t <= 0 else clamp(dying_t / 0.34, 0.0, 1.0)
            invis_alpha = 1.0
            if self.is_invisi_ghoul_mode() and not z.hypnotized and dying_t <= 0:
                invis_alpha = self.invisighoul_alpha(z)
                alpha *= invis_alpha
            if kind == "digger" and self.digger_state(z) in {"burrow_enter", "underground_travel"}:
                alpha *= 0.45
            if z.state.get("whack_popup", 0.0) > 0.0:
                life = clamp(float(z.state.get("whack_t", 0.0)) / 1.45, 0.0, 1.0)
                dy += 22.0 * (1.0 - life)
                scale *= 0.82 + 0.18 * life
            used_anim_frame = False
            if kind == "bungee":
                target_row = int(z.state.get("target_row", z.row))
                target_col = int(z.state.get("target_col", -1.0))
                if 0 <= target_col < COLS:
                    tx, ty = self.cell_center(target_row, target_col)
                    shadow_w = 28 if self.bungee_state(z) == "descending" else 36
                    pygame.draw.ellipse(screen, (18, 18, 16), (tx - shadow_w // 2, ty + 18, shadow_w, 10))
                    if self.bungee_state(z) in {"lock_target", "steal_lift"}:
                        ring = pygame.Surface((54, 22), pygame.SRCALPHA)
                        pygame.draw.ellipse(ring, (255, 224, 124, 118), (2, 2, 50, 16), 2)
                        screen.blit(ring, (tx - 27, ty + 11))
            if kind == "digger" and self.digger_state(z) in {"burrow_enter", "emerge"}:
                dust = pygame.Surface((42, 20), pygame.SRCALPHA)
                alpha = 100 if self.digger_state(z) == "emerge" else 68
                pygame.draw.ellipse(dust, (128, 98, 66, alpha), (4, 8, 34, 8))
                pygame.draw.ellipse(dust, (182, 154, 110, alpha // 2), (8, 4, 26, 10))
                screen.blit(dust, (int(z.x) - 21, y + 16))
            zsprite = zombie_sprite_fn(z.kind)
            anim_alpha = alpha
            if entity_anim_frame_fn is not None:
                anim_surface, anim_frame = entity_anim_frame_fn(
                    "zombie",
                    z.kind,
                    self.get_entity_animation_state(z),
                )
                if anim_surface is not None and anim_frame is not None and self.zombie_animation_variant(z):
                    target_size = self.surface_content_size(zsprite)
                    anim_surface, surf_dx, surf_dy, anim_scale_fit = self.normalize_animation_surface(
                        anim_surface,
                        anim_frame,
                        target_size=target_size,
                    )
                    zsprite = anim_surface
                    dx = float(anim_frame.offset[0]) + surf_dx
                    dy = float(anim_frame.offset[1]) + surf_dy
                    scale = float(anim_frame.scale) * anim_scale_fit
                    angle = float(anim_frame.angle)
                    anim_alpha = alpha * clamp(float(anim_frame.alpha) / 255.0, 0.0, 1.0)
                    used_anim_frame = True
            draw_x = int(z.x + dx)
            draw_y = int(y - 6 + dy)
            zombie_render_w = 56
            zombie_render_h = 84
            shadow_scale = 1.0 if kind not in ("gargantuar", "imp") else (1.28 if kind == "gargantuar" else 0.72)
            z_shadow_w = int(44 * shadow_scale)
            z_shadow_h = int(12 * shadow_scale)
            pygame.draw.ellipse(screen, (24, 24, 24), (draw_x - z_shadow_w // 2, draw_y + 28, z_shadow_w, z_shadow_h))
            if zsprite is not None:
                flash_strength = (hit_flash / 0.24) if used_anim_frame else (hit_flash / 0.14)
                sp = sprite_fx(
                    zsprite,
                    scale=scale if used_anim_frame else scale * zombie_global_scale,
                    angle=angle,
                    flash=flash_strength,
                    alpha=anim_alpha,
                    flip_x=z.hypnotized,
                )
                z_rect = sp.get_rect(center=(draw_x, draw_y))
                zombie_render_w = max(24, z_rect.w)
                zombie_render_h = max(24, z_rect.h)
                screen.blit(sp, z_rect)
            else:
                body_col = (130, 138, 148)
                if hit_flash > 0:
                    body_col = (188, 196, 206)
                h = 84
                w = 56
                if kind == "gargantuar":
                    h, w = 118, 74
                elif kind == "imp":
                    h, w = 62, 42
                elif kind in ("zomboni", "catapult", "bobsled_team"):
                    h, w = 54, 94
                pygame.draw.rect(screen, body_col, (draw_x - w // 2, draw_y - h // 2, w, h), border_radius=8)
                zombie_render_w = w
                zombie_render_h = h
                if z.kind == "balloon":
                    pygame.draw.circle(screen, (236, 112, 112), (draw_x, draw_y - 40), 16)
            if kind == "bungee":
                rope_top = max(0, draw_y - 118)
                pygame.draw.line(screen, (86, 70, 54), (draw_x, rope_top), (draw_x, draw_y - 18), 2)
            if kind == "newspaper" and not used_anim_frame:
                self.ensure_newspaper_state(z)
                paper_state = str(z.state.get("paper_state", "paper_intact"))
                if paper_state == "paper_intact":
                    paper = pygame.Rect(draw_x + 8, draw_y - 18, 24, 30)
                    pygame.draw.rect(screen, (244, 242, 232), paper, border_radius=4)
                    pygame.draw.rect(screen, (136, 126, 106), paper, 2, border_radius=4)
                    for i in range(4):
                        yy = paper.y + 8 + i * 5
                        pygame.draw.line(screen, (148, 142, 126), (paper.x + 4, yy), (paper.right - 4, yy), 1)
                elif paper_state == "paper_lost_transition":
                    px = draw_x + int(float(z.state.get("paper_drop_x", 0.0)))
                    py = draw_y + int(float(z.state.get("paper_drop_y", 0.0)))
                    rot = float(z.state.get("paper_drop_rot", 0.0))
                    tear = pygame.Surface((24, 18), pygame.SRCALPHA)
                    pygame.draw.polygon(tear, (244, 242, 232), [(0, 2), (22, 0), (24, 16), (2, 18)])
                    pygame.draw.polygon(tear, (136, 126, 106), [(0, 2), (22, 0), (24, 16), (2, 18)], 2)
                    tear_rot = pygame.transform.rotozoom(tear, rot, 1.0)
                    tear_rot.set_alpha(int(clamp((float(z.state.get("paper_drop_t", 0.0)) / 0.46) * 255, 0.0, 255.0)))
                    screen.blit(tear_rot, tear_rot.get_rect(center=(px, py)))
                else:
                    pygame.draw.circle(screen, (222, 64, 52), (draw_x + 10, draw_y - 18), 4)
            variant = str(z.state.get("zombotany_variant", ""))
            if variant in self.plant_types:
                plant_head = plant_sprite_fn(variant, "main")
                if plant_head is not None:
                    head = sprite_fx(plant_head, scale=0.42 + (0.06 if kind in ("buckethead", "football") else 0.0), alpha=alpha)
                    screen.blit(head, head.get_rect(center=(draw_x + 2, draw_y - 24)))
            if show_zombie_hp_bars:
                if z.state.get("whack_popup", 0.0) > 0.0:
                    continue
                if self.is_invisi_ghoul_mode() and (not z.hypnotized) and invis_alpha < 0.48:
                    continue
                hp_ratio = clamp(z.hp / z.hp_max, 0.0, 1.0)
                bar_w = int(clamp(zombie_render_w * 0.62, 34.0, 84.0))
                bar_h = 10
                bar_x = draw_x - bar_w // 2
                bar_y = draw_y - max(50, int(zombie_render_h * 0.55))
                lane_track = zombie_bar_tracks.setdefault(z.row, [])
                for prev_x, prev_y, prev_w in reversed(lane_track[-8:]):
                    overlap_w = int((bar_w + prev_w) * 0.55)
                    if abs(bar_x - prev_x) < overlap_w and abs(bar_y - prev_y) < 14:
                        bar_y = prev_y - 14
                bar_y = max(LAWN_Y + 28, bar_y)
                lane_track.append((bar_x, bar_y, bar_w))
                bar_rect = pygame.Rect(bar_x, bar_y, bar_w, bar_h)
                pygame.draw.rect(screen, (10, 10, 10), bar_rect.inflate(4, 4), border_radius=5)
                pygame.draw.rect(screen, (32, 36, 44), bar_rect, border_radius=4)
                hp_fill = pygame.Rect(bar_rect.x + 1, bar_rect.y + 1, int((bar_rect.w - 2) * hp_ratio), bar_rect.h - 2)
                pygame.draw.rect(screen, (242, 88, 82), hp_fill, border_radius=3)
                pygame.draw.rect(screen, (12, 14, 20), bar_rect, 1, border_radius=4)
                if kind == "newspaper":
                    paper_hp = float(z.state.get("paper_hp", 0.0))
                    paper_max = max(1.0, self.newspaper_paper_max_hp(z))
                    if paper_hp > 0.0:
                        paper_ratio = clamp(paper_hp / paper_max, 0.0, 1.0)
                        paper_rect = pygame.Rect(bar_x, bar_y - 8, bar_w, 6)
                        pygame.draw.rect(screen, (18, 18, 18), paper_rect.inflate(4, 3), border_radius=4)
                        pygame.draw.rect(screen, (40, 44, 52), paper_rect, border_radius=3)
                        paper_fill = pygame.Rect(paper_rect.x + 1, paper_rect.y + 1, int((paper_rect.w - 2) * paper_ratio), paper_rect.h - 2)
                        pygame.draw.rect(screen, (216, 226, 238), paper_fill, border_radius=2)
        for t in self.tokens:
            cx, cy = int(t.x), int(t.y)
            if t.kind == "sun":
                pygame.draw.circle(screen, (255, 215, 73), (cx, cy), 21)
                pygame.draw.circle(screen, (242, 158, 21), (cx, cy), 21, 3)
            else:
                pygame.draw.circle(screen, (245, 201, 70), (cx, cy), 16)
                pygame.draw.circle(screen, (185, 127, 24), (cx, cy), 16, 3)
        if self.wave_warning_t > 0:
            warn = pygame.Rect(0, 0, 316, 34)
            warn.center = (LAWN_X + (COLS * CELL_W) // 2, LAWN_Y + 36)
            alpha = int(150 + 90 * abs(math.sin(self.wave_warning_t * 6.0)))
            overlay = pygame.Surface((warn.w, warn.h), pygame.SRCALPHA)
            overlay.fill((176, 40, 32, alpha))
            screen.blit(overlay, warn.topleft)
            pygame.draw.rect(screen, (255, 214, 188), warn, 2, border_radius=8)
            text = tr("huge_wave")
            surf = fonts["small"].render(text, True, (255, 244, 214))
            screen.blit(surf, surf.get_rect(center=warn.center))


