        if key in {"puff_shroom", "sun_shroom", "fume_shroom", "hypno_shroom", "scaredy_shroom", "ice_shroom", "doom_shroom", "sea_shroom", "gloom_shroom", "magnet_shroom", "gold_magnet"}:
            return self.draw_seed_mushroom_variant(key)
