        if key in {"cabbage_pult", "kernel_pult", "melon_pult", "winter_melon", "cob_cannon"}:
            return self.draw_seed_pult_variant(key)
        if key == "flower_pot":
            return self.draw_seed_flower_pot()
        if key == "coffee_bean":
            return self.draw_seed_coffee_bean()
