    def load_asset_source_map(self) -> Dict[str, str]:
        mapping: Dict[str, str] = {}
        manifest_path = Path(__file__).resolve().parent / "asset_sources.txt"
        if not manifest_path.exists():
            return mapping
        try:
            for line in manifest_path.read_text(encoding="utf-8").splitlines():
                if "->" not in line:
                    continue
                key, value = line.split("->", 1)
                k = key.strip()
                v = value.strip()
                if not k:
                    continue
                mapping[k] = v
        except Exception:
            return {}
        return mapping

    def surface_has_transparency(self, surf: pygame.Surface) -> bool:
        # Require at least some alpha pixels for cleaner sprite compositing.
        if surf.get_masks()[3] == 0 and not (surf.get_flags() & pygame.SRCALPHA):
            return False
        w, h = surf.get_width(), surf.get_height()
        step_x = max(1, w // 32)
        step_y = max(1, h // 32)
        for y in range(0, h, step_y):
            for x in range(0, w, step_x):
                if surf.get_at((x, y)).a < 250:
                    return True
        return False

    def is_disallowed_placeholder_source(self, url: str) -> bool:
        lowered = url.lower()
        blocked = (
            "twemoji",
            "openmoji",
            "emoji",
            "emojipedia",
            "noto-emoji",
            "icon",
            "symbol",
        )
        return any(token in lowered for token in blocked)

    def sprite_looks_like_character(self, surf: pygame.Surface) -> bool:
        w, h = surf.get_width(), surf.get_height()
        # Reject tiny icon-sized images.
        if w < 96 or h < 96:
            return False
        if not self.surface_has_transparency(surf):
            return False
        try:
            rect = surf.get_bounding_rect(min_alpha=12)
        except Exception:
            return False
        if rect.width < 48 or rect.height < 48:
            return False
        bbox_area = rect.width * rect.height
        total_area = max(1, w * h)
        bbox_ratio = bbox_area / total_area
        # Too small -> symbol-like. Too full -> background not clean.
        if bbox_ratio < 0.12 or bbox_ratio > 0.9:
            return False

        # Sample pixels to estimate silhouette density and color complexity.
        step_x = max(1, w // 48)
        step_y = max(1, h // 48)
        alpha_samples = 0
        opaque_samples = 0
        colors = set()
        transitions = 0
        prev_opaque = None
        for y in range(0, h, step_y):
            for x in range(0, w, step_x):
                c = surf.get_at((x, y))
                alpha_samples += 1
                is_opaque = c.a > 180
                if is_opaque:
                    opaque_samples += 1
                    colors.add((c.r // 16, c.g // 16, c.b // 16))
                if prev_opaque is not None and prev_opaque != is_opaque:
                    transitions += 1
                prev_opaque = is_opaque
        if alpha_samples == 0:
            return False
        opaque_ratio = opaque_samples / alpha_samples
        if opaque_ratio < 0.08 or opaque_ratio > 0.82:
            return False
        # Too few colors is usually emoji/icon placeholder.
        if len(colors) < 18:
            return False
        # Too smooth/simple likely a placeholder symbol.
        if transitions < max(14, alpha_samples // 40):
            return False
        return True

    def try_download_sprite(self, key: str, rel_path: str) -> bool:
        if key in self.download_attempted_keys:
            return False
        self.download_attempted_keys.add(key)
        url = self.asset_source_map.get(key, "")
        if (not url) or (url == "NOT FOUND") or (not url.lower().endswith(".png")):
            return False
        if self.is_disallowed_placeholder_source(url):
            print(f"[sprite rejected] {key} placeholder/emoji source blocked -> {url}")
            return False
        full = Path(__file__).resolve().parent / rel_path
        tmp = str(full) + ".tmp"
        try:
            req = Request(url, headers={"User-Agent": "Mozilla/5.0", "Accept": "image/png,image/*;q=0.9,*/*;q=0.8"})
            with urlopen(req, timeout=15) as resp:
                data = resp.read()
            if len(data) < 8 or data[0:4] != b"\x89PNG":
                print(f"[sprite rejected] {key} not a PNG -> {url}")
                return False
            with open(tmp, "wb") as f:
                f.write(data)
            probe = pygame.image.load(tmp).convert_alpha()
            if not self.sprite_looks_like_character(probe):
                try:
                    os.remove(tmp)
                except OSError:
                    pass
                print(f"[sprite rejected] {key} not a valid character sprite -> {url}")
                return False
            os.makedirs(full.parent, exist_ok=True)
            os.replace(tmp, full)
            print(f"[sprite downloaded] {key} -> {rel_path}")
            return True
        except Exception:
            try:
                if os.path.exists(tmp):
                    os.remove(tmp)
            except OSError:
                pass
            return False

    def tr(self, key: str) -> str:
        return I18N.get(self.lang, I18N["en"]).get(key, I18N["en"].get(key, key))

    def fit_label(self, text: str, font: pygame.font.Font, max_width: int) -> str:
        clipped = text
        while clipped and font.size(clipped)[0] > max_width:
            clipped = clipped[:-1]
        if clipped != text and len(clipped) >= 2:
            clipped = clipped[:-1] + "…"
        return clipped

    def plant_display_name(self, kind: str) -> str:
        cfg = self.plants.get(kind)
        if not cfg:
            return kind
        return get_display_name(kind, self.lang, PLANT_NAMES, cfg.name)

    def zombie_display_name(self, kind: str) -> str:
        cfg = self.zombies.get(kind)
        if not cfg:
            return kind
        return get_display_name(kind, self.lang, ZOMBIE_NAMES, cfg.name)

    def load_image(self, path: str, size: Optional[Tuple[int, int]] = None, fallback_draw_fn=None) -> Optional[pygame.Surface]:
        cache_key = (path, size)
        if cache_key in self.image_cache:
            return self.image_cache[cache_key]
        full = Path(__file__).resolve().parent / path
        if not full.exists():
            self.try_download_sprite(Path(path).stem, path)
        if not full.exists():
            self.image_cache[cache_key] = None
            return None
        try:
            image = pygame.image.load(str(full)).convert_alpha()
            if size:
                image = pygame.transform.smoothscale(image, size)
            self.image_cache[cache_key] = image
            return image
        except Exception:
            self.image_cache[cache_key] = None
            return None

    def get_plant_sprite(
        self,
        kind: str,
        slot: str = "main",
        size: Optional[Tuple[int, int]] = None,
    ) -> Optional[pygame.Surface]:
        cfg = self.plants.get(kind)
        if not cfg:
            return None
        # Backward-compatible guard: some call sites pass size as second positional arg.
        if isinstance(slot, tuple) and len(slot) == 2 and all(isinstance(v, int) for v in slot):
            size = (int(slot[0]), int(slot[1]))
            slot = "main"
        log_key = ("plant", kind)
        if size is not None:
            sprite = self.load_image(cfg.sprite_path, size=size)
        elif slot == "support":
            sprite = self.load_image(cfg.sprite_path, size=(72, 72))
        elif slot == "armor":
            sprite = self.load_image(cfg.sprite_path, size=(88, 72))
        else:
            sprite = self.load_image(cfg.sprite_path, size=(72, 72))
        if sprite is not None:
            if log_key not in self.logged_loaded_sprites:
                print(f"[sprite loaded] plant {kind} -> {cfg.sprite_path}")
                self.logged_loaded_sprites.add(log_key)
        else:
            if log_key not in self.logged_missing_sprites:
                print(f"[missing sprite] plant {kind} -> {cfg.sprite_path}")
                self.logged_missing_sprites.add(log_key)
        return sprite

    def get_zombie_sprite(self, kind: str, size: Optional[Tuple[int, int]] = None) -> Optional[pygame.Surface]:
        cfg = self.zombies.get(kind)
        if not cfg:
            return None
        sprite = self.load_image(cfg.sprite_path, size=size or (74, 102))
        log_key = ("zombie", kind)
        if sprite is not None:
            if log_key not in self.logged_loaded_sprites:
                print(f"[sprite loaded] zombie {kind} -> {cfg.sprite_path}")
                self.logged_loaded_sprites.add(log_key)
        else:
            if log_key not in self.logged_missing_sprites:
                print(f"[missing sprite] zombie {kind} -> {cfg.sprite_path}")
                self.logged_missing_sprites.add(log_key)
        return sprite

    def load_animation_sheet(self, path: str) -> Optional[pygame.Surface]:
        if path in self.animation_sheet_cache:
            return self.animation_sheet_cache[path]
        full = Path(__file__).resolve().parent / path
        if not full.exists():
            self.animation_sheet_cache[path] = None
            return None
        try:
            sheet = pygame.image.load(str(full)).convert_alpha()
            self.animation_sheet_cache[path] = sheet
            return sheet
        except Exception:
            self.animation_sheet_cache[path] = None
            return None

    def load_animation_set(self, entity_kind: str, variant: str) -> Optional[AnimationSet]:
        cache_key = (entity_kind, variant)
        if cache_key in self.animation_set_cache:
            return self.animation_set_cache[cache_key]
        registry = ANIMATION_REGISTRY.get(entity_kind, {})
        anim_root = self.assets_root / ("plants" if entity_kind == "plant" else "zombies") / "anim" / variant
        result: Optional[AnimationSet] = registry.get(variant)
        try:
            if anim_root.exists():
                json_path = anim_root / "anim.json"
                if json_path.exists():
                    raw = json.loads(json_path.read_text(encoding="utf-8"))
                    sheet_name = str(raw.get("sheet", "")).strip()
                    sheet_path = ""
                    if sheet_name:
                        sheet_path = str((anim_root / sheet_name).relative_to(Path(__file__).resolve().parent)).replace("\\", "/")
                    anchor = raw.get("anchor", (0, 0))
                    if not isinstance(anchor, (list, tuple)) or len(anchor) != 2:
                        anchor = (0, 0)
                    clips: Dict[str, AnimationClip] = {}
                    raw_clips = raw.get("clips", {})
                    if isinstance(raw_clips, dict):
                        for clip_name, payload in raw_clips.items():
                            if not isinstance(payload, dict):
                                continue
                            frames: List[Dict[str, object]] = []
                            raw_frames = payload.get("frames")
                            if isinstance(raw_frames, list):
                                for frame in raw_frames:
                                    if not isinstance(frame, dict):
                                        continue
                                    frame_spec = dict(frame)
                                    raw_surface_path = str(frame_spec.get("surface_path", "")).strip()
                                    if raw_surface_path:
                                        root_resolved = Path(__file__).resolve().parent / raw_surface_path
                                        anim_resolved = anim_root / raw_surface_path
                                        if not root_resolved.exists() and anim_resolved.exists():
                                            frame_spec["surface_path"] = str(anim_resolved.relative_to(Path(__file__).resolve().parent)).replace("\\", "/")
                                    if sheet_path and not frame_spec.get("surface_path"):
                                        frame_spec["surface_path"] = sheet_path
                                    frames.append(frame_spec)
                            frame_order = payload.get("frame_order", [])
                            if isinstance(frame_order, list):
                                for item in frame_order:
                                    item_name = str(item).strip()
                                    if not item_name:
                                        continue
                                    frame_path = str((anim_root / item_name).relative_to(Path(__file__).resolve().parent)).replace("\\", "/")
                                    frames.append({"surface_path": frame_path, "duration_ms": payload.get("frame_duration_ms", 100)})
                            if frames:
                                clips[str(clip_name)] = make_animation_clip(
                                    frames,
                                    loop=bool(payload.get("loop", True)),
                                    next_clip=str(payload.get("next_clip", "")),
                                    event_markers=tuple(str(x) for x in payload.get("event_markers", []) if x),
                                    hold_last_frame_ms=int(payload.get("hold_last_frame_ms", 0)),
                                    impact_marker=str(payload.get("impact_marker", "")),
                                    lock_until_end=bool(payload.get("lock_until_end", False)),
                                    anchor=(int(anchor[0]), int(anchor[1])),
                                )
                    if clips:
                        result = AnimationSet(clips=clips, anchor=(int(anchor[0]), int(anchor[1])))
                elif anim_root.is_dir():
                    groups: Dict[str, List[Path]] = {}
                    for frame_path in sorted(anim_root.glob("*.png")):
                        match = re.match(r"^(.*?)(?:[_-](\d+))?$", frame_path.stem)
                        if not match:
                            continue
                        clip_name = (match.group(1) or frame_path.stem).strip("_-")
                        groups.setdefault(clip_name, []).append(frame_path)
                    clips = {}
                    for clip_name, paths in groups.items():
                        specs = [
                            {
                                "surface_path": str(path.relative_to(Path(__file__).resolve().parent)).replace("\\", "/"),
                                "duration_ms": 100,
                            }
                            for path in paths
                        ]
                        if specs:
                            clips[clip_name] = make_animation_clip(specs)
                    if clips:
                        result = AnimationSet(clips=clips, anchor=(0, 0))
        except Exception:
            result = registry.get(variant)
        self.animation_set_cache[cache_key] = result
        log_key = f"{entity_kind}:{variant}"
        if result is not None:
            if log_key not in self.logged_loaded_animation_sets:
                print(f"[animation loaded] {entity_kind} {variant}")
                self.logged_loaded_animation_sets.add(log_key)
        elif log_key not in self.logged_missing_animation_sets:
            print(f"[missing animation] {entity_kind} {variant}")
            self.logged_missing_animation_sets.add(log_key)
        return result

    def get_animation_clip(self, entity_kind: str, action: str, variant: Optional[str] = None) -> Optional[AnimationClip]:
        if not variant:
            return None
        anim_set = self.load_animation_set(entity_kind, variant)
        if anim_set is None:
            return None
        clip = anim_set.clips.get(action)
        if clip is None and action != "idle":
            clip = anim_set.clips.get("idle")
        if clip is None and action != "walk":
            clip = anim_set.clips.get("walk")
        return clip

    def get_entity_render_frame(
        self,
        entity_kind: str,
        variant: str,
        anim_state: Optional[AnimationState],
        *,
        slot: str = "main",
    ) -> Tuple[Optional[pygame.Surface], Optional[AnimationFrame]]:
        if anim_state is None or not anim_state.current_clip:
            return None, None
        clip = self.get_animation_clip(entity_kind, anim_state.current_clip, variant=variant)
        if clip is None or not clip.frames:
            return None, None
        frame = clip.frames[min(anim_state.frame_index, len(clip.frames) - 1)]
        surface: Optional[pygame.Surface] = None
        if frame.surface_path:
            cache_key = (frame.surface_path, frame.source_rect)
            if cache_key in self.animation_frame_cache:
                surface = self.animation_frame_cache[cache_key]
            else:
                if frame.source_rect is not None:
                    sheet = self.load_animation_sheet(frame.surface_path)
                    if sheet is not None:
                        rect = pygame.Rect(frame.source_rect)
                        rect.clamp_ip(sheet.get_rect())
                        if rect.w > 0 and rect.h > 0:
                            surface = sheet.subsurface(rect).copy()
                else:
                    surface = self.load_image(frame.surface_path)
                self.animation_frame_cache[cache_key] = surface
        if surface is None:
            return None, None
        return surface, frame

    def normalize_animation_surface(
        self,
        surface: Optional[pygame.Surface],
        frame: AnimationFrame,
        *,
        target_size: Optional[Tuple[int, int]] = None,
    ) -> Tuple[Optional[pygame.Surface], float, float, float]:
        if surface is None:
            return None, 0.0, 0.0, 1.0
        full_rect = surface.get_rect()
        rect = full_rect.copy()
        if frame.content_bbox is not None:
            rect = pygame.Rect(frame.content_bbox)
            rect.clamp_ip(full_rect)
            if rect.w <= 0 or rect.h <= 0:
                rect = full_rect.copy()
        anchor = frame.anchor
        if not (0 <= int(anchor[0]) <= full_rect.w and 0 <= int(anchor[1]) <= full_rect.h):
            anchor = full_rect.center
        crop_anchor_x = float(anchor[0] - rect.x)
        crop_anchor_y = float(anchor[1] - rect.y)
        crop_center_x = rect.w / 2.0
        crop_center_y = rect.h / 2.0
        shift_x = float(crop_center_x - crop_anchor_x)
        shift_y = float(crop_center_y - crop_anchor_y)
        scale_ratio = 1.0
        if target_size is not None:
            target_w = max(1, int(target_size[0]))
            target_h = max(1, int(target_size[1]))
            scale_ratio = min(target_w / max(1, rect.w), target_h / max(1, rect.h))
        if rect.size == surface.get_size() and rect.topleft == (0, 0):
            return surface, shift_x, shift_y, scale_ratio
        return surface.subsurface(rect).copy(), shift_x, shift_y, scale_ratio

    def scale_surface_cover(self, image: pygame.Surface, size: Tuple[int, int]) -> pygame.Surface:
        tw, th = max(1, int(size[0])), max(1, int(size[1]))
        iw, ih = max(1, image.get_width()), max(1, image.get_height())
        scale = max(tw / iw, th / ih)
        sw = max(1, int(iw * scale))
        sh = max(1, int(ih * scale))
        scaled = pygame.transform.smoothscale(image, (sw, sh))
        out = pygame.Surface((tw, th), pygame.SRCALPHA)
        ox = (tw - sw) // 2
        oy = (th - sh) // 2
        out.blit(scaled, (ox, oy))
        return out

    def mode_thumb_seed(self, mode_id: str) -> int:
        return zlib.adler32(mode_id.encode("utf-8")) & 0xFFFFFFFF

    def mode_thumb_meta(self, mode_id: str) -> Dict[str, str]:
        return MODE_THUMB_META.get(mode_id, {"theme": "survival_day", "variant": "normal"})

    def mode_thumb_renderer(self, mode_id: str) -> str:
        return MODE_THUMB_RENDERERS.get(mode_id, mode_id)

    def draw_mode_thumb_gradient(
        self,
        surf: pygame.Surface,
        rect: pygame.Rect,
        top: Tuple[int, int, int],
        bottom: Tuple[int, int, int],
    ) -> None:
        for y in range(rect.h):
            t = y / max(1, rect.h - 1)
            col = (
                int(top[0] + (bottom[0] - top[0]) * t),
                int(top[1] + (bottom[1] - top[1]) * t),
                int(top[2] + (bottom[2] - top[2]) * t),
            )
            pygame.draw.line(surf, col, (rect.x, rect.y + y), (rect.right, rect.y + y))

    def draw_mode_thumb_brain(self, surf: pygame.Surface, x: int, y: int, scale: float = 1.0) -> None:
        w = int(26 * scale)
        h = int(16 * scale)
        lobes = [
            (x - w // 3, y - h // 4, int(10 * scale)),
            (x, y - h // 4, int(10 * scale)),
            (x + w // 3, y - h // 5, int(9 * scale)),
            (x - w // 4, y + h // 5, int(9 * scale)),
            (x + w // 5, y + h // 4, int(8 * scale)),
        ]
        for cx, cy, r in lobes:
            pygame.draw.circle(surf, (236, 184, 170), (cx, cy), max(2, r))
        pygame.draw.ellipse(surf, (226, 168, 156), (x - w // 2, y - h // 2, w, h))
        pygame.draw.ellipse(surf, (130, 84, 78), (x - w // 2, y - h // 2, w, h), 2)

    def draw_mode_thumb_vase(self, surf: pygame.Surface, x: int, y: int, scale: float = 1.0, cracked: bool = False, tone: str = "clay") -> None:
        w = int(18 * scale)
        h = int(28 * scale)
        body = pygame.Rect(x - w // 2, y - h, w, h)
        body_col = (166, 184, 206)
        border_col = (90, 104, 132)
        neck_col = (178, 198, 218)
        neck_border = (96, 110, 140)
        if tone == "metal":
            body_col = (176, 186, 194)
            border_col = (88, 92, 104)
            neck_col = (194, 204, 212)
            neck_border = (92, 96, 110)
        elif tone == "gold":
            body_col = (214, 188, 112)
            border_col = (136, 96, 34)
            neck_col = (230, 208, 142)
            neck_border = (144, 104, 40)
        elif tone == "shadow":
            body_col = (132, 142, 172)
            border_col = (72, 82, 116)
            neck_col = (146, 158, 186)
            neck_border = (76, 86, 120)
        pygame.draw.ellipse(surf, body_col, body)
        pygame.draw.ellipse(surf, border_col, body, 2)
        neck = pygame.Rect(x - w // 4, y - h - int(6 * scale), w // 2, int(8 * scale))
        pygame.draw.ellipse(surf, neck_col, neck)
        pygame.draw.ellipse(surf, neck_border, neck, 2)
        if cracked:
            zig = [(x - w // 5, y - h + 4), (x, y - h // 2), (x - w // 6, y - 4), (x + w // 8, y - 2)]
            pygame.draw.lines(surf, (70, 78, 102), False, zig, 2)
        if tone == "gold":
            pygame.draw.arc(surf, (252, 234, 164), (body.x + 2, body.y + 3, body.w - 4, body.h - 8), 3.6, 6.0, 1)

    def draw_mode_thumb_grave(self, surf: pygame.Surface, x: int, y: int, scale: float = 1.0) -> None:
        w = int(18 * scale)
        h = int(22 * scale)
        body = pygame.Rect(x - w // 2, y - h, w, h)
        pygame.draw.rect(surf, (108, 112, 126), body, border_radius=4)
        pygame.draw.rect(surf, (58, 60, 76), body, 1, border_radius=4)
        cap = pygame.Rect(body.x + 2, body.y - int(5 * scale), body.w - 4, int(8 * scale))
        pygame.draw.ellipse(surf, (124, 128, 142), cap)
        pygame.draw.ellipse(surf, (62, 64, 80), cap, 1)
        pygame.draw.line(surf, (194, 198, 208), (x, body.y + 3), (x, body.bottom - 4), 1)
        pygame.draw.line(surf, (194, 198, 208), (x - 4, body.y + 8), (x + 4, body.y + 8), 1)

    def draw_mode_thumb_wallnut(self, surf: pygame.Surface, x: int, y: int, scale: float = 1.0, angry: bool = False) -> None:
        r = max(6, int(11 * scale))
        pygame.draw.circle(surf, (172, 120, 74), (x, y), r)
        pygame.draw.circle(surf, (102, 70, 42), (x, y), r, 2)
        eye_dx = max(2, int(3 * scale))
        eye_y = y - max(1, int(2 * scale))
        pygame.draw.circle(surf, (28, 22, 18), (x - eye_dx, eye_y), 1)
        pygame.draw.circle(surf, (28, 22, 18), (x + eye_dx, eye_y), 1)
        if angry:
            pygame.draw.line(surf, (70, 46, 24), (x - eye_dx - 2, eye_y - 2), (x - eye_dx + 1, eye_y - 1), 1)
            pygame.draw.line(surf, (70, 46, 24), (x + eye_dx + 2, eye_y - 2), (x + eye_dx - 1, eye_y - 1), 1)
        pygame.draw.arc(
            surf,
            (78, 48, 30),
            (x - max(2, int(4 * scale)), y - 1, max(3, int(8 * scale)), max(2, int(6 * scale))),
            0.2,
            2.9,
            1,
        )

    def draw_mode_thumb_plant(self, surf: pygame.Surface, x: int, y: int, kind: str = "pea", scale: float = 1.0) -> None:
        stem_h = int(10 * scale)
        stem_w = max(2, int(2 * scale))
        base_kind = kind
        if base_kind in {"puff_shroom", "sun_shroom", "fume_shroom", "scaredy_shroom", "hypno_shroom", "ice_shroom", "doom_shroom", "grave_buster", "magnet_shroom", "gloom_shroom"}:
            base_kind = "mushroom"
        elif base_kind in {"repeater", "gatling", "split_pea"}:
            base_kind = "pea_multi"
        elif base_kind in {"threepeater"}:
            base_kind = "threepeater"
        elif base_kind in {"wallnut", "tall_nut"}:
            base_kind = "wallnut"
        elif base_kind in {"cabbage_pult"}:
            base_kind = "cabbage"
        elif base_kind in {"kernel_pult"}:
            base_kind = "kernel"
        elif base_kind in {"melon_pult", "winter_melon"}:
            base_kind = "melon"
        elif base_kind in {"cob_cannon"}:
            base_kind = "cob"
        elif base_kind in {"umbrella_leaf"}:
            base_kind = "umbrella"
        elif base_kind in {"flower_pot"}:
            base_kind = "flower_pot"

        if base_kind not in {"lily_pad", "tangle_kelp"}:
            pygame.draw.rect(surf, (58, 132, 62), (x - stem_w // 2, y - stem_h, stem_w, stem_h))
            pygame.draw.ellipse(surf, (74, 160, 78), (x - int(8 * scale), y - int(6 * scale), int(7 * scale), int(4 * scale)))
            pygame.draw.ellipse(surf, (74, 160, 78), (x + int(1 * scale), y - int(6 * scale), int(7 * scale), int(4 * scale)))
        if base_kind == "sunflower":
            pygame.draw.circle(surf, (116, 74, 38), (x, y - stem_h - int(6 * scale)), int(6 * scale))
            for a in range(0, 360, 30):
                px = x + int(math.cos(math.radians(a)) * 9 * scale)
                py = y - stem_h - int(6 * scale) + int(math.sin(math.radians(a)) * 9 * scale)
                pygame.draw.circle(surf, (244, 204, 78), (px, py), max(2, int(3 * scale)))
        elif base_kind == "mushroom":
            cap_col = (138, 84, 170)
            if kind == "sun_shroom":
                cap_col = (242, 176, 82)
            elif kind == "fume_shroom":
                cap_col = (120, 70, 158)
            elif kind == "hypno_shroom":
                cap_col = (200, 110, 226)
            elif kind == "ice_shroom":
                cap_col = (174, 224, 244)
            elif kind == "doom_shroom":
                cap_col = (90, 48, 118)
            pygame.draw.rect(surf, (224, 210, 180), (x - int(3 * scale), y - stem_h - int(4 * scale), int(6 * scale), int(6 * scale)), border_radius=3)
            pygame.draw.ellipse(surf, cap_col, (x - int(10 * scale), y - stem_h - int(12 * scale), int(20 * scale), int(10 * scale)))
            if kind == "hypno_shroom":
                pygame.draw.arc(surf, (252, 236, 196), (x - int(5 * scale), y - stem_h - int(11 * scale), int(10 * scale), int(10 * scale)), 0.0, 5.8, 1)
            elif kind == "doom_shroom":
                pygame.draw.arc(surf, (238, 104, 104), (x - int(6 * scale), y - stem_h - int(10 * scale), int(12 * scale), int(8 * scale)), 0.1, 3.0, 1)
        elif base_kind == "star":
            pts = []
            cx = x
            cy = y - stem_h - int(8 * scale)
            for i in range(10):
                r = 8 * scale if i % 2 == 0 else 4 * scale
                ang = math.radians(-90 + i * 36)
                pts.append((cx + int(math.cos(ang) * r), cy + int(math.sin(ang) * r)))
            pygame.draw.polygon(surf, (242, 214, 86), pts)
            pygame.draw.polygon(surf, (120, 92, 36), pts, 1)
        elif base_kind == "wallnut":
            self.draw_mode_thumb_wallnut(surf, x, y - stem_h - int(2 * scale), scale=(1.10 if kind == "tall_nut" else 0.92) * scale, angry=(kind == "tall_nut"))
        elif kind == "grave_buster":
            pygame.draw.circle(surf, (118, 110, 130), (x, y - stem_h - int(8 * scale)), int(8 * scale))
            pygame.draw.circle(surf, (68, 60, 82), (x, y - stem_h - int(8 * scale)), int(8 * scale), 1)
            pygame.draw.arc(surf, (238, 228, 214), (x - int(6 * scale), y - stem_h - int(10 * scale), int(12 * scale), int(8 * scale)), 0.1, 3.1, 1)
        elif base_kind == "potato_mine":
            mound = pygame.Rect(x - int(9 * scale), y - int(10 * scale), int(18 * scale), int(12 * scale))
            pygame.draw.ellipse(surf, (146, 96, 56), mound)
            pygame.draw.ellipse(surf, (86, 56, 28), mound, 1)
            pygame.draw.line(surf, (78, 140, 64), (x, y - int(8 * scale)), (x, y - int(15 * scale)), 2)
            pygame.draw.circle(surf, (208, 40, 40), (x + int(7 * scale), y - int(14 * scale)), max(1, int(2 * scale)))
        elif base_kind == "cherrybomb":
            pygame.draw.circle(surf, (212, 52, 62), (x - int(5 * scale), y - stem_h - int(5 * scale)), int(6 * scale))
            pygame.draw.circle(surf, (228, 64, 68), (x + int(5 * scale), y - stem_h - int(6 * scale)), int(6 * scale))
            pygame.draw.line(surf, (72, 120, 54), (x - int(5 * scale), y - stem_h - int(10 * scale)), (x, y - stem_h - int(16 * scale)), 2)
            pygame.draw.line(surf, (72, 120, 54), (x + int(5 * scale), y - stem_h - int(11 * scale)), (x, y - stem_h - int(16 * scale)), 2)
        elif base_kind == "chomper":
            mouth = pygame.Rect(x - int(12 * scale), y - stem_h - int(18 * scale), int(24 * scale), int(18 * scale))
            pygame.draw.ellipse(surf, (146, 72, 178), mouth)
