    def load_mode_thumbnail(self, mode_id: str, size: Tuple[int, int]) -> pygame.Surface:
        target = (max(32, int(size[0])), max(24, int(size[1])))
        cache_key = (mode_id, target)
        if cache_key in self.mode_thumb_cache:
            return self.mode_thumb_cache[cache_key]
        path = MODE_THUMBNAILS.get(mode_id, f"assets/ui/modes/{mode_id}.png")
        img = self.load_image(path, size=None)
        if img is not None:
            thumb = self.scale_surface_cover(img, target)
        else:
            thumb = self.draw_mode_thumbnail_fallback(mode_id, target)
        self.mode_thumb_cache[cache_key] = thumb
        return thumb

    def adventure_chapter_def(self, world: int) -> Dict[str, object]:
        for chapter in ADVENTURE_CHAPTERS:
            if int(chapter.get("world", 0)) == int(world):
                return chapter
        return ADVENTURE_CHAPTERS[0]

    def adventure_chapter_title(self, world: int) -> str:
        chapter = self.adventure_chapter_def(world)
        return self.tr(str(chapter.get("title_key", "chapter_1_title")))

    def adventure_chapter_subtitle(self, world: int) -> str:
        chapter = self.adventure_chapter_def(world)
        return self.tr(str(chapter.get("subtitle_key", "chapter_1_subtitle")))

    def adventure_chapter_focus(self, world: int) -> str:
        chapter = self.adventure_chapter_def(world)
        return self.tr(str(chapter.get("focus_key", "chapter_1_focus")))

    def adventure_chapter_code_range(self, world: int) -> str:
        levels = self.adventure_levels_for_world(world)
        if not levels:
            return f"{world}-1 ~ {world}-10"
        return f"{levels[0].display_code} ~ {levels[-1].display_code}"

    def adventure_chapter_range_label(self, world: int) -> str:
        return self.tr("chapter_range").format(range=self.adventure_chapter_code_range(world))

    def adventure_chapter_focus_label(self, world: int) -> str:
        return self.tr("chapter_focus").format(focus=self.adventure_chapter_focus(world))

    def adventure_levels_for_world(self, world: int) -> List[LevelConfig]:
        return [lv for lv in self.levels if lv.world == world]

    def adventure_level_unlocked(self, level: LevelConfig) -> bool:
        unlocked = int(self.save_data.get("unlocked", 1))
        return level.idx <= unlocked

    def adventure_level_cleared(self, level: LevelConfig) -> bool:
        cleared = self.save_data.get("cleared_levels", [])
        if not isinstance(cleared, list):
            return False
        code = str(level.display_code or level.idx)
        return code in cleared

    def adventure_world_progress(self, world: int) -> Tuple[int, int]:
        levels = self.adventure_levels_for_world(world)
        total = len(levels)
        done = sum(1 for level in levels if self.adventure_level_cleared(level))
        return done, total

    def mark_adventure_level_cleared(self, level: Optional[LevelConfig]) -> None:
        if level is None:
            return
        code = str(level.display_code or level.idx)
        cleared = self.save_data.get("cleared_levels", [])
        if not isinstance(cleared, list):
            cleared = []
        if code not in cleared:
            cleared.append(code)
            self.save_data["cleared_levels"] = cleared

    def adventure_chapter_unlocked(self, world: int) -> bool:
        unlocked = int(self.save_data.get("unlocked", 1))
        return unlocked >= ((world - 1) * 10 + 1)

    def adventure_chapter_preview_level(self, world: int) -> Optional[LevelConfig]:
        chapter_levels = self.adventure_levels_for_world(world)
        if not chapter_levels:
            return None
        return chapter_levels[min(4, len(chapter_levels) - 1)]

    def load_adventure_chapter_preview(self, world: int, size: Tuple[int, int]) -> pygame.Surface:
        target = (max(96, int(size[0])), max(72, int(size[1])))
        cache_key = (world, target)
        if cache_key in self.adventure_chapter_cache:
            return self.adventure_chapter_cache[cache_key]
        chapter_levels = self.adventure_levels_for_world(world)
        surf = pygame.Surface(target, pygame.SRCALPHA)
        if not chapter_levels:
            self.adventure_chapter_cache[cache_key] = surf
            return surf
        main_level = chapter_levels[min(4, len(chapter_levels) - 1)]
        early_level = chapter_levels[0]
        late_level = chapter_levels[-1]
        main_rect = pygame.Rect(int(target[0] * 0.14), int(target[1] * 0.12), int(target[0] * 0.68), int(target[1] * 0.68))
        left_rect = pygame.Rect(int(target[0] * 0.03), int(target[1] * 0.30), int(target[0] * 0.28), int(target[1] * 0.34))
        right_rect = pygame.Rect(int(target[0] * 0.72), int(target[1] * 0.18), int(target[0] * 0.24), int(target[1] * 0.30))
        self.draw_mode_thumb_gradient(surf, pygame.Rect(0, 0, target[0], target[1]), (232, 212, 174), (202, 174, 126))
        for gy in range(8, target[1], 10):
            wave = 2 + (gy % 4)
            pygame.draw.line(surf, (142, 104, 62, 26), (8, gy), (target[0] - 8, gy + wave), 1)
        main_preview = self.load_adventure_level_preview(main_level, main_rect.size)
        left_preview = self.load_adventure_level_preview(early_level, left_rect.size)
        right_preview = self.load_adventure_level_preview(late_level, right_rect.size)
        for frame_rect, inner_col in ((main_rect.inflate(10, 10), (84, 58, 34)), (left_rect.inflate(8, 8), (102, 70, 40)), (right_rect.inflate(8, 8), (102, 70, 40))):
            pygame.draw.rect(surf, inner_col, frame_rect, border_radius=10)
            pygame.draw.rect(surf, (244, 238, 220), frame_rect.inflate(-4, -4), 2, border_radius=9)
        surf.blit(main_preview, main_rect)
        left_rot = pygame.transform.rotozoom(left_preview, -6, 1.0)
        right_rot = pygame.transform.rotozoom(right_preview, 7, 1.0)
        surf.blit(left_rot, left_rot.get_rect(center=left_rect.center))
        surf.blit(right_rot, right_rot.get_rect(center=right_rect.center))
        for pin in ((left_rect.x + 10, left_rect.y + 8), (right_rect.right - 10, right_rect.y + 8), (main_rect.centerx, main_rect.y + 6)):
            pygame.draw.circle(surf, (214, 52, 48), pin, 4)
            pygame.draw.circle(surf, (96, 20, 18), pin, 4, 1)
        badge = pygame.Rect(int(target[0] * 0.72), int(target[1] * 0.64), int(target[0] * 0.22), int(target[1] * 0.22))
        pygame.draw.ellipse(surf, (250, 220, 96), badge)
        pygame.draw.ellipse(surf, (160, 112, 36), badge, 3)
        badge_label = self.fonts["small"].render(str(world), True, (84, 54, 24))
        surf.blit(badge_label, badge_label.get_rect(center=badge.center))
        accent = pygame.Surface(target, pygame.SRCALPHA)
        tint = {
            1: (252, 232, 118, 26),
            2: (182, 136, 224, 30),
            3: (116, 198, 244, 28),
            4: (204, 214, 224, 36),
            5: (238, 154, 96, 28),
        }.get(world, (255, 255, 255, 0))
        pygame.draw.rect(accent, tint, (0, 0, target[0], target[1]), border_radius=12)
        surf.blit(accent, (0, 0))
        self.adventure_chapter_cache[cache_key] = surf
        return surf

    def load_adventure_level_preview(self, level: LevelConfig, size: Tuple[int, int]) -> pygame.Surface:
        target = (max(64, int(size[0])), max(48, int(size[1])))
        cache_key = (level.display_code or str(level.idx), target)
        if cache_key in self.adventure_preview_cache:
            return self.adventure_preview_cache[cache_key]
        path = f"assets/ui/adventure/{level.display_code or level.idx}.png"
        img = self.load_image(path, size=None)
        if img is not None:
            surf = self.scale_surface_cover(img, target)
        else:
            surf = self.draw_adventure_level_preview_fallback(level, target)
        self.adventure_preview_cache[cache_key] = surf
        return surf

    def adventure_preview_recipe(self, level: LevelConfig) -> Dict[str, object]:
        recipe = ADVENTURE_PREVIEW_RECIPES.get(level.display_code or "")
        if recipe:
            return recipe
        threat = sorted(level.z_weights.items(), key=lambda item: item[1], reverse=True)
        main_zombie = threat[0][0] if threat else "normal"
        lead_plant = "sunflower"
        if level.battlefield in ("night", "fog"):
            lead_plant = "puff_shroom"
        elif level.battlefield == "pool":
            lead_plant = "lily_pad"
        elif level.battlefield == "roof":
            lead_plant = "flower_pot"
        return adventure_preview_recipe(
            "boss" if main_zombie == "zomboss" else level.battlefield,
            plants=[(lead_plant, "front_left", 0.92)],
            zombies=[(main_zombie, "lane_right", 0.90)],
            props=[],
            effects=[],
        )

