        pygame.draw.ellipse(self.screen, (108, 176, 98), (226, 420, 1010, 372))
        pygame.draw.ellipse(self.screen, (90, 156, 82), (720, 456, 820, 334))
        pygame.draw.ellipse(self.screen, (238, 238, 226), (920, 46, 180, 64))
