        for y in range(rect.y + 12, rect.bottom - 10, 12):
            pygame.draw.line(self.screen, self.shift_color(fill, -26), (rect.x + 14, y), (rect.right - 14, y + (y % 3) - 1), 1)
        crack_col = self.shift_color(edge, 8)
