    def draw_sun_counter_panel(self, rect: pygame.Rect, sun_value: int) -> None:
        self.draw_framed_panel(rect, fill=(236, 190, 74), border=(126, 82, 28), radius=16, inner=(248, 214, 118))
        inset = rect.inflate(-12, -12)
        self.draw_mode_thumb_gradient(self.screen, inset, (252, 232, 160), (232, 176, 58))
        pygame.draw.rect(self.screen, (140, 90, 28), inset, 2, border_radius=12)
        sun_center = (rect.x + 26, rect.centery - 2)
        pygame.draw.circle(self.screen, (255, 232, 118), sun_center, 15)
        pygame.draw.circle(self.screen, (176, 122, 24), sun_center, 15, 2)
        for angle in range(0, 360, 45):
            rad = math.radians(angle)
            outer = (int(sun_center[0] + math.cos(rad) * 22), int(sun_center[1] + math.sin(rad) * 22))
            inner = (int(sun_center[0] + math.cos(rad) * 17), int(sun_center[1] + math.sin(rad) * 17))
            pygame.draw.line(self.screen, (250, 226, 92), inner, outer, 3)
            pygame.draw.line(self.screen, (196, 142, 34), inner, outer, 1)
        self.draw_text_shadow(self.fonts["tiny"], self.tr("sun"), (92, 54, 18), (rect.x + 50, rect.y + 9), shadow=(252, 242, 198), offset=(1, 1))
        self.draw_text_shadow(self.fonts["ui"], str(int(sun_value)), (52, 34, 14), (rect.x + 48, rect.y + 28), shadow=(252, 242, 210), offset=(1, 1))

    def battle_mode_display_label(self, mode_name: str) -> str:
        if mode_name in CLASSIC_MODE_TITLE_BY_ID:
            if self.lang == "zh":
                return CLASSIC_MODE_SUBTITLE_BY_ID.get(mode_name, CLASSIC_MODE_TITLE_BY_ID[mode_name])
            return CLASSIC_MODE_TITLE_BY_ID[mode_name]
        return self.tr("adventure")

    def battle_special_hint_lines(self) -> Tuple[str, str]:
        primary = self.tr(self.battle.special_primary_hint_key()) if self.battle.special_primary_hint_key() else ""
        secondary_key = self.battle.special_secondary_hint_key()
        secondary = self.tr(secondary_key) if secondary_key else ""
        return primary, secondary

    def battle_special_progress_text(self) -> str:
        progress_type = self.battle.special_progress_type()
        if progress_type == "reveal":
            active = sum(
                1
                for z in self.battle.zombies
                if z.hp > 0 and float(z.state.get("dying_t", 0.0)) <= 0.0 and not z.hypnotized
            )
            cap = max(1, self.battle.special_active_cap())
            return f"{self.tr('active_label')}: {active}/{cap}"
        if progress_type == "portal":
            interval = max(0.1, self.battle.mode_float("portal_shuffle_interval", 12.0))
            remain = max(0.0, interval - float(self.battle.portal_shuffle_t))
            return f"{self.tr('shift_label')}: {remain:.1f}{self.tr('sec')}"
        if progress_type == "variant":
            heads = self.battle.zombotany_variant_roster()
            labels = [self.plant_display_name(kind) for kind in heads[:3]]
            suffix = "..." if len(heads) > 3 else ""
            return f"{self.tr('heads_label')}: {'/'.join(labels)}{suffix}"
        if progress_type == "burst":
            interval = max(0.1, self.battle.mode_float("bobsled_burst_interval", 11.5))
            remain = max(0.0, interval - float(self.battle.bobsled_burst_t))
            return f"{self.tr('burst_label')}: {remain:.1f}{self.tr('sec')}"
        if progress_type == "speed":
            return f"{self.tr('speed_label')}: {self.battle.mode_float('zombie_speed_scale', 1.0):.2f}x"
        if progress_type == "pogo":
            pogo_alive = sum(
                1
                for z in self.battle.zombies
                if z.kind == 'pogo' and z.hp > 0 and float(z.state.get('dying_t', 0.0)) <= 0.0 and not z.hypnotized
            )
            return f"{self.tr('pogo_label')}: {pogo_alive}"
        if progress_type == "boss_hp":
            ratio = int(round(self.battle.zomboss_progress_ratio() * 100.0))
            return f"{self.tr('boss_hp_label')}: {ratio}%"
        return ""

    def battle_adventure_level(self) -> Optional[LevelConfig]:
        if self.battle.is_adventure_mainline():
            return self.battle.level
        return None

    def battle_adventure_tag_text(self, level: Optional[LevelConfig] = None) -> str:
        target = level or self.battle_adventure_level()
        if target is None:
            return self.tr("tag_general")
        return self.tr(str(getattr(target, "tag_key", "tag_general") or "tag_general"))

    def battle_adventure_focus_text(self, level: Optional[LevelConfig] = None) -> str:
        target = level or self.battle_adventure_level()
        if target is None:
            return self.adventure_chapter_focus(1)
        return self.adventure_chapter_focus(int(getattr(target, "world", 1) or 1))

    def battle_adventure_field_text(self, level: Optional[LevelConfig] = None) -> str:
        target = level or self.battle_adventure_level()
        field_key = str(getattr(target, "battlefield", self.battle.field.key if self.battle.field else "day"))
        return self.tr("field_" + field_key)

    def battle_adventure_prepare_hint(self, level: Optional[LevelConfig] = None) -> str:
        target = level or self.battle_adventure_level()
        if target is None:
            return ""
        return self.tr("adventure_prepare_hint").format(
            field=self.battle_adventure_field_text(target),
            tag=self.battle_adventure_tag_text(target),
            focus=self.battle_adventure_focus_text(target),
        )

    def battle_adventure_notice_text(self, level: Optional[LevelConfig], win: bool) -> str:
        target = level or self.battle_adventure_level()
        if target is None:
            return self.tr("win") if win else self.tr("lose")
        key = "adventure_clear_notice" if win else "adventure_lose_notice"
        return self.tr(key).format(
            field=self.battle_adventure_field_text(target),
            tag=self.battle_adventure_tag_text(target),
            focus=self.battle_adventure_focus_text(target),
        )

    def battle_adventure_result_summary_text(self, level: Optional[LevelConfig], win: bool) -> str:
        target = level or self.battle_adventure_level()
        if target is None:
            return self.tr("win") if win else self.tr("lose")
        key = "adventure_result_win_summary" if win else "adventure_result_lose_summary"
        return self.tr(key).format(
            field=self.battle_adventure_field_text(target),
            tag=self.battle_adventure_tag_text(target),
            focus=self.battle_adventure_focus_text(target),
        )

    def battle_result_hold_duration_ms(self, win: bool) -> int:
        if self.battle.is_special_hud_mode():
            return 900 if win else 1050
        if self.battle_adventure_level() is not None:
            return 720 if win else 880
        return 560 if win else 680

    def battle_result_hold_active(self) -> bool:
        return bool(self.battle_result_hold_result) and pygame.time.get_ticks() < int(self.battle_result_hold_until_ms)

    def draw_battle_result_hold_overlay(self) -> None:
        if not self.battle_result_hold_active():
            return
        win = self.battle_result_hold_result == "win"
        shade = pygame.Surface((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.SRCALPHA)
        shade.fill((16, 12, 10, 116 if win else 132))
        self.screen.blit(shade, (0, 0))
        panel = pygame.Rect(0, 0, 620, 234)
        panel.center = (SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2 + 14)
        self.draw_book_panel(panel)
        title_text = self.tr("win") if win else self.tr("lose")
        result_title = self.battle_result_title_text(win)
        self.draw_wood_sign(pygame.Rect(panel.x + 116, panel.y + 18, panel.w - 232, 70), title_text, result_title)
        notice_text = self.battle_clear_notice_text() if win else self.battle_lose_notice_text()
        notice_chip = pygame.Rect(panel.x + 86, panel.y + 102, panel.w - 172, 28)
        chip_fill = (220, 236, 188) if win else (236, 206, 188)
        chip_border = (96, 132, 66) if win else (148, 82, 56)
        chip_inner = (236, 246, 214) if win else (246, 226, 212)
        self.draw_framed_panel(notice_chip, fill=chip_fill, border=chip_border, radius=11, inner=chip_inner)
        notice_label = self.fit_label(notice_text, self.fonts["small"], notice_chip.w - 18)
        self.draw_text_center_shadow(self.fonts["small"], notice_label, (74, 56, 28), notice_chip.center, shadow=(248, 242, 222), offset=(1, 1))
        summary_box = pygame.Rect(panel.x + 70, panel.y + 142, panel.w - 140, 52)
        self.draw_framed_panel(summary_box, fill=(244, 234, 206), border=(134, 98, 48), radius=14, inner=(250, 242, 224))
        summary_text = self.battle_result_summary_text(win)
        summary_line = self.fit_label(summary_text, self.fonts["small"], summary_box.w - 18)
        self.draw_text_center_shadow(self.fonts["small"], summary_line, (70, 52, 28), summary_box.center, shadow=(250, 242, 224), offset=(1, 1))
        progress_lines = self.battle_result_progress_lines(win)
        if progress_lines:
            chip_w = max(220, min(272, panel.w - 172))
            chip = pygame.Rect(0, 0, chip_w, 26)
            chip.center = (panel.centerx, panel.bottom - 24)
            self.draw_framed_panel(chip, fill=(228, 214, 176), border=(128, 92, 46), radius=10, inner=(242, 232, 206))
            chip_text = self.fit_label(progress_lines[0], self.fonts["tiny"], chip.w - 12)
            self.draw_text_center_shadow(self.fonts["tiny"], chip_text, (68, 48, 24), chip.center, shadow=(250, 242, 220), offset=(1, 1))

    def battle_clear_notice_text(self) -> str:
        key = self.battle.special_clear_notice_key()
        if key:
            return self.tr(key)
        adventure_level = self.battle_adventure_level()
        if adventure_level is not None:
            return self.battle_adventure_notice_text(adventure_level, True)
        if self.battle.is_beghouled_mode() or self.battle.is_beghouled_twist_mode():
            return self.tr("beghouled_clear_notice")
        if self.battle.is_seeing_stars_mode():
            return self.tr("seeing_stars_clear_notice")
        if self.battle.is_vasebreaker_mode():
            return self.tr("vasebreaker_clear_notice")
        if self.battle.is_i_zombie_mode():
            return self.tr("i_zombie_clear_notice")
        if self.battle.is_zombiquarium_mode():
            return self.tr("zombiquarium_clear_notice")
        if self.battle.is_last_stand_mode():
            return self.tr("last_stand_clear_notice")
        return self.tr("win")

    def battle_lose_notice_text(self) -> str:
        key = self.battle.special_lose_notice_key()
        if key:
            return self.tr(key)
        adventure_level = self.battle_adventure_level()
        if adventure_level is not None:
            return self.battle_adventure_notice_text(adventure_level, False)
        if self.battle.is_beghouled_twist_mode():
            return self.tr("beghouled_twist_lose_notice")
        if self.battle.is_beghouled_mode():
            return self.tr("beghouled_lose_notice")
        if self.battle.is_seeing_stars_mode():
            return self.tr("seeing_stars_lose_notice")
        if self.battle.is_vasebreaker_mode():
            return self.tr("vasebreaker_lose_notice")
        if self.battle.is_i_zombie_mode():
            return self.tr("i_zombie_lose_notice")
        if self.battle.is_zombiquarium_mode():
            return self.tr("zombiquarium_lose_notice")
        if self.battle.is_last_stand_mode():
            return self.tr("last_stand_lose_notice")
        if self.battle.is_whack_mode():
            return self.tr("whack_lose_notice")
        return self.tr("lose")

    def battle_result_title_text(self, win: bool) -> str:
        key = self.battle.special_result_title_key() if win else self.battle.special_result_fail_title_key()
        if key:
            return self.tr(key)
        mode_name = str(self.battle.mode_rules.get("mode_name", ""))
        if mode_name:
            return self.battle_mode_display_label(mode_name)
        level = self.levels[self.level_idx] if 0 <= self.level_idx < len(self.levels) else None
        return self.level_display_name(level) if level is not None else self.tr("adventure")

    def battle_result_summary_text(self, win: bool) -> str:
        key = self.battle.special_result_summary_key() if win else self.battle.special_result_fail_summary_key()
        if key:
            return self.tr(key)
        adventure_level = self.battle_adventure_level()
        if adventure_level is not None:
            return self.battle_adventure_result_summary_text(adventure_level, win)
        if self.battle.is_beghouled_twist_mode():
            return self.tr("beghouled_twist_hint" if win else "beghouled_twist_fail_summary")
        if self.battle.is_beghouled_mode():
            return self.tr("beghouled_hint" if win else "beghouled_fail_summary")
        if self.battle.is_seeing_stars_mode():
            return self.tr("seeing_stars_hint" if win else "seeing_stars_fail_summary")
        if self.battle.is_vasebreaker_mode():
            return self.tr("vasebreaker_hint" if win else "vasebreaker_fail_summary")
        if self.battle.is_i_zombie_mode():
            return self.tr("i_zombie_objective" if win else "i_zombie_fail_summary")
        if self.battle.is_zombiquarium_mode():
            return self.tr("zombiquarium_hint" if win else "zombiquarium_fail_summary")
        if self.battle.is_last_stand_mode():
            return self.tr("last_stand_hint" if win else "last_stand_fail_summary")
        if self.battle.is_whack_mode():
            return self.tr("whack_hint" if win else "whack_fail_summary")
        return self.tr("win") if win else self.tr("lose")

    def battle_result_progress_lines(self, win: bool) -> List[str]:
        lines: List[str] = []
        if self.battle.is_beghouled_mode() or self.battle.is_beghouled_twist_mode():
            lines.append(f"{self.tr('beghouled_score')}: {self.battle.mode_score}/{self.battle.mode_goal}")
            combo = int(self.battle.mode_rules.get("beghouled_last_combo", 0.0))
            gain = int(self.battle.mode_rules.get("beghouled_last_gain", 0.0))
            if not win:
                lines.append(self.battle_lose_notice_text())
            elif combo > 1:
                lines.append(f"{self.tr('beghouled_combo')}: x{combo}")
            elif gain > 0:
                lines.append(f"+{gain}")
            return lines
        if self.battle.is_seeing_stars_mode():
            lines.append(f"{self.tr('seeing_stars_done')}: {self.battle.mode_score}/{max(1, len(self.battle.seeing_stars_targets))}")
            if not win:
                lines.append(self.battle_lose_notice_text())
            return lines
        if self.battle.is_vasebreaker_mode():
            lines.append(self.tr("vasebreaker_clear_notice") if win else self.battle_lose_notice_text())
            return lines
        if self.battle.is_i_zombie_mode():
            label = "Brains" if self.lang == "en" else "脑子"
            lines.append(f"{label}: {len(self.battle.brains)}/{self.battle.brain_goal}")
            if not win:
                lines.append(self.battle_lose_notice_text())
            return lines
        if self.battle.is_zombiquarium_mode():
            lines.append(f"{self.tr('fish_count')}: {len(self.battle.zombiquarium_fish)}")
            lines.append(self.tr("zombiquarium_trophy_bought") if win else self.battle_lose_notice_text())
            return lines
        if self.battle.is_last_stand_mode():
            lines.append(self.tr("last_stand_fight") if win else self.battle_lose_notice_text())
            return lines
        if self.battle.is_whack_mode():
            lines.append(f"{self.tr('whack_score')}: {self.battle.mode_score}/{self.battle.mode_goal}")
            lines.append(f"{self.tr('whack_miss')}: {self.battle.mode_misses}" if win else self.battle_lose_notice_text())
            return lines
        adventure_level = self.battle_adventure_level()
        if adventure_level is not None:
            lines.append(f"{self.tr('threat')}: {self.battle_adventure_tag_text(adventure_level)}")
            lines.append(f"{self.tr('focus_short')}: {self.battle_adventure_focus_text(adventure_level)}")
            return lines
        progress = self.battle_special_progress_text()
        if progress:
            lines.append(progress)
        summary_text = self.battle_clear_notice_text() if win else self.battle_lose_notice_text()
        if summary_text:
            lines.append(summary_text)
        secondary = self.battle.special_secondary_hint_key()
        if secondary and len(lines) < 2:
            lines.append(self.tr(secondary))
        return lines[:2]

    def draw_seed_bank_top(self, rect: pygame.Rect, label: str = "") -> None:
        self.draw_framed_panel(rect, fill=(162, 108, 52), border=(84, 50, 20), radius=18, inner=(202, 146, 86))
        channel = rect.inflate(-12, -9)
        self.draw_framed_panel(channel, fill=(108, 68, 32), border=(72, 44, 18), radius=12, inner=(146, 98, 54))
        lip = pygame.Rect(channel.x + 10, channel.y + 7, channel.w - 20, 8)
        pygame.draw.rect(self.screen, (228, 190, 132), lip, border_radius=5)
        pygame.draw.rect(self.screen, (120, 76, 38), channel, 1, border_radius=11)
        if label:
            ribbon = pygame.Rect(rect.x + 16, rect.y - 9, min(172, rect.w - 32), 20)
            self.draw_framed_panel(ribbon, fill=(200, 54, 38), border=(108, 28, 20), radius=8, inner=(226, 88, 72))
            text = self.fit_label(label, self.fonts["tiny"], ribbon.w - 12)
            self.draw_text_center_shadow(self.fonts["tiny"], text, (248, 236, 214), ribbon.center, shadow=(86, 26, 18), offset=(1, 1))

    def draw_seed_packet_top(
        self,
        rect: pygame.Rect,
        plant_key: str,
        selected: bool = False,
        hover: bool = False,
        disabled: bool = False,
        display_cost: Optional[int] = None,
        display_icon_key: Optional[str] = None,
    ) -> None:
        cfg = self.plants[plant_key]
        icon_key = display_icon_key or plant_key
        icon_cfg = self.plants.get(icon_key, cfg)
        shown_cost = int(display_cost if display_cost is not None else cfg.cost)
        base = (248, 236, 196)
        if selected:
            base = (255, 242, 202)
        elif hover and not disabled:
            base = (252, 242, 208)
        if disabled:
            base = (200, 192, 172)
        border = (232, 154, 48) if selected else (134, 92, 46)
        self.draw_panel_shadow(rect, radius=12, alpha=42, offset=(0, 3))
        self.draw_framed_panel(rect, fill=base, border=border, radius=12, inner=(254, 248, 230))
        top_band_h = 11 if rect.h <= 50 else (12 if rect.h <= 56 else 16)
        top_band = pygame.Rect(rect.x + 4, rect.y + 4, rect.w - 8, top_band_h)
        self.draw_framed_panel(top_band, fill=(192, 132, 66), border=(102, 62, 26), radius=7, inner=(220, 160, 94))
        cost_label = self.fonts["tiny"].render(str(shown_cost), True, (252, 240, 214))
        self.screen.blit(cost_label, cost_label.get_rect(center=top_band.center))
        icon_box = pygame.Rect(rect.x + 6, top_band.bottom + 1, rect.w - 12, max(16, rect.h - top_band_h - 9))
        self.draw_mode_thumb_gradient(self.screen, icon_box, (250, 244, 222), (228, 218, 184))
        pygame.draw.rect(self.screen, (156, 118, 64), icon_box, 1, border_radius=8)
        icon_size = 22 if rect.h <= 50 else (24 if rect.h <= 56 else 32)
        icon = self.load_image(icon_cfg.sprite_path, size=(icon_size, icon_size))
        if icon is not None:
            self.screen.blit(icon, icon.get_rect(center=icon_box.center))
        else:
            pygame.draw.circle(self.screen, (88, 170, 98), icon_box.center, max(10, icon_size // 2))
        if rect.h > 60:
            label = self.fit_label(self.plant_display_name(plant_key), self.fonts["tiny"], rect.w - 10)
            self.draw_text_center_shadow(self.fonts["tiny"], label, (62, 46, 26), (rect.centerx, rect.bottom - 8), shadow=(250, 242, 214), offset=(1, 1))
        if selected:
            pygame.draw.rect(self.screen, (255, 216, 112), rect.inflate(4, 4), 2, border_radius=14)
        if disabled:
            shade = pygame.Surface((rect.w, rect.h), pygame.SRCALPHA)
            shade.fill((24, 24, 24, 92))
            self.screen.blit(shade, rect.topleft)

    def draw_wave_flag_meter(self, rect: pygame.Rect) -> None:
        self.draw_framed_panel(rect, fill=(180, 126, 66), border=(104, 66, 28), radius=12, inner=(206, 150, 88))
        track = rect.inflate(-12, -9)
        pygame.draw.rect(self.screen, (80, 58, 30), track, border_radius=6)
        inner = track.inflate(-2, -2)
        pygame.draw.rect(self.screen, (120, 86, 46), inner, border_radius=5)

        total = max(1, int(self.battle.total_waves))
        current = int(max(0, self.battle.current_wave))
        progress = 0.0
        if self.battle.uses_wave_system() and total > 0:
            progress = current / total
            if self.battle.is_adventure_mainline() and self.battle.wave_spawn_total > 0 and current > 0:
                spawned = clamp(float(self.battle.wave_spawn_total - self.battle.wave_spawn_remaining), 0.0, float(self.battle.wave_spawn_total))
                progress = ((current - 1) + spawned / max(1.0, float(self.battle.wave_spawn_total))) / total
            elif 0 < current <= len(self.battle.wave_budgets):
                budget = max(1, int(self.battle.wave_budgets[current - 1]))
                done = clamp(float(budget - self.battle.wave_spawn_remaining), 0.0, float(budget))
                progress = ((current - 1) + done / budget) / total
            if current >= total and self.battle.wave_spawn_remaining <= 0:
                progress = 1.0 if not self.battle.zombies else max(progress, (total - 0.2) / total)
        progress = clamp(progress, 0.0, 1.0)
        fill_w = int(inner.w * progress)
        if fill_w > 0:
            fill = pygame.Rect(inner.x, inner.y, fill_w, inner.h)
            self.draw_mode_thumb_gradient(self.screen, fill, (226, 78, 60), (176, 40, 30))
            gloss = pygame.Rect(fill.x + 1, fill.y + 1, max(0, fill.w - 2), max(3, fill.h // 2))
            if gloss.w > 0:
                pygame.draw.rect(self.screen, (248, 156, 128), gloss, border_radius=4)
        if self.battle.uses_wave_system() and total > 1:
            for idx in self.battle.large_wave_indices:
                pos = int(inner.x + inner.w * (idx / total))
                pygame.draw.line(self.screen, (246, 224, 142), (pos, inner.y - 2), (pos, inner.bottom + 2), 2)
                flag = [(pos + 2, inner.y - 2), (pos + 16, inner.y + 3), (pos + 2, inner.y + 8)]
                pygame.draw.polygon(self.screen, (214, 44, 42), flag)
            final_idx = max(1, int(self.battle.final_wave_index or total))
            final_x = int(inner.x + inner.w * (final_idx / total))
            pygame.draw.line(self.screen, (255, 246, 198), (final_x, inner.y - 3), (final_x, inner.bottom + 4), 3)
        label = f"{self.tr('wave_label')} {max(0, current)}/{total}"
        font = self.fonts["tiny"] if rect.h <= 24 else self.fonts["small"]
        self.draw_text_center_shadow(font, label, (252, 244, 220), rect.center, shadow=(66, 42, 22), offset=(1, 1))

