    def draw_mode_card(self, mode_id: str, rect: pygame.Rect, title: str, zh_title: str, status: str, thumb_key: str, hover: bool, selected: bool) -> None:
        stage_style = self.mode_entry_stage_style(mode_id)
        fill = (232, 204, 152) if not hover else (242, 216, 164)
        inner = (248, 238, 210) if not hover else (255, 246, 224)
        border = (132, 88, 42) if not selected else (228, 154, 48)
        self.draw_panel_shadow(rect, radius=14, alpha=52, offset=(0, 3))
        self.draw_framed_panel(rect, fill=fill, border=border, radius=16, inner=inner)
        inner_rect = rect.inflate(-7, -7)
        self.draw_mode_thumb_gradient(self.screen, inner_rect, self.shift_color(inner, 6), self.shift_color(inner, -6))
        pygame.draw.rect(self.screen, self.shift_color(border, 18), inner_rect, 1, border_radius=12)

        title_h = max(22, int(rect.h * 0.135))
        status_h = 11
        title_area = pygame.Rect(rect.x + 10, rect.y + 5, rect.w - 20, title_h)
        title_bar = pygame.Rect(title_area.x + 7, title_area.y + 1, title_area.w - 14, max(15, title_h - 9))
        thumb_area = pygame.Rect(rect.x + 9, title_area.bottom + 4, rect.w - 18, rect.h - title_h - status_h - 20)
        badge_area = pygame.Rect(rect.x + 18, rect.bottom - status_h - 6, rect.w - 36, status_h)

        primary_title = zh_title if self.lang == "zh" and zh_title else title
        secondary_title = title if self.lang == "zh" else zh_title
        self.draw_framed_panel(title_bar, fill=(170, 120, 66), border=(102, 64, 28), radius=8, inner=(194, 144, 84))
        pygame.draw.circle(self.screen, (132, 26, 26), (title_bar.x + 10, title_bar.centery), 3)
        pygame.draw.circle(self.screen, (92, 20, 20), (title_bar.x + 10, title_bar.centery), 3, 1)
        pygame.draw.circle(self.screen, (132, 26, 26), (title_bar.right - 10, title_bar.centery), 3)
        pygame.draw.circle(self.screen, (92, 20, 20), (title_bar.right - 10, title_bar.centery), 3, 1)
        primary_title = self.fit_label(primary_title, self.fonts["small"], title_bar.w - 26)
        title_main = self.fonts["small"].render(primary_title, True, (52, 34, 18))
        self.screen.blit(title_main, title_main.get_rect(center=(title_area.centerx, title_bar.centery)))
        if secondary_title and title_area.h >= 26:
            title_sub = self.fonts["tiny"].render(self.fit_label(secondary_title, self.fonts["tiny"], title_area.w - 8), True, (96, 70, 42))
            self.screen.blit(title_sub, title_sub.get_rect(center=(title_area.centerx, title_area.bottom - 2)))

        frame_col = (156, 108, 58) if not selected else (236, 156, 52)
        self.draw_panel_shadow(thumb_area, radius=10, alpha=34, offset=(0, 2))
        pygame.draw.rect(self.screen, (246, 234, 198), thumb_area, border_radius=9)
        pygame.draw.rect(self.screen, frame_col, thumb_area, 2, border_radius=10)
        inner_thumb = thumb_area.inflate(-4, -4)
        thumb = self.load_mode_thumbnail(thumb_key or mode_id, (inner_thumb.w, inner_thumb.h))
        if selected:
            zoom = pygame.transform.smoothscale(thumb, (max(8, int(inner_thumb.w * 1.03)), max(8, int(inner_thumb.h * 1.03))))
            zx = inner_thumb.x - (zoom.get_width() - inner_thumb.w) // 2
            zy = inner_thumb.y - (zoom.get_height() - inner_thumb.h) // 2
            clip_prev = self.screen.get_clip()
            self.screen.set_clip(inner_thumb)
            self.screen.blit(zoom, (zx, zy))
            self.screen.set_clip(clip_prev)
            glow = pygame.Surface((inner_thumb.w, inner_thumb.h), pygame.SRCALPHA)
            glow.fill((255, 240, 190, 22))
            self.screen.blit(glow, inner_thumb.topleft)
        else:
            self.screen.blit(thumb, inner_thumb.topleft)

        if hover:
            hover_fx = pygame.Surface((inner_thumb.w, inner_thumb.h), pygame.SRCALPHA)
            hover_fx.fill((255, 248, 220, 34))
            self.screen.blit(hover_fx, inner_thumb.topleft)

        if status == "locked":
            shade = pygame.Surface((inner_thumb.w, inner_thumb.h), pygame.SRCALPHA)
            shade.fill((24, 24, 30, 136))
            self.screen.blit(shade, inner_thumb.topleft)
            lock = pygame.Rect(inner_thumb.centerx - 13, inner_thumb.centery - 9, 26, 19)
            pygame.draw.rect(self.screen, (214, 196, 142), lock, border_radius=5)
            pygame.draw.rect(self.screen, (96, 80, 54), lock, 2, border_radius=5)
            pygame.draw.arc(self.screen, (214, 196, 142), (lock.x + 4, lock.y - 11, 18, 15), 0.12, 3.02, 3)
            pygame.draw.arc(self.screen, (96, 80, 54), (lock.x + 4, lock.y - 11, 18, 15), 0.12, 3.02, 2)

        if status == "prototype":
            ribbon = [(thumb_area.right - 44, thumb_area.y + 2), (thumb_area.right - 2, thumb_area.y + 2), (thumb_area.right - 2, thumb_area.y + 15)]
            pygame.draw.polygon(self.screen, (224, 150, 68), ribbon)
            pygame.draw.polygon(self.screen, (132, 84, 30), ribbon, 1)
            tag = self.fonts["tiny"].render(self.tr("prototype"), True, (60, 36, 14))
            self.screen.blit(tag, (thumb_area.right - tag.get_width() - 5, thumb_area.y + 3))
        elif status == "playable":
            medal = (thumb_area.right - 10, thumb_area.y + 10)
            pygame.draw.circle(self.screen, (246, 214, 96), medal, 4)
            pygame.draw.circle(self.screen, (148, 104, 36), medal, 4, 1)
            pygame.draw.circle(self.screen, (252, 238, 168), medal, 2)
        if stage_style != "normal_select":
            style_badge = pygame.Rect(thumb_area.x + 6, thumb_area.y + 6, 46, 16)
            self.draw_stage_style_badge(style_badge, stage_style)

        if status == "playable":
            bfill, bborder, btxt = (154, 198, 134), (72, 112, 60), self.tr("playable_now")
            txt_col = (22, 48, 20)
        elif status == "prototype":
            bfill, bborder, btxt = (234, 196, 134), (144, 96, 42), self.tr("prototype")
            txt_col = (62, 40, 18)
        else:
            bfill, bborder, btxt = (210, 194, 170), (116, 102, 78), self.tr("locked")
            txt_col = (48, 36, 22)
        self.draw_mode_thumb_gradient(self.screen, badge_area, self.shift_color(bfill, 12), self.shift_color(bfill, -8))
        pygame.draw.rect(self.screen, bborder, badge_area, 1, border_radius=5)
        self.draw_text_center_shadow(self.fonts["tiny"], btxt, txt_col, badge_area.center, shadow=(236, 226, 206), offset=(1, 1))

    def show_mode_notice(self, text_key: str) -> None:
        self.mode_notice = self.tr(text_key)
        self.mode_notice_until_ms = pygame.time.get_ticks() + 1800

    def show_battle_notice(self, text: str, color: Tuple[int, int, int] = (58, 42, 24), duration_ms: int = 1500) -> None:
        self.battle_notice = text
        self.battle_notice_color = color
        self.battle_notice_until_ms = pygame.time.get_ticks() + int(duration_ms)

    def find_level_by_field(self, field_key: str) -> int:
        unlocked = int(self.save_data.get("unlocked", 1))
        candidates = [i for i, lv in enumerate(self.levels) if lv.battlefield == field_key and i < unlocked]
        if candidates:
            return candidates[-1]
        for i, lv in enumerate(self.levels):
            if lv.battlefield == field_key:
                return i
        return 0

    def build_survival_round_rules(
        self,
        entry_id: str,
        round_idx: int,
        total_rounds: int,
        return_scene: str = "survival_select",
    ) -> Dict[str, object]:
        hard = entry_id.endswith("_hard")
        endless = entry_id == "survival_endless"
        progress = (round_idx - 1) / max(1, total_rounds - 1) if total_rounds > 1 else 0.0
        waves = 4 if not hard else 5
        if endless:
            waves = int(clamp(4 + round_idx // 3, 4, 8))
        large = [max(2, waves // 2), waves]
        if waves >= 6:
            large.insert(1, waves - 2)
        large = sorted(set(int(clamp(float(x), 1.0, float(waves))) for x in large))
        base_budget = 4 + (1 if hard else 0) + (2 if endless else 0) + round_idx // (2 if hard else 3)
        budgets: List[int] = []
        for i in range(waves):
            w = i + 1
            b = base_budget + i // 2
            if w in large:
                b += 2
            if w == waves:
                b += 3 + (1 if hard else 0)
            budgets.append(int(b))
        bonus = 200 if hard else 175
        if endless:
            bonus = 225
        rules: Dict[str, object] = {
            "mode_name": entry_id,
            "mode_family": "survival",
            "return_scene": return_scene,
            "survival_round_index": float(round_idx),
            "survival_total_rounds": float(total_rounds),
            "survival_endless": endless,
            "survival_round_bonus": float(bonus),
            "duration_mult": 1.2 + progress * (0.18 if hard else 0.12),
            "spawn_rate_mult": (1.06 if not hard else 1.14) + progress * (0.20 if hard else 0.16),
            "zombie_hp_scale": (0.96 if not hard else 1.04) + progress * (0.30 if hard else 0.38),
            "zombie_dps_scale": (0.94 if not hard else 1.00) + progress * (0.24 if hard else 0.32),
            "wave_interval": max(14.5, (19.0 if not hard else 17.0) - progress * (3.2 if hard else 2.5)),
            "rhythm_cycle": 20.0 if hard else 22.0,
            "total_waves_override": float(waves),
            "large_wave_indices": large,
            "final_wave_index": float(waves),
            "wave_budgets": budgets,
        }
        return rules

    def is_active_survival_mode(self) -> bool:
        return str(self.current_mode_base_rules.get("mode_family", "")) == "survival"

    def handle_survival_round_win(self) -> bool:
        if not self.is_active_survival_mode():
            return False
        mode_name = str(self.current_mode_base_rules.get("mode_name", "survival_day"))
        total_rounds = int(self.current_mode_base_rules.get("survival_total_rounds", 5))
        if mode_name == "survival_endless":
            total_rounds = max(total_rounds, 999)
        round_idx = int(self.current_mode_base_rules.get("survival_round_index", 1))
        next_round = round_idx + 1
        if mode_name != "survival_endless" and round_idx >= total_rounds:
            return False
        self.survival_pending_state = self.battle.export_survival_state()
        bonus = int(self.current_mode_base_rules.get("survival_round_bonus", 175))
        self.survival_resume_sun = int(self.battle.sun + bonus)
        self.survival_round_index = next_round
        self.survival_total_rounds = total_rounds
        self.survival_endless = mode_name == "survival_endless"
        self.survival_entry_id = mode_name
        self.scene = "survival_intermission"
        return True

    def start_survival_next_round(self) -> None:
        if self.survival_pending_state is None:
            self.scene = "survival_select"
            return
        round_idx = max(1, int(self.survival_round_index))
        total_rounds = max(round_idx, int(self.survival_total_rounds or 5))
        rules = self.build_survival_round_rules(self.survival_entry_id or "survival_day", round_idx, total_rounds, return_scene="survival_select")
        rules["survival_resume"] = True
        rules["survival_resume_state"] = self.survival_pending_state
        rules["survival_resume_sun"] = float(self.survival_resume_sun)
        preset = list(self.battle.initial_selected_cards) if self.battle.initial_selected_cards else []
        self.open_plant_select(
            self.level_idx,
            preset_selected=preset,
            pick_limit=8,
            mode_rules=rules,
            return_scene="survival_select",
        )

    def mode_scene_change_page(self, scene: str, delta: int) -> None:
        total = self.mode_scene_total_pages(scene)
        curr = int(self.mode_scene_page.get(scene, 0))
        self.mode_scene_page[scene] = int(clamp(float(curr + delta), 0.0, float(total - 1)))

